/* eslint-disable @typescript-eslint/no-explicit-any */
"use client";

import { useEffect, useState } from "react";
import {
  Row,
  Col,
  Card,
  Button,
  Modal,
  Form,
  Space,
  Popconfirm,
  message,
  Table,
  Select,
  Switch,
  Typography,
  Tag,
  Alert,
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  KeyOutlined,
  UserOutlined,
  BookOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";

interface GuruPermission {
  id: number;
  guruId: number;
  halaqahId: number;
  canAbsensi: boolean;
  canHafalan: boolean;
  canTarget: boolean;
  isActive: boolean;
  createdAt: string;
  guru: {
    id: number;
    namaLengkap: string;
    username: string;
  };
  halaqah: {
    id: number;
    namaHalaqah: string;
    guru: {
      namaLengkap: string;
    };
  };
}

interface Guru {
  id: number;
  namaLengkap: string;
  username: string;
}

interface Halaqah {
  id: number;
  namaHalaqah: string;
  guru: {
    namaLengkap: string;
  };
}

export default function GuruPermissionsPage() {
  const [permissions, setPermissions] = useState<GuruPermission[]>([]);
  const [gurus, setGurus] = useState<Guru[]>([]);
  const [halaqahs, setHalaqahs] = useState<Halaqah[]>([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPermission, setEditingPermission] = useState<GuruPermission | null>(null);
  const [form] = Form.useForm();

  // Fetch data
  const fetchPermissions = async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/admin/guru-permissions");
      if (!res.ok) throw new Error("Failed to fetch permissions");
      const data = await res.json();
      setPermissions(data.data || []);
    } catch (error: any) {
      console.error("Error fetching permissions:", error);
      message.error("Error fetching permissions");
    } finally {
      setLoading(false);
    }
  };

  const fetchGurus = async () => {
    try {
      const res = await fetch("/api/admin/users?role=guru");
      if (!res.ok) throw new Error("Failed to fetch gurus");
      const data = await res.json();
      setGurus(data || []);
    } catch (error: any) {
      console.error("Error fetching gurus:", error);
    }
  };

  const fetchHalaqahs = async () => {
    try {
      const res = await fetch("/api/halaqah");
      if (!res.ok) throw new Error("Failed to fetch halaqahs");
      const data = await res.json();
      setHalaqahs(data || []);
    } catch (error: any) {
      console.error("Error fetching halaqahs:", error);
    }
  };

  useEffect(() => {
    fetchPermissions();
    fetchGurus();
    fetchHalaqahs();
  }, []);

  // CRUD operations
  const openModal = (permission?: GuruPermission) => {
    if (permission) {
      setEditingPermission(permission);
      form.setFieldsValue({
        guruId: permission.guruId,
        halaqahId: permission.halaqahId,
        canAbsensi: permission.canAbsensi,
        canHafalan: permission.canHafalan,
        canTarget: permission.canTarget,
        isActive: permission.isActive,
      });
    } else {
      setEditingPermission(null);
      form.resetFields();
      form.setFieldsValue({
        canAbsensi: true,
        canHafalan: false,
        canTarget: false,
        isActive: true,
      });
    }
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    try {
      const values = await form.validateFields();
      const url = editingPermission 
        ? `/api/admin/guru-permissions/${editingPermission.id}` 
        : "/api/admin/guru-permissions";
      const method = editingPermission ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(values),
      });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch (parseError) {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to save permission (${res.status})`);
      }

      const data = await res.json();

      message.success(data.message || "Permission berhasil disimpan");
      setIsModalOpen(false);
      form.resetFields();
      fetchPermissions();
    } catch (error: any) {
      console.error("Error saving permission:", error);
      message.error(error.message || "Error saving permission");
    }
  };

  const handleDelete = async (id: number) => {
    try {
      const res = await fetch(`/api/admin/guru-permissions/${id}`, { 
        method: "DELETE" 
      });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch (parseError) {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to delete permission (${res.status})`);
      }

      const data = await res.json();
      message.success(data.message || "Permission berhasil dihapus");
      fetchPermissions();
    } catch (error: any) {
      console.error("Error deleting permission:", error);
      message.error(error.message || "Error deleting permission");
    }
  };

  const columns = [
    {
      title: "Guru",
      key: "guru",
      render: (_: unknown, record: GuruPermission) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>{record.guru.namaLengkap}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>@{record.guru.username}</div>
        </div>
      ),
    },
    {
      title: "Halaqah",
      key: "halaqah",
      render: (_: unknown, record: GuruPermission) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>{record.halaqah.namaHalaqah}</div>
          <div style={{ fontSize: '12px', color: '#666' }}>
            Guru: {record.halaqah.guru.namaLengkap}
          </div>
        </div>
      ),
    },
    {
      title: "Permissions",
      key: "permissions",
      render: (_: unknown, record: GuruPermission) => (
        <Space direction="vertical" size="small">
          <div>
            {record.canAbsensi && <Tag color="green">­ƒôØ Absensi</Tag>}
            {record.canHafalan && <Tag color="blue">­ƒôû Hafalan</Tag>}
            {record.canTarget && <Tag color="orange">­ƒÄ» Target</Tag>}
          </div>
        </Space>
      ),
    },
    {
      title: "Status",
      key: "status",
      render: (_: unknown, record: GuruPermission) => (
        <Tag color={record.isActive ? 'success' : 'error'}>
          {record.isActive ? '­ƒƒó Aktif' : '­ƒö┤ Nonaktif'}
        </Tag>
      ),
    },
    {
      title: "Actions",
      key: "actions",
      width: 150,
      render: (_: unknown, record: GuruPermission) => (
        <Space size="small">
          <Button
            type="text"
            icon={<EditOutlined />}
            onClick={() => openModal(record)}
            size="small"
          >
            Edit
          </Button>
          <Popconfirm
            title="Hapus Permission"
            description="Apakah Anda yakin ingin menghapus permission ini?"
            onConfirm={() => handleDelete(record.id)}
            okText="Ya, Hapus"
            cancelText="Batal"
            okType="danger"
          >
            <Button type="text" danger icon={<DeleteOutlined />} size="small">
              Delete
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <div style={{ padding: "24px 0" }}>
        <div style={{ marginBottom: 24 }}>
          <h1>Guru Permissions Management</h1>
          <p style={{ margin: 0, color: "#666" }}>
            Kelola akses guru ke halaqah lain untuk absensi, hafalan, dan target
          </p>
        </div>

        {/* Info Alert */}
        <Alert
          message="Tentang Guru Permissions"
          description={
            <div>
              <div>ÔÇó <strong>Own Halaqah:</strong> Guru otomatis punya akses penuh ke halaqah yang dia ampu</div>
              <div>ÔÇó <strong>Cross-Halaqah Permission:</strong> Guru bisa diberi akses ke halaqah lain dengan permission terbatas</div>
              <div>ÔÇó <strong>Absensi:</strong> Bisa input absensi santri</div>
              <div>ÔÇó <strong>Hafalan:</strong> Bisa input hafalan santri</div>
              <div>ÔÇó <strong>Target:</strong> Bisa set target hafalan santri</div>
            </div>
          }
          type="info"
          showIcon
          style={{ marginBottom: 24 }}
        />

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <KeyOutlined style={{ fontSize: '24px', color: '#1890ff', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Total Permissions</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1890ff' }}>
                    {permissions.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <UserOutlined style={{ fontSize: '24px', color: '#52c41a', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Active Permissions</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#52c41a' }}>
                    {permissions.filter(p => p.isActive).length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <BookOutlined style={{ fontSize: '24px', color: '#722ed1', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Unique Gurus</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#722ed1' }}>
                    {new Set(permissions.map(p => p.guruId)).size}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
        </Row>

        {/* Main Content */}
        <Card
          title="Permissions List"
          extra={
            <Button type="primary" icon={<PlusOutlined />} onClick={() => openModal()}>
              Add Permission
            </Button>
          }
        >
          <Table
            dataSource={permissions}
            columns={columns}
            rowKey="id"
            loading={loading}
            size="small"
            scroll={{ x: 800 }}
            pagination={{ pageSize: 10 }}
          />
        </Card>

        {/* Modal */}
        <Modal
          title={
            <Space>
              <KeyOutlined />
              {editingPermission ? "Edit Permission" : "Add New Permission"}
            </Space>
          }
          open={isModalOpen}
          onCancel={() => setIsModalOpen(false)}
          onOk={handleSave}
          okText="Save"
          width={600}
        >
          <Form form={form} layout="vertical" size="large">
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item
                  label="Guru"
                  name="guruId"
                  rules={[{ required: true, message: "Please select guru" }]}
                >
                  <Select 
                    placeholder="Select guru"
                    showSearch
                    filterOption={(input, option) =>
                      (option?.children as unknown as string)?.toLowerCase().includes(input.toLowerCase())
                    }
                  >
                    {gurus.map((guru) => (
                      <Select.Option key={guru.id} value={guru.id}>
                        {guru.namaLengkap} (@{guru.username})
                      </Select.Option>
                    ))}
                  </Select>
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item
                  label="Halaqah"
                  name="halaqahId"
                  rules={[{ required: true, message: "Please select halaqah" }]}
                >
                  <Select 
                    placeholder="Select halaqah"
                    showSearch
                    filterOption={(input, option) =>
                      (option?.children as unknown as string)?.toLowerCase().includes(input.toLowerCase())
                    }
                  >
                    {halaqahs.map((halaqah) => (
                      <Select.Option key={halaqah.id} value={halaqah.id}>
                        <div>
                          <div>{halaqah.namaHalaqah}</div>
                          <div style={{ fontSize: '12px', color: '#666' }}>
                            Guru: {halaqah.guru?.namaLengkap}
                          </div>
                        </div>
                      </Select.Option>
                    ))}
                  </Select>
                </Form.Item>
              </Col>
            </Row>

            <div style={{ 
              padding: '16px', 
              background: '#f6ffed', 
              border: '1px solid #b7eb8f', 
              borderRadius: '6px',
              marginBottom: '16px'
            }}>
              <Typography.Text strong style={{ color: '#52c41a' }}>
                ­ƒöæ Permissions
              </Typography.Text>
              <br />
              <Typography.Text style={{ fontSize: '12px' }}>
                Pilih akses yang akan diberikan kepada guru untuk halaqah ini
              </Typography.Text>

              <Row gutter={16} style={{ marginTop: '12px' }}>
                <Col span={8}>
                  <Form.Item
                    label="Absensi"
                    name="canAbsensi"
                    valuePropName="checked"
                  >
                    <Switch 
                      checkedChildren="Ô£à" 
                      unCheckedChildren="ÔØî"
                    />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    label="Hafalan"
                    name="canHafalan"
                    valuePropName="checked"
                  >
                    <Switch 
                      checkedChildren="Ô£à" 
                      unCheckedChildren="ÔØî"
                    />
                  </Form.Item>
                </Col>
                <Col span={8}>
                  <Form.Item
                    label="Target"
                    name="canTarget"
                    valuePropName="checked"
                  >
                    <Switch 
                      checkedChildren="Ô£à" 
                      unCheckedChildren="ÔØî"
                    />
                  </Form.Item>
                </Col>
              </Row>
            </div>

            <Form.Item
              label="Status"
              name="isActive"
              valuePropName="checked"
            >
              <Switch 
                checkedChildren="­ƒƒó Aktif" 
                unCheckedChildren="­ƒö┤ Nonaktif"
              />
            </Form.Item>
          </Form>
        </Modal>
      </div>
    </LayoutApp>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
"use client";

import { useEffect, useState, useCallback } from "react";
import dynamic from "next/dynamic";
import {
  Row,
  Col,
  Card,
  Button,
  Form,
  Input,
  Space,
  Popconfirm,
  message,
  Select,
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  TeamOutlined,
  UserOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import LoadingSkeleton from "@/components/layout/LoadingSkeleton";

const DynamicTable = dynamic(() => import("antd").then(mod => mod.Table), {
  ssr: false,
  loading: () => <LoadingSkeleton type="table" count={5} />
});

const DynamicModal = dynamic(() => import("antd").then(mod => mod.Modal), {
  ssr: false
});

interface Halaqah {
  id: number;
  namaHalaqah: string;
  deskripsi?: string;
  guruId?: number;
  guru?: {
    id: number;
    namaLengkap: string;
  };
  santri: Array<{
    id: number;
    santri: {
      id: number;
      namaLengkap: string;
    };
  }>;
  _count?: {
    santri: number;
  };
}

interface Guru {
  id: number;
  namaLengkap: string;
}

interface Santri {
  id: number;
  namaLengkap: string;
}

export default function AdminHalaqahPage() {
  const [halaqah, setHalaqah] = useState<Halaqah[]>([]);
  const [guru, setGuru] = useState<Guru[]>([]);
  const [santri, setSantri] = useState<Santri[]>([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingHalaqah, setEditingHalaqah] = useState<Halaqah | null>(null);
  const [form] = Form.useForm();

  // Fetch data
  const fetchHalaqah = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/halaqah");
      if (!res.ok) throw new Error("Failed to fetch halaqah");
      const data = await res.json();
      setHalaqah(data);
    } catch (error: unknown) {
      console.error("Error fetching halaqah:", error);
      message.error("Error fetching halaqah");
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchGuru = useCallback(async () => {
    try {
      const res = await fetch("/api/admin/users?role=guru");
      if (!res.ok) throw new Error("Failed to fetch guru");
      const data = await res.json();
      setGuru(data);
    } catch (error: unknown) {
      console.error("Error fetching guru:", error);
    }
  }, []);

  const fetchSantri = useCallback(async (halaqahId?: number) => {
    try {
      let url;
      if (halaqahId) {
        // For editing: get santri available for this halaqah (including current members)
        url = `/api/admin/users/available?halaqahId=${halaqahId}`;
      } else {
        // For new halaqah: get santri not assigned to any halaqah
        url = "/api/admin/users?role=santri&excludeAssigned=true";
      }
      
      const res = await fetch(url);
      if (!res.ok) throw new Error("Failed to fetch santri");
      const data = await res.json();
      setSantri(data);
    } catch (error: unknown) {
      console.error("Error fetching santri:", error);
    }
  }, []);

  useEffect(() => {
    fetchHalaqah();
    fetchGuru();
    fetchSantri();
  }, [fetchHalaqah, fetchGuru, fetchSantri]);

  // CRUD operations
  const openModal = (halaqah?: Halaqah) => {
    if (halaqah) {
      setEditingHalaqah(halaqah);
      // Fetch santri excluding current halaqah for editing
      fetchSantri(halaqah.id);
      form.setFieldsValue({
        ...halaqah,
        guruId: halaqah.guruId,
        santriIds: halaqah.santri?.map(hs => hs.santri?.id).filter(Boolean) || [],
      });
    } else {
      setEditingHalaqah(null);
      form.resetFields();
      // Fetch available santri for new halaqah
      fetchSantri();
      // Set default first 5 santri for new halaqah
      setTimeout(() => {
        const firstFiveSantri = santri.slice(0, 5).map(s => s.id);
        form.setFieldsValue({
          santriIds: firstFiveSantri,
        });
      }, 100);
    }
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    try {
      const values = await form.validateFields();

      // Ensure santriIds is provided and not empty
      if (!values.santriIds || values.santriIds.length === 0) {
        message.error("Please select at least one santri");
        return;
      }

      const url = editingHalaqah ? `/api/halaqah/${editingHalaqah.id}` : "/api/halaqah";
      const method = editingHalaqah ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(values),
      });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }

        // Handle specific error cases
        if (errorData.error === 'At least 5 santri must be selected') {
          message.error('Minimal 5 santri harus dipilih');
        } else if (errorData.error === 'Nama halaqah is required') {
          message.error('Nama halaqah wajib diisi');
        } else if (errorData.error) {
          message.error(errorData.error);
        } else {
          message.error(`Gagal menyimpan halaqah (${res.status})`);
        }

        // Log error details for debugging
        console.error("API Error Response:", {
          status: res.status,
          statusText: res.statusText,
          errorData: errorData,
          url: url,
          method: method
        });
        return;
      }

      const data = await res.json();

      message.success(editingHalaqah ? "Halaqah berhasil diperbarui" : "Halaqah berhasil ditambahkan");
      setIsModalOpen(false);
      form.resetFields();
      // Refresh all data to ensure synchronization
      await Promise.all([
        fetchHalaqah(),
        fetchSantri() // Refresh available santri list
      ]);
    } catch (error: unknown) {
      console.error("Error saving halaqah:", error);
      // Provide more detailed error message
      const errorMessage = error instanceof Error ? error.message : "Error saving halaqah";
      message.error(errorMessage);
    }
  };

  const handleDelete = async (id: number) => {
    try {
      const res = await fetch(`/api/halaqah/${id}`, { method: "DELETE" });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to delete halaqah (${res.status})`);
      }

      const data = await res.json();
      message.success(data.message || "Halaqah berhasil dihapus");

      // Refresh all data to ensure synchronization
      await Promise.all([
        fetchHalaqah(),
        fetchSantri() // Refresh available santri list
      ]);
    } catch (error: unknown) {
      console.error("Error deleting halaqah:", error);
      message.error(error instanceof Error ? error.message : "Error deleting halaqah");
    }
  };

  const columns = [
    {
      title: "ID",
      dataIndex: "id",
      key: "id",
      width: 80,
    },
    {
      title: "Nama Halaqah",
      dataIndex: "namaHalaqah",
      key: "namaHalaqah",
      render: (text: string, record: Halaqah) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>{text}</div>
          {record.deskripsi && (
            <div style={{ fontSize: '12px', color: '#666' }}>{record.deskripsi}</div>
          )}
        </div>
      ),
    },
    {
      title: "Guru Pengampu",
      dataIndex: "guru",
      key: "guru",
       
      render: (guru: any) => guru?.namaLengkap || "Belum ditentukan",
    },
    {
      title: "Jumlah Santri",
      dataIndex: "santri",
      key: "santriCount",
       
      render: (santri: any[]) => santri?.length || 0,
    },
    {
      title: "Actions",
      key: "actions",
      width: 150,
      render: (_: unknown, record: Halaqah) => (
        <Space size="small">
          <Button
            type="text"
            icon={<EditOutlined />}
            onClick={() => openModal(record)}
            size="small"
          >
            Edit
          </Button>
          <Popconfirm
            title="Are you sure you want to delete this halaqah?"
            onConfirm={() => handleDelete(record.id)}
            okText="Yes"
            cancelText="No"
          >
            <Button type="text" danger icon={<DeleteOutlined />} size="small">
              Delete
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <div style={{ padding: "24px 0" }}>
        <div style={{ marginBottom: 24 }}>
          <h1>Halaqah Management</h1>
          <p style={{ margin: 0, color: "#666" }}>
            Manage halaqah groups and assign teachers
          </p>
        </div>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <TeamOutlined style={{ fontSize: '24px', color: '#1890ff', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Total Halaqah</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1890ff' }}>
                    {halaqah.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <UserOutlined style={{ fontSize: '24px', color: '#52c41a', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Total Guru</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#52c41a' }}>
                    {guru.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <TeamOutlined style={{ fontSize: '24px', color: '#722ed1', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Total Santri</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#722ed1' }}>
                    {santri.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
        </Row>

        {/* Main Content */}
        <Card
          title="Halaqah List"
          extra={
            <Button type="primary" icon={<PlusOutlined />} onClick={() => openModal()}>
              Add Halaqah
            </Button>
          }
        >
          <DynamicTable
            dataSource={halaqah}
            columns={columns}
            rowKey="id"
            loading={loading}
            size="small"
            scroll={{ x: 600 }}
          />
        </Card>

        {/* Modal */}
        <DynamicModal
          title={
            <Space>
              <TeamOutlined />
              {editingHalaqah ? "Edit Halaqah" : "Add New Halaqah"}
            </Space>
          }
          open={isModalOpen}
          onCancel={() => setIsModalOpen(false)}
          onOk={handleSave}
          okText="Save"
          width={600}
        >
          <Form form={form} layout="vertical" size="large">
            <Form.Item
              label="Nama Halaqah"
              name="namaHalaqah"
              rules={[{ required: true, message: "Please enter halaqah name" }]}
            >
              <Input placeholder="Enter halaqah name" />
            </Form.Item>
            <Form.Item label="Deskripsi" name="deskripsi">
              <Input.TextArea
                placeholder="Enter halaqah description (optional)"
                rows={3}
              />
            </Form.Item>
            <Form.Item label="Guru Pengampu" name="guruId">
              <Select placeholder="Select teacher (optional)">
                {guru.map((g) => (
                  <Select.Option key={g.id} value={g.id}>
                    {g.namaLengkap}
                  </Select.Option>
                ))}
              </Select>
            </Form.Item>
            <Form.Item
              label="Pilih Santri (Minimal 5 santri)"
              name="santriIds"
              rules={[{ required: true, message: "Please select at least 5 santri" }]}
            >
              <Select
                mode="multiple"
                placeholder="Select santri for halaqah"
                maxTagCount={5}
                maxTagTextLength={20}
                style={{ width: '100%' }}
                notFoundContent={
                  santri.length === 0
                    ? "Semua santri sudah terdaftar di halaqah lain"
                    : "Tidak ada santri tersedia"
                }
              >
                {santri.map((s) => (
                  <Select.Option key={s.id} value={s.id}>
                    {s.namaLengkap}
                  </Select.Option>
                ))}
              </Select>
              {santri.length === 0 && (
                <div style={{ color: '#ff4d4f', fontSize: '12px', marginTop: '4px' }}>
                  ÔÜá´©Å Semua santri sudah terdaftar di halaqah lain
                </div>
              )}
            </Form.Item>
          </Form>
        </DynamicModal>
      </div>
    </LayoutApp>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
"use client";

import { useEffect, useState, useCallback } from "react";
import dynamic from "next/dynamic";
import {
  Row,
  Col,
  Card,
  Button,
  Form,
  Space,
  Popconfirm,
  message,
  Select,
  DatePicker,
  TimePicker,
  Typography,
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  CalendarOutlined,
  ClockCircleOutlined,
  TeamOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import dayjs from "dayjs";
import LoadingSkeleton from "@/components/layout/LoadingSkeleton";

const DynamicTable = dynamic(() => import("antd").then((mod) => mod.Table), {
  ssr: false,
  loading: () => <LoadingSkeleton type="table" count={5} />,
});

const DynamicModal = dynamic(() => import("antd").then((mod) => mod.Modal), {
  ssr: false,
});

interface Jadwal {
  id: number;
  hari: string;
  jamMulai: Date | string;
  jamSelesai: Date | string;
  halaqah: {
    id: number;
    namaHalaqah: string;
    guru?: {
      id: number;
      namaLengkap: string;
    };
    jumlahSantri?: number;
  };
}

interface Halaqah {
  id: number;
  namaHalaqah: string;
}

export default function AdminJadwalPage() {
  const [jadwal, setJadwal] = useState<Jadwal[]>([]);
  const [halaqah, setHalaqah] = useState<Halaqah[]>([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingJadwal, setEditingJadwal] = useState<Jadwal | null>(null);
  const [form] = Form.useForm();

  const hariOptions = [
    { value: "Senin", label: "Senin" },
    { value: "Selasa", label: "Selasa" },
    { value: "Rabu", label: "Rabu" },
    { value: "Kamis", label: "Kamis" },
    { value: "Jumat", label: "Jumat" },
    { value: "Sabtu", label: "Sabtu" },
    { value: "Minggu", label: "Minggu" },
  ];

  // Fetch data
  const fetchJadwal = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/jadwal");
      if (!res.ok) throw new Error("Failed to fetch jadwal");
      const data = await res.json();
      setJadwal(data);
    } catch (error: unknown) {
      console.error("Error fetching jadwal:", error);
      message.error("Error fetching jadwal");
    } finally {
      setLoading(false);
    }
  }, []);

  const fetchHalaqah = useCallback(async () => {
    try {
      const res = await fetch("/api/halaqah");
      if (!res.ok) throw new Error("Failed to fetch halaqah");
      const data = await res.json();
      setHalaqah(data);
    } catch (error: unknown) {
      console.error("Error fetching halaqah:", error);
    }
  }, []);

  useEffect(() => {
    fetchJadwal();
    fetchHalaqah();
  }, [fetchJadwal, fetchHalaqah]);

  // CRUD operations
   
  const openModal = (jadwal?: any) => {
    if (jadwal) {
      setEditingJadwal(jadwal);
      const formValues: any = {
        halaqahId: jadwal.halaqah.id,
        hari: jadwal.hari,
        jamMulai: dayjs(jadwal.jamMulai),
        jamSelesai: dayjs(jadwal.jamSelesai),
        isTemplate: jadwal.isTemplate ?? true,
        isActive: jadwal.isActive ?? true
      };

      // Add date fields if available
      if (jadwal.tanggalMulai) {
        formValues.tanggalMulai = dayjs(jadwal.tanggalMulai);
      }
      if (jadwal.tanggalSelesai) {
        formValues.tanggalSelesai = dayjs(jadwal.tanggalSelesai);
      }

      // For specific date mode
      if (!jadwal.isTemplate && jadwal.tanggalMulai) {
        formValues.tanggalSpesifik = dayjs(jadwal.tanggalMulai);
      }

      form.setFieldsValue(formValues);
    } else {
      setEditingJadwal(null);
      form.resetFields();
      // Set default values for new jadwal
      form.setFieldsValue({
        isTemplate: true,
        isActive: true
      });
    }
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    try {
      const values = await form.validateFields();

      // Convert time to string format with validation
      const payload: any = {
        hari: values.hari,
        jamMulai: values.jamMulai ? values.jamMulai.format("HH:mm:ss") : "08:00:00",
        jamSelesai: values.jamSelesai ? values.jamSelesai.format("HH:mm:ss") : "10:00:00",
        halaqahId: parseInt(values.halaqahId),
        isTemplate: Boolean(values.isTemplate ?? true),
        isActive: Boolean(values.isActive ?? true)
      };

      // Add date fields based on mode (optional)
      try {
        if (values.isTemplate !== false) {
          // Template mode - add optional date range
          if (values.tanggalMulai && values.tanggalMulai.isValid()) {
            payload.tanggalMulai = values.tanggalMulai.format("YYYY-MM-DD");
          }
          if (values.tanggalSelesai && values.tanggalSelesai.isValid()) {
            payload.tanggalSelesai = values.tanggalSelesai.format("YYYY-MM-DD");
          }
        } else {
          // Specific date mode
          payload.isTemplate = false;
          if (values.tanggalSpesifik && values.tanggalSpesifik.isValid()) {
            payload.tanggalMulai = values.tanggalSpesifik.format("YYYY-MM-DD");
            payload.tanggalSelesai = values.tanggalSpesifik.format("YYYY-MM-DD");
          }
        }
      } catch (dateError) {
        console.warn("Date processing error:", dateError);
        // Continue without dates if there's an error
      }

      const url = editingJadwal ? `/api/jadwal/${editingJadwal.id}` : "/api/jadwal";
      const method = editingJadwal ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        let errorData;
        try {
          const responseText = await res.text();
          try {
            errorData = JSON.parse(responseText);
          } catch {
            errorData = { error: `Server error (${res.status}): ${responseText}` };
          }
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }
        
        console.error('API Error Details:', errorData);
        throw new Error(errorData.error || errorData.details || `Failed to save jadwal (${res.status})`);
      }

      const data = await res.json();

      const successMessage = editingJadwal 
        ? "Jadwal berhasil diperbarui" 
        : values.isTemplate 
          ? "Template jadwal berhasil dibuat! Jadwal akan berulang setiap minggu."
          : "Jadwal spesifik berhasil dibuat!";

      message.success(successMessage);
      setIsModalOpen(false);
      form.resetFields();
      fetchJadwal();
    } catch (error: unknown) {
      console.error("Error saving jadwal:", error);
      message.error(error instanceof Error ? error.message : "Error saving jadwal");
    }
  };

  const handleDelete = async (id: number) => {
    try {
      const res = await fetch(`/api/jadwal/${id}`, { method: "DELETE" });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to delete jadwal (${res.status})`);
      }

      const data = await res.json();
      message.success(data.message || "Jadwal berhasil dihapus");

      fetchJadwal();
    } catch (error: unknown) {
      console.error("Error deleting jadwal:", error);
      message.error(error instanceof Error ? error.message : "Error deleting jadwal");
    }
  };

  // Toggle status jadwal
  const handleToggleStatus = async (id: number) => {
    try {
      const res = await fetch(`/api/jadwal/${id}/toggle`, {
        method: "PUT",
        headers: { "Content-Type": "application/json" },
      });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to toggle status (${res.status})`);
      }

      const data = await res.json();
      message.success(data.message);
      fetchJadwal();
    } catch (error: unknown) {
      console.error("Error toggling status:", error);
      message.error(error instanceof Error ? error.message : "Error toggling status");
    }
  };

  const columns = [
    {
      title: "ID",
      dataIndex: "id",
      key: "id",
      width: 80,
    },
    {
      title: "Halaqah",
      dataIndex: "halaqah",
      key: "halaqah",
       
      render: (halaqah: any) => halaqah?.namaHalaqah || "Unknown",
    },
    {
      title: "Hari",
      dataIndex: "hari",
      key: "hari",
    },
    {
      title: "Waktu",
      key: "waktu",
      render: (_: unknown, record: Jadwal) => (
        <div>
          <div style={{ fontWeight: 'bold' }}>
            {dayjs(record.jamMulai).format("HH:mm")} - {dayjs(record.jamSelesai).format("HH:mm")}
          </div>
        </div>
      ),
    },
    {
      title: "Mode & Status",
      key: "status",
      render: (_: unknown, record: any) => (
        <div>
          <div style={{ marginBottom: '4px' }}>
            {record.isTemplate ? (
              <Typography.Text style={{ fontSize: '12px', color: '#1890ff' }}>
                ­ƒôà Template
              </Typography.Text>
            ) : (
              <Typography.Text style={{ fontSize: '12px', color: '#fa8c16' }}>
                ­ƒôå Spesifik
              </Typography.Text>
            )}
          </div>
          <div>
            {record.isActive ? (
              <Typography.Text style={{ fontSize: '12px', color: '#52c41a' }}>
                ­ƒƒó Aktif
              </Typography.Text>
            ) : (
              <Typography.Text style={{ fontSize: '12px', color: '#ff4d4f' }}>
                ­ƒö┤ Nonaktif
              </Typography.Text>
            )}
          </div>
        </div>
      ),
    },
    {
      title: "Guru",
      key: "guru",
      render: (_: unknown, record: Jadwal) => (
        <div>
          {record.halaqah.guru?.namaLengkap || "Belum ditentukan"}
        </div>
      ),
    },
    {
      title: "Actions",
      key: "actions",
      width: 200,
      render: (_: unknown, record: any) => (
        <Space size="small" direction="vertical">
          <Space size="small">
            <Button
              type="text"
              icon={<EditOutlined />}
              onClick={() => openModal(record)}
              size="small"
            >
              Edit
            </Button>
            <Button
              type="text"
              onClick={() => handleToggleStatus(record.id)}
              size="small"
              style={{ 
                color: record.isActive ? '#ff4d4f' : '#52c41a'
              }}
            >
              {record.isActive ? '­ƒö┤ Nonaktifkan' : '­ƒƒó Aktifkan'}
            </Button>
          </Space>
          <Popconfirm
            title="Are you sure you want to delete this schedule?"
            onConfirm={() => handleDelete(record.id)}
            okText="Yes"
            cancelText="No"
          >
            <Button type="text" danger icon={<DeleteOutlined />} size="small">
              Delete
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <div style={{ padding: "24px 0" }}>
        <div style={{ marginBottom: 24 }}>
          <h1>Schedule Management</h1>
          <p style={{ margin: 0, color: "#666" }}>
            Manage halaqah schedules and timings
          </p>
        </div>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <CalendarOutlined style={{ fontSize: '24px', color: '#1890ff', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Total Schedules</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1890ff' }}>
                    {jadwal.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <TeamOutlined style={{ fontSize: '24px', color: '#52c41a', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>Active Halaqah</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#52c41a' }}>
                    {halaqah.length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
          <Col xs={24} sm={12} md={8}>
            <Card>
              <div style={{ display: 'flex', alignItems: 'center' }}>
                <ClockCircleOutlined style={{ fontSize: '24px', color: '#722ed1', marginRight: 12 }} />
                <div>
                  <div style={{ fontSize: '14px', color: '#666' }}>This Week</div>
                  <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#722ed1' }}>
                    {jadwal.filter(j => j.hari === dayjs().format('dddd')).length}
                  </div>
                </div>
              </div>
            </Card>
          </Col>
        </Row>

        {/* Main Content */}
        <Card
          title="Schedule List"
          extra={
            <Button type="primary" icon={<PlusOutlined />} onClick={() => openModal()}>
              Add Schedule
            </Button>
          }
        >
          <DynamicTable
            dataSource={jadwal}
            columns={columns}
            rowKey="id"
            loading={loading}
            size="small"
            scroll={{ x: 600 }}
          />
        </Card>

        {/* Modal */}
        <DynamicModal
          title={
            <Space>
              <CalendarOutlined />
              {editingJadwal ? "Edit Schedule" : "Add New Schedule"}
            </Space>
          }
          open={isModalOpen}
          onCancel={() => setIsModalOpen(false)}
          onOk={handleSave}
          okText="Save"
          width={600}
        >
          <Form form={form} layout="vertical" size="large">
            <Form.Item
              label="Halaqah"
              name="halaqahId"
              rules={[{ required: true, message: "Please select halaqah" }]}
            >
              <Select placeholder="Select halaqah">
                {halaqah.map((h) => (
                  <Select.Option key={h.id} value={h.id}>
                    {h.namaHalaqah}
                  </Select.Option>
                ))}
              </Select>
            </Form.Item>
            
            <Form.Item
              label="Mode Jadwal"
              name="isTemplate"
              initialValue={true}
            >
              <Select>
                <Select.Option value={true}>
                  ­ƒôà Template Mode (Berulang Mingguan)
                </Select.Option>
                <Select.Option value={false}>
                  ­ƒôå Specific Date Mode (Tanggal Tertentu)
                </Select.Option>
              </Select>
            </Form.Item>

            <Form.Item
              label="Hari"
              name="hari"
              rules={[{ required: true, message: "Please select day" }]}
            >
              <Select placeholder="Select day">
                {hariOptions.map((option) => (
                  <Select.Option key={option.value} value={option.value}>
                    {option.label}
                  </Select.Option>
                ))}
              </Select>
            </Form.Item>
            
            <Row gutter={16}>
              <Col span={12}>
                <Form.Item
                  label="Jam Mulai"
                  name="jamMulai"
                  rules={[{ required: true, message: "Please select start time" }]}
                >
                  <TimePicker
                    format="HH:mm"
                    placeholder="Start time"
                    style={{ width: '100%' }}
                  />
                </Form.Item>
              </Col>
              <Col span={12}>
                <Form.Item
                  label="Jam Selesai"
                  name="jamSelesai"
                  rules={[{ required: true, message: "Please select end time" }]}
                >
                  <TimePicker
                    format="HH:mm"
                    placeholder="End time"
                    style={{ width: '100%' }}
                  />
                </Form.Item>
              </Col>
            </Row>

            <Form.Item
              noStyle
              shouldUpdate={(prevValues, currentValues) => 
                prevValues.isTemplate !== currentValues.isTemplate
              }
            >
              {({ getFieldValue }) => {
                const isTemplate = getFieldValue('isTemplate');
                return isTemplate ? (
                  <div style={{ 
                    padding: '16px', 
                    background: '#f6ffed', 
                    border: '1px solid #b7eb8f', 
                    borderRadius: '6px',
                    marginBottom: '16px'
                  }}>
                    <Typography.Text strong style={{ color: '#52c41a' }}>
                      ­ƒôà Template Mode
                    </Typography.Text>
                    <br />
                    <Typography.Text style={{ fontSize: '12px' }}>
                      Jadwal akan berulang setiap minggu secara otomatis. 
                      Anda bisa mengatur periode berlaku di bawah (opsional).
                    </Typography.Text>
                    
                    <Row gutter={16} style={{ marginTop: '12px' }}>
                      <Col span={12}>
                        <Form.Item
                          label="Tanggal Mulai Berlaku (Opsional)"
                          name="tanggalMulai"
                        >
                          <DatePicker
                            style={{ width: '100%' }}
                            format="DD/MM/YYYY"
                            placeholder="Pilih tanggal mulai"
                          />
                        </Form.Item>
                      </Col>
                      <Col span={12}>
                        <Form.Item
                          label="Tanggal Selesai Berlaku (Opsional)"
                          name="tanggalSelesai"
                        >
                          <DatePicker
                            style={{ width: '100%' }}
                            format="DD/MM/YYYY"
                            placeholder="Pilih tanggal selesai"
                          />
                        </Form.Item>
                      </Col>
                    </Row>
                  </div>
                ) : (
                  <div style={{ 
                    padding: '16px', 
                    background: '#fff7e6', 
                    border: '1px solid #ffd591', 
                    borderRadius: '6px',
                    marginBottom: '16px'
                  }}>
                    <Typography.Text strong style={{ color: '#fa8c16' }}>
                      ­ƒôå Specific Date Mode
                    </Typography.Text>
                    <br />
                    <Typography.Text style={{ fontSize: '12px' }}>
                      Jadwal hanya berlaku untuk tanggal tertentu yang Anda pilih.
                    </Typography.Text>
                    
                    <Form.Item
                      label="Tanggal Spesifik"
                      name="tanggalSpesifik"
                      rules={[{ required: !isTemplate, message: "Please select specific date" }]}
                      style={{ marginTop: '12px', marginBottom: 0 }}
                    >
                      <DatePicker
                        style={{ width: '100%' }}
                        format="DD/MM/YYYY"
                        placeholder="Pilih tanggal spesifik"
                      />
                    </Form.Item>
                  </div>
                );
              }}
            </Form.Item>

            <Form.Item
              label="Status"
              name="isActive"
              initialValue={true}
            >
              <Select>
                <Select.Option value={true}>­ƒƒó Aktif</Select.Option>
                <Select.Option value={false}>­ƒö┤ Nonaktif</Select.Option>
              </Select>
            </Form.Item>
          </Form>
        </DynamicModal>
      </div>
    </LayoutApp>
  );
}

