"use client";

import { useEffect, useState, useCallback } from "react";
import dynamic from "next/dynamic";
import {
  Row,
  Col,
  Card,
  Button,
  Modal,
  Form,
  Input,
  Space,
  Popconfirm,
  message,
  Select,
  DatePicker,
  Divider,
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import dayjs from "dayjs";
import LoadingSkeleton from "@/components/layout/LoadingSkeleton";

const DynamicTable = dynamic(() => import("antd").then((mod) => mod.Table), {
  ssr: false,
  loading: () => <LoadingSkeleton type="table" count={5} />,
});

const DynamicModal = dynamic(() => import("antd").then((mod) => mod.Modal), {
  ssr: false,
});

interface Pengumuman {
  id: number;
  judul: string;
  isi: string;
  tanggal: string;
  tanggalKadaluarsa?: string;
  targetAudience: string;
  creator: {
    id: number;
    namaLengkap: string;
    role: {
      name: string;
    };
  };
  isRead?: boolean;
  readCount?: number;
  readDetails?: {
    userId: number;
    userName: string;
    userRole: string;
    readAt: string;
  }[];
  createdAt: string;
  updatedAt: string;
}

export default function AdminPengumumanPage() {
  const [pengumuman, setPengumuman] = useState<Pengumuman[]>([]);
  const [loading, setLoading] = useState(false);
  const [isModalOpen, setIsModalOpen] = useState(false);
  const [editingPengumuman, setEditingPengumuman] = useState<Pengumuman | null>(null);
  const [form] = Form.useForm();

  const audienceOptions = [
    { 
      value: "semua", 
      label: "­ƒîÉ Semua User", 
      description: "Pengumuman akan muncul di semua dashboard (Admin, Guru, Santri, Orang Tua, Yayasan)",
      color: "#1890ff"
    },
    { 
      value: "santri", 
      label: "­ƒÄô Khusus Santri", 
      description: "Hanya muncul di dashboard santri",
      color: "#fa8c16"
    },
    { 
      value: "guru", 
      label: "­ƒæ¿ÔÇì­ƒÅ½ Khusus Guru", 
      description: "Hanya muncul di dashboard guru",
      color: "#52c41a"
    },
    { 
      value: "ortu", 
      label: "­ƒæ¿ÔÇì­ƒæ®ÔÇì­ƒæºÔÇì­ƒæª Khusus Orang Tua", 
      description: "Hanya muncul di dashboard orang tua",
      color: "#722ed1"
    },
    { 
      value: "yayasan", 
      label: "­ƒÅó Khusus Yayasan", 
      description: "Hanya muncul di dashboard yayasan",
      color: "#fa8c16"
    },
    { 
      value: "admin", 
      label: "ÔÜÖ´©Å Khusus Admin", 
      description: "Hanya muncul di dashboard admin",
      color: "#f5222d"
    },
  ];

  // Fetch data
  const fetchPengumuman = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetch("/api/pengumuman");
      if (!res.ok) throw new Error("Failed to fetch pengumuman");
      const data = await res.json();
      // Handle both paginated and direct array responses
      const pengumumanData = data.data || data;
      setPengumuman(Array.isArray(pengumumanData) ? pengumumanData : []);
    } catch (error: unknown) {
      console.error("Error fetching pengumuman:", error);
      message.error("Error fetching pengumuman");
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchPengumuman();
  }, [fetchPengumuman]);

  // CRUD operations
  const openModal = (pengumuman?: Pengumuman) => {
    if (pengumuman) {
      setEditingPengumuman(pengumuman);
      form.setFieldsValue({
        judul: pengumuman.judul,
        isi: pengumuman.isi,
        targetAudience: pengumuman.targetAudience,
        tanggalKadaluarsa: pengumuman.tanggalKadaluarsa ? dayjs(pengumuman.tanggalKadaluarsa) : null,
      });
    } else {
      setEditingPengumuman(null);
      form.resetFields();
    }
    setIsModalOpen(true);
  };

  const handleSave = async () => {
    try {
      const values = await form.validateFields();
      // Prepare payload
      const payload = {
        judul: values.judul,
        isi: values.isi,
        targetAudience: values.targetAudience || 'semua',
        tanggalKadaluarsa: values.tanggalKadaluarsa ? values.tanggalKadaluarsa.toISOString() : null
      };

      const url = editingPengumuman ? `/api/pengumuman/${editingPengumuman.id}` : "/api/pengumuman";
      const method = editingPengumuman ? "PUT" : "POST";

      const res = await fetch(url, {
        method,
        headers: { "Content-Type": "application/json" },
        body: JSON.stringify(payload),
      });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to save pengumuman (${res.status})`);
      }

      const data = await res.json();

      message.success(editingPengumuman ? "Pengumuman berhasil diperbarui" : "Pengumuman berhasil ditambahkan");
      setIsModalOpen(false);
      form.resetFields();
      fetchPengumuman();
    } catch (error: unknown) {
      console.error("Error saving pengumuman:", error);
      message.error(error instanceof Error ? error.message : "Error saving pengumuman");
    }
  };

  const handleDelete = async (id: number) => {
    try {
      const res = await fetch(`/api/pengumuman/${id}`, { method: "DELETE" });

      if (!res.ok) {
        let errorData;
        try {
          errorData = await res.json();
        } catch (parseError) {
          errorData = { error: `Server error (${res.status})` };
        }
        throw new Error(errorData.error || `Failed to delete pengumuman (${res.status})`);
      }

      const data = await res.json();
      message.success(data.message || "Pengumuman berhasil dihapus");

      fetchPengumuman();
    } catch (error: unknown) {
      console.error("Error deleting pengumuman:", error);
      message.error(error instanceof Error ? error.message : "Error deleting pengumuman");
    }
  };

  const columns = [
    {
      title: "Pengumuman",
      key: "pengumuman",
      render: (record: Pengumuman) => (
        <div className="flex items-start gap-3">
          <div className="w-12 h-12 bg-gradient-to-br from-purple-500 to-indigo-600 rounded-full flex items-center justify-center text-white font-bold text-lg">
            ­ƒôó
          </div>
          <div className="flex-1">
            <div className="font-semibold text-gray-800 text-lg mb-1">{record.judul}</div>
            <div className="text-sm text-gray-500 mb-2">
              {record.isi.length > 120 ? `${record.isi.substring(0, 120)}...` : record.isi}
            </div>
            <div className="flex items-center gap-2">
              <span className="text-xs text-gray-400">ID: {record.id}</span>
              <span className="text-xs text-gray-400">ÔÇó</span>
              <span className="text-xs text-gray-400">{dayjs(record.tanggal).format("DD MMM YYYY")}</span>
            </div>
          </div>
        </div>
      ),
    },
    {
      title: "Target & Status",
      key: "target",
      render: (record: Pengumuman) => {
        const option = audienceOptions.find(opt => opt.value === record.targetAudience);
        return (
          <div>
            <div className="mb-2">
              <span 
                className="px-3 py-1 rounded-full text-sm font-medium"
                style={{ 
                  backgroundColor: option?.color + '15',
                  border: `1px solid ${option?.color}30`,
                  color: option?.color,
                }}
              >
                {option?.label || record.targetAudience}
              </span>
            </div>
            <div className="text-center">
              <div className="text-lg font-bold text-blue-600">{record.readCount || 0}</div>
              <div className="text-xs text-gray-500">pembaca</div>
            </div>
          </div>
        );
      },
    },
    {
      title: "Pembuat",
      key: "creator",
      render: (record: Pengumuman) => (
        <div className="flex items-center gap-3">
          <div className="w-10 h-10 bg-gradient-to-br from-blue-500 to-purple-600 rounded-full flex items-center justify-center text-white font-bold">
            {record.creator?.namaLengkap?.[0] || "?"}
          </div>
          <div>
            <div className="font-semibold text-gray-800">{record.creator?.namaLengkap || "Unknown"}</div>
            <div className="text-sm text-gray-500">{record.creator?.role?.name || ""}</div>
          </div>
        </div>
      ),
    },
    {
      title: "Kadaluarsa",
      key: "kadaluarsa",
      render: (record: Pengumuman) => {
        if (!record.tanggalKadaluarsa) {
          return (
            <div className="text-center">
              <div className="text-sm text-gray-500">Tidak ada</div>
              <div className="text-xs text-gray-400">batas waktu</div>
            </div>
          );
        }
        
        const isExpired = dayjs(record.tanggalKadaluarsa).isBefore(dayjs());
        const daysLeft = dayjs(record.tanggalKadaluarsa).diff(dayjs(), 'day');
        
        return (
          <div className="text-center">
            <div className={`font-medium ${isExpired ? 'text-red-600' : 'text-gray-800'}`}>
              {dayjs(record.tanggalKadaluarsa).format("DD MMM YYYY")}
            </div>
            <div className="text-xs mt-1">
              {isExpired ? (
                <span className="text-red-500">Sudah kadaluarsa</span>
              ) : daysLeft === 0 ? (
                <span className="text-orange-500">Hari ini</span>
              ) : (
                <span className="text-gray-500">{daysLeft} hari lagi</span>
              )}
            </div>
          </div>
        );
      },
    },
    {
      title: "Aksi",
      key: "actions",
      render: (record: Pengumuman) => (
        <Space>
          <Button
            type="text"
            icon={<EditOutlined />}
            onClick={() => openModal(record)}
            className="text-blue-600 hover:bg-blue-50"
          />
          <Popconfirm
            title="Yakin ingin menghapus pengumuman ini?"
            onConfirm={() => handleDelete(record.id)}
            okText="Ya"
            cancelText="Tidak"
          >
            <Button 
              type="text" 
              danger 
              icon={<DeleteOutlined />}
              className="text-red-600 hover:bg-red-50"
            />
          </Popconfirm>
          {(record as any).readDetails && (record as any).readDetails.length > 0 && (
            <Button
              type="text"
              size="small"
              onClick={() => {
                Modal.info({
                  title: `Detail Pembaca - ${record.judul}`,
                  width: 600,
                  content: (
                    <div style={{ maxHeight: '400px', overflowY: 'auto' }}>
                      {(record as any).readDetails.map((reader: any, index: number) => (
                        <div key={index} className="flex justify-between items-center p-3 mb-2 bg-gray-50 rounded-lg">
                          <div>
                            <div className="font-semibold">{reader.userName}</div>
                            <div className="text-sm text-gray-500">{reader.userRole}</div>
                          </div>
                          <div className="text-sm text-gray-400">
                            {dayjs(reader.readAt).format("DD/MM/YYYY HH:mm")}
                          </div>
                        </div>
                      ))}
                    </div>
                  ),
                });
              }}
              className="text-green-600 hover:bg-green-50"
            >
              ­ƒæü´©Å Detail
            </Button>
          )}
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <style jsx>{`
        .custom-table .ant-table-thead > tr > th {
          background: linear-gradient(135deg, #667eea 0%, #764ba2 100%);
          color: white;
          font-weight: 600;
          border: none;
        }
        .custom-table .ant-table-tbody > tr:hover > td {
          background: #f0f9ff !important;
        }
        .custom-table .ant-table-tbody > tr > td {
          border-bottom: 1px solid #e5e7eb;
          padding: 16px;
        }
      `}</style>
      <div style={{ padding: "24px 0" }}>
        {/* Header */}
        <div className="bg-gradient-to-r from-purple-600 via-blue-600 to-indigo-700 rounded-2xl p-8 text-white shadow-2xl mb-6">
          <div className="flex justify-between items-center">
            <div>
              <h1 className="text-4xl font-bold mb-2">­ƒôó Manajemen Pengumuman</h1>
              <p className="text-purple-100 text-lg">Buat dan kelola pengumuman untuk berbagai grup pengguna</p>
            </div>
            <Button 
              type="primary" 
              icon={<PlusOutlined />} 
              onClick={() => openModal()}
              size="large"
              className="bg-white/20 hover:bg-white/30 border-white/30 text-white shadow-lg"
            >
              Tambah Pengumuman
            </Button>
          </div>
        </div>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={8}>
            <Card className="text-center border-0 shadow-md hover:shadow-lg transition-all duration-300">
              <div className="text-3xl font-bold text-purple-600 mb-2">{pengumuman.length}</div>
              <div className="text-gray-600">Total Pengumuman</div>
            </Card>
          </Col>
          <Col xs={24} sm={8}>
            <Card className="text-center border-0 shadow-md hover:shadow-lg transition-all duration-300">
              <div className="text-3xl font-bold text-blue-600 mb-2">
                {Array.isArray(pengumuman) ? pengumuman.filter(p => dayjs(p.tanggal).isAfter(dayjs().startOf('month'))).length : 0}
              </div>
              <div className="text-gray-600">Bulan Ini</div>
            </Card>
          </Col>
          <Col xs={24} sm={8}>
            <Card className="text-center border-0 shadow-md hover:shadow-lg transition-all duration-300">
              <div className="text-3xl font-bold text-indigo-600 mb-2">
                {Array.isArray(pengumuman) ? pengumuman.filter(p => dayjs(p.tanggal).isAfter(dayjs().startOf('week'))).length : 0}
              </div>
              <div className="text-gray-600">Minggu Ini</div>
            </Card>
          </Col>
        </Row>

        {/* Main Content */}
        <Card title="­ƒôï Daftar Pengumuman" className="shadow-md">
          <DynamicTable
            dataSource={Array.isArray(pengumuman) ? pengumuman : []}
            columns={columns}
            rowKey="id"
            loading={loading}
            pagination={{
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true,
              showTotal: (total, range) => `${range[0]}-${range[1]} dari ${total} pengumuman`,
            }}
            className="custom-table"
          />
        </Card>

        {/* Enhanced Modal */}
        <DynamicModal
          title={
            <div className="flex items-center gap-3 p-2">
              <div className="w-10 h-10 bg-gradient-to-br from-purple-500 to-indigo-600 rounded-full flex items-center justify-center">
                <span className="text-white text-lg">­ƒôó</span>
              </div>
              <div>
                <div className="text-lg font-bold text-gray-800">
                  {editingPengumuman ? "Edit Pengumuman" : "Tambah Pengumuman Baru"}
                </div>
                <div className="text-sm text-gray-500">
                  {editingPengumuman ? "Perbarui pengumuman yang sudah ada" : "Buat pengumuman baru untuk pengguna"}
                </div>
              </div>
            </div>
          }
          open={isModalOpen}
          onCancel={() => setIsModalOpen(false)}
          onOk={handleSave}
          okText="­ƒÆ¥ Simpan Pengumuman"
          cancelText="ÔØî Batal"
          width={800}
          className="custom-modal"
        >
          <Divider />
          <Form form={form} layout="vertical" className="space-y-4">
            <Form.Item
              label={
                <span className="flex items-center gap-2 font-medium text-gray-700">
                  ­ƒôØ Judul Pengumuman
                </span>
              }
              name="judul"
              rules={[{ required: true, message: "Masukkan judul pengumuman" }]}
            >
              <Input 
                placeholder="Contoh: Libur Hari Raya Idul Fitri"
                size="large"
                className="rounded-lg"
              />
            </Form.Item>
            
            <Form.Item
              label={
                <span className="flex items-center gap-2 font-medium text-gray-700">
                  ­ƒôä Isi Pengumuman
                </span>
              }
              name="isi"
              rules={[{ required: true, message: "Masukkan isi pengumuman" }]}
            >
              <Input.TextArea
                placeholder="Tulis isi pengumuman yang jelas dan informatif..."
                rows={6}
                className="rounded-lg"
              />
            </Form.Item>

            <Row gutter={16}>
              <Col span={12}>
                <Form.Item
                  label={
                    <span className="flex items-center gap-2 font-medium text-gray-700">
                      ­ƒÄ» Target Audience
                    </span>
                  }
                  name="targetAudience"
                  rules={[{ required: true, message: "Pilih target audience" }]}
                >
                  <Select 
                    placeholder="Pilih siapa yang akan menerima pengumuman"
                    size="large"
                    className="rounded-lg"
                  >
                    {audienceOptions.map((option) => (
                      <Select.Option key={option.value} value={option.value}>
                        <div className="py-2">
                          <div className="font-bold mb-1" style={{ color: option.color }}>
                            {option.label}
                          </div>
                          <div className="text-xs text-gray-500 leading-tight">
                            {option.description}
                          </div>
                        </div>
                      </Select.Option>
                    ))}
                  </Select>
                </Form.Item>
              </Col>
              
              <Col span={12}>
                <Form.Item
                  label={
                    <span className="flex items-center gap-2 font-medium text-gray-700">
                      ­ƒôà Tanggal Kadaluarsa
                    </span>
                  }
                  name="tanggalKadaluarsa"
                >
                  <DatePicker
                    format="DD/MM/YYYY"
                    placeholder="Pilih tanggal kadaluarsa (opsional)"
                    style={{ width: '100%' }}
                    size="large"
                    className="rounded-lg"
                  />
                </Form.Item>
              </Col>
            </Row>

            <div className="bg-blue-50 border border-blue-200 rounded-lg p-4 mt-4">
              <div className="flex items-start gap-3">
                <div className="text-blue-500 text-lg">­ƒÆí</div>
                <div>
                  <div className="font-medium text-blue-800 mb-1">Tips Pengumuman Efektif:</div>
                  <ul className="text-sm text-blue-700 space-y-1">
                    <li>ÔÇó Gunakan judul yang jelas dan menarik perhatian</li>
                    <li>ÔÇó Pilih target audience yang tepat sesuai konten</li>
                    <li>ÔÇó Tulis isi yang singkat, padat, dan informatif</li>
                    <li>ÔÇó Set tanggal kadaluarsa untuk pengumuman sementara</li>
                  </ul>
                </div>
              </div>
            </div>
          </Form>
        </DynamicModal>
      </div>
    </LayoutApp>
  );
}

"use client";

import { useEffect, useState } from "react";
import {
  Row,
  Col,
  Card,
  Button,
  Select,
  Input,
  Switch,
  Space,
  Typography,
  Progress,
  message,
  Tag,
  Tabs,
  Form,
  InputNumber,
  Divider,
  Alert,
  Modal,
} from "antd";
import {
  SettingOutlined,
  DatabaseOutlined,
  SecurityScanOutlined,
  ServerOutlined,
  SaveOutlined,
  ReloadOutlined,
  ExclamationCircleOutlined,
  CheckCircleOutlined,
  ClockCircleOutlined,
  UserOutlined,
  FileTextOutlined,
  BellOutlined,
  MailOutlined,
  LockOutlined,
  EyeOutlined,
  DeleteOutlined,
  CloudServerOutlined,
  SafetyOutlined,
  MonitorOutlined,
  HistoryOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";

const { Title, Text } = Typography;
const { TextArea } = Input;

interface SystemSettings {
  appName: string;
  appDescription: string;
  contactEmail: string;
  maintenanceMode: boolean;
  allowRegistration: boolean;
  maxUsers: number;
  sessionTimeout: number;
  backupEnabled: boolean;
  emailNotifications: boolean;
  smsNotifications: boolean;
  autoBackupHour: number;
  maxFileSize: number;
  allowedFileTypes: string[];
}

interface SystemStats {
  totalUsers: number;
  activeUsers: number;
  totalUjian: number;
  totalRaport: number;
  dbSize: string;
  lastBackup: string;
  systemUptime: string;
  memoryUsage: number;
  diskUsage: number;
  cpuUsage: number;
}

export default function AdminSettingsPage() {
  const [settings, setSettings] = useState<SystemSettings>({
    appName: "AR-Hafalan",
    appDescription: "Sistem Manajemen Hafalan Al-Quran Terpadu",
    contactEmail: "admin@arhafalan.com",
    maintenanceMode: false,
    allowRegistration: true,
    maxUsers: 1000,
    sessionTimeout: 30,
    backupEnabled: true,
    emailNotifications: true,
    smsNotifications: false,
    autoBackupHour: 2,
    maxFileSize: 10,
    allowedFileTypes: ["pdf", "doc", "docx", "jpg", "png"],
  });

  const [systemStats, setSystemStats] = useState<SystemStats>({
    totalUsers: 342,
    activeUsers: 89,
    totalUjian: 1250,
    totalRaport: 340,
    dbSize: "2.4 GB",
    lastBackup: "2 jam yang lalu",
    systemUptime: "15 hari 4 jam",
    memoryUsage: 68,
    diskUsage: 45,
    cpuUsage: 23,
  });

  const [loading, setLoading] = useState(false);
  const [activeTab, setActiveTab] = useState("general");
  const [form] = Form.useForm();

  useEffect(() => {
    fetchSettings();
    fetchSystemStats();
    // Auto refresh stats every 30 seconds
    const interval = setInterval(fetchSystemStats, 30000);
    return () => clearInterval(interval);
  }, []);

  const fetchSettings = async () => {
    try {
      // Simulate API call
    } catch (error) {
      console.error("Error fetching settings:", error);
    }
  };

  const fetchSystemStats = async () => {
    try {
      // Simulate API call with random variations
      setSystemStats(prev => ({
        ...prev,
        activeUsers: 85 + Math.floor(Math.random() * 10),
        memoryUsage: 65 + Math.floor(Math.random() * 10),
        cpuUsage: 20 + Math.floor(Math.random() * 15),
      }));
    } catch (error) {
      console.error("Error fetching system stats:", error);
    }
  };

  const handleSaveSettings = async () => {
    setLoading(true);
    try {
      await new Promise(resolve => setTimeout(resolve, 1500));
      message.success("Pengaturan sistem berhasil disimpan!");
    } catch (error) {
      message.error("Gagal menyimpan pengaturan sistem");
    } finally {
      setLoading(false);
    }
  };

  const handleResetSettings = () => {
    Modal.confirm({
      title: "Reset Pengaturan",
      content: "Apakah Anda yakin ingin mereset semua pengaturan ke default?",
      icon: <ExclamationCircleOutlined />,
      okText: "Ya, Reset",
      cancelText: "Batal",
      okType: "danger",
      onOk: () => {
        // Reset to default values
        message.success("Pengaturan berhasil direset ke default");
      },
    });
  };

  const tabItems = [
    {
      key: "general",
      label: (
        <Space>
          <SettingOutlined />
          Umum
        </Space>
      ),
    },
    {
      key: "security",
      label: (
        <Space>
          <SecurityScanOutlined />
          Keamanan
        </Space>
      ),
    },
    {
      key: "system",
      label: (
        <Space>
          <ServerOutlined />
          Sistem
        </Space>
      ),
    },
    {
      key: "notifications",
      label: (
        <Space>
          <BellOutlined />
          Notifikasi
        </Space>
      ),
    },
    {
      key: "backup",
      label: (
        <Space>
          <DatabaseOutlined />
          Backup
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <div style={{ padding: "0 4px" }}>
        {/* Modern Header */}
        <div
          style={{
            marginBottom: 32,
            background: "linear-gradient(135deg, #667eea 0%, #764ba2 100%)",
            borderRadius: 20,
            padding: "32px 40px",
            color: "white",
            position: "relative",
            overflow: "hidden",
          }}
        >
          <div
            style={{
              position: "absolute",
              top: -50,
              right: -50,
              width: 200,
              height: 200,
              background: "rgba(255, 255, 255, 0.1)",
              borderRadius: "50%",
              filter: "blur(40px)",
            }}
          />
          <div
            style={{
              position: "absolute",
              bottom: -30,
              left: -30,
              width: 150,
              height: 150,
              background: "rgba(255, 255, 255, 0.08)",
              borderRadius: "50%",
              filter: "blur(30px)",
            }}
          />

          <Row align="middle" justify="space-between">
            <Col>
              <Space direction="vertical" size={4}>
                <Title
                  level={2}
                  style={{
                    color: "white",
                    margin: 0,
                    fontSize: 28,
                    fontWeight: 700,
                  }}
                >
                  <SettingOutlined style={{ marginRight: 12 }} />
                  Pengaturan Sistem
                </Title>
                <Text
                  style={{
                    color: "rgba(255, 255, 255, 0.9)",
                    fontSize: 16,
                    fontWeight: 400,
                  }}
                >
                  Kelola konfigurasi dan pengaturan sistem AR-Hafalan
                </Text>
                <Space style={{ marginTop: 8 }}>
                  <Tag
                    icon={<MonitorOutlined />}
                    style={{
                      background: "rgba(255, 255, 255, 0.2)",
                      border: "1px solid rgba(255, 255, 255, 0.3)",
                      color: "white",
                      borderRadius: 20,
                      padding: "4px 12px",
                    }}
                  >
                    System Online
                  </Tag>
                  <Tag
                    icon={<SafetyOutlined />}
                    style={{
                      background: "rgba(255, 255, 255, 0.15)",
                      border: "1px solid rgba(255, 255, 255, 0.25)",
                      color: "white",
                      borderRadius: 20,
                      padding: "4px 12px",
                    }}
                  >
                    Secure
                  </Tag>
                </Space>
              </Space>
            </Col>
            <Col>
              <Space size="middle">
                <Button
                  icon={<ReloadOutlined />}
                  size="large"
                  onClick={fetchSystemStats}
                  style={{
                    background: "rgba(255, 255, 255, 0.15)",
                    border: "1px solid rgba(255, 255, 255, 0.25)",
                    borderRadius: 12,
                    backdropFilter: "blur(10px)",
                    color: "white",
                    fontWeight: 500,
                  }}
                >
                  Refresh
                </Button>
                <Button
                  type="primary"
                  icon={<SaveOutlined />}
                  size="large"
                  loading={loading}
                  onClick={handleSaveSettings}
                  style={{
                    background: "rgba(255, 255, 255, 0.2)",
                    border: "1px solid rgba(255, 255, 255, 0.3)",
                    borderRadius: 12,
                    backdropFilter: "blur(10px)",
                    color: "white",
                    fontWeight: 600,
                  }}
                >
                  Simpan Pengaturan
                </Button>
              </Space>
            </Col>
          </Row>
        </div>

        {/* System Status Cards */}
        <Row gutter={[20, 20]} style={{ marginBottom: 32 }}>
          <Col xs={24} sm={12} lg={6}>
            <Card
              hoverable
              style={{
                borderRadius: 16,
                border: "1px solid #e8f4fd",
                background: "linear-gradient(135deg, #f0f9ff 0%, #e0f2fe 100%)",
                boxShadow: "0 2px 12px rgba(59, 130, 246, 0.08)",
                transition: "all 0.3s ease",
              }}
              styles={{ body: { padding: "24px" } }}
            >
              <Space direction="vertical" size={12} style={{ width: "100%" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                  }}
                >
                  <div
                    style={{
                      width: 48,
                      height: 48,
                      borderRadius: 12,
                      background: "linear-gradient(135deg, #3b82f6 0%, #1d4ed8 100%)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      boxShadow: "0 4px 12px rgba(59, 130, 246, 0.3)",
                    }}
                  >
                    <UserOutlined style={{ fontSize: 20, color: "white" }} />
                  </div>
                  <Tag color="blue" style={{ borderRadius: 12, fontSize: 11 }}>
                    +{systemStats.activeUsers} aktif
                  </Tag>
                </div>
                <div>
                  <Text style={{ fontSize: 13, color: "#64748b", fontWeight: 500 }}>
                    Total Pengguna
                  </Text>
                  <div
                    style={{
                      fontSize: 28,
                      fontWeight: 700,
                      color: "#1e293b",
                      lineHeight: 1,
                    }}
                  >
                    {systemStats.totalUsers}
                  </div>
                </div>
              </Space>
            </Card>
          </Col>

          <Col xs={24} sm={12} lg={6}>
            <Card
              hoverable
              style={{
                borderRadius: 16,
                border: "1px solid #f0fdf4",
                background: "linear-gradient(135deg, #f0fdf4 0%, #dcfce7 100%)",
                boxShadow: "0 2px 12px rgba(34, 197, 94, 0.08)",
                transition: "all 0.3s ease",
              }}
              styles={{ body: { padding: "24px" } }}
            >
              <Space direction="vertical" size={12} style={{ width: "100%" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                  }}
                >
                  <div
                    style={{
                      width: 48,
                      height: 48,
                      borderRadius: 12,
                      background: "linear-gradient(135deg, #22c55e 0%, #16a34a 100%)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      boxShadow: "0 4px 12px rgba(34, 197, 94, 0.3)",
                    }}
                  >
                    <DatabaseOutlined style={{ fontSize: 20, color: "white" }} />
                  </div>
                  <Tag color="green" style={{ borderRadius: 12, fontSize: 11 }}>
                    {systemStats.diskUsage}% used
                  </Tag>
                </div>
                <div>
                  <Text style={{ fontSize: 13, color: "#64748b", fontWeight: 500 }}>
                    Database Size
                  </Text>
                  <div
                    style={{
                      fontSize: 28,
                      fontWeight: 700,
                      color: "#1e293b",
                      lineHeight: 1,
                    }}
                  >
                    {systemStats.dbSize}
                  </div>
                </div>
              </Space>
            </Card>
          </Col>

          <Col xs={24} sm={12} lg={6}>
            <Card
              hoverable
              style={{
                borderRadius: 16,
                border: "1px solid #fdf4ff",
                background: "linear-gradient(135deg, #fdf4ff 0%, #fae8ff 100%)",
                boxShadow: "0 2px 12px rgba(168, 85, 247, 0.08)",
                transition: "all 0.3s ease",
              }}
              styles={{ body: { padding: "24px" } }}
            >
              <Space direction="vertical" size={12} style={{ width: "100%" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                  }}
                >
                  <div
                    style={{
                      width: 48,
                      height: 48,
                      borderRadius: 12,
                      background: "linear-gradient(135deg, #a855f7 0%, #7c3aed 100%)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      boxShadow: "0 4px 12px rgba(168, 85, 247, 0.3)",
                    }}
                  >
                    <MonitorOutlined style={{ fontSize: 20, color: "white" }} />
                  </div>
                  <Tag color="purple" style={{ borderRadius: 12, fontSize: 11 }}>
                    {systemStats.cpuUsage}% CPU
                  </Tag>
                </div>
                <div>
                  <Text style={{ fontSize: 13, color: "#64748b", fontWeight: 500 }}>
                    Memory Usage
                  </Text>
                  <div
                    style={{
                      fontSize: 28,
                      fontWeight: 700,
                      color: "#1e293b",
                      lineHeight: 1,
                    }}
                  >
                    {systemStats.memoryUsage}%
                  </div>
                </div>
              </Space>
            </Card>
          </Col>

          <Col xs={24} sm={12} lg={6}>
            <Card
              hoverable
              style={{
                borderRadius: 16,
                border: "1px solid #fff7ed",
                background: "linear-gradient(135deg, #fff7ed 0%, #fed7aa 100%)",
                boxShadow: "0 2px 12px rgba(249, 115, 22, 0.08)",
                transition: "all 0.3s ease",
              }}
              styles={{ body: { padding: "24px" } }}
            >
              <Space direction="vertical" size={12} style={{ width: "100%" }}>
                <div
                  style={{
                    display: "flex",
                    justifyContent: "space-between",
                    alignItems: "flex-start",
                  }}
                >
                  <div
                    style={{
                      width: 48,
                      height: 48,
                      borderRadius: 12,
                      background: "linear-gradient(135deg, #f97316 0%, #ea580c 100%)",
                      display: "flex",
                      alignItems: "center",
                      justifyContent: "center",
                      boxShadow: "0 4px 12px rgba(249, 115, 22, 0.3)",
                    }}
                  >
                    <ClockCircleOutlined style={{ fontSize: 20, color: "white" }} />
                  </div>
                  <Tag color="orange" style={{ borderRadius: 12, fontSize: 11 }}>
                    Online
                  </Tag>
                </div>
                <div>
                  <Text style={{ fontSize: 13, color: "#64748b", fontWeight: 500 }}>
                    System Uptime
                  </Text>
                  <div
                    style={{
                      fontSize: 16,
                      fontWeight: 700,
                      color: "#1e293b",
                      lineHeight: 1,
                    }}
                  >
                    {systemStats.systemUptime}
                  </div>
                </div>
              </Space>
            </Card>
          </Col>
        </Row>

        {/* Main Settings Tabs */}
        <Card
          style={{
            borderRadius: 16,
            border: "1px solid #e2e8f0",
            boxShadow: "0 4px 24px rgba(0, 0, 0, 0.06)",
          }}
          styles={{ body: { padding: 0 } }}
        >
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={tabItems}
            style={{ padding: "24px" }}
            size="large"
          />

          <div style={{ padding: "0 24px 24px" }}>
            {/* General Settings Tab */}
            {activeTab === "general" && (
              <div>
                <Title level={4} style={{ marginBottom: 24 }}>
                  <SettingOutlined style={{ marginRight: 8 }} />
                  Pengaturan Umum Aplikasi
                </Title>
                
                <Form form={form} layout="vertical" initialValues={settings}>
                  <Row gutter={[24, 16]}>
                    <Col xs={24} md={12}>
                      <Form.Item
                        label="Nama Aplikasi"
                        name="appName"
                        rules={[{ required: true, message: "Nama aplikasi wajib diisi" }]}
                      >
                        <Input
                          size="large"
                          placeholder="Masukkan nama aplikasi"
                          prefix={<FileTextOutlined />}
                        />
                      </Form.Item>
                    </Col>
                    <Col xs={24} md={12}>
                      <Form.Item
                        label="Email Kontak"
                        name="contactEmail"
                        rules={[
                          { required: true, message: "Email kontak wajib diisi" },
                          { type: "email", message: "Format email tidak valid" },
                        ]}
                      >
                        <Input
                          size="large"
                          placeholder="admin@example.com"
                          prefix={<MailOutlined />}
                        />
                      </Form.Item>
                    </Col>
                    <Col xs={24}>
                      <Form.Item
                        label="Deskripsi Aplikasi"
                        name="appDescription"
                        rules={[{ required: true, message: "Deskripsi aplikasi wajib diisi" }]}
                      >
                        <TextArea
                          rows={4}
                          placeholder="Deskripsi singkat tentang aplikasi"
                          showCount
                          maxLength={500}
                        />
                      </Form.Item>
                    </Col>
                  </Row>
                </Form>

                <Divider />

                <Title level={5} style={{ marginBottom: 16 }}>
                  Pengaturan Pengguna
                </Title>
                <Row gutter={[24, 16]}>
                  <Col xs={24} md={12}>
                    <div
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        padding: 16,
                        border: "1px solid #e2e8f0",
                        borderRadius: 8,
                      }}
                    >
                      <div>
                        <Text strong>Izinkan Registrasi Baru</Text>
                        <br />
                        <Text type="secondary" style={{ fontSize: 12 }}>
                          Izinkan pengguna baru untuk mendaftar
                        </Text>
                      </div>
                      <Switch
                        checked={settings.allowRegistration}
                        onChange={(checked) =>
                          setSettings({ ...settings, allowRegistration: checked })
                        }
                      />
                    </div>
                  </Col>
                  <Col xs={24} md={12}>
                    <div
                      style={{
                        padding: 16,
                        border: "1px solid #e2e8f0",
                        borderRadius: 8,
                      }}
                    >
                      <Text strong>Maksimal Pengguna</Text>
                      <br />
                      <InputNumber
                        style={{ width: "100%", marginTop: 8 }}
                        size="large"
                        min={1}
                        max={10000}
                        value={settings.maxUsers}
                        onChange={(value) =>
                          setSettings({ ...settings, maxUsers: value || 1000 })
                        }
                        formatter={(value) => `${value}`.replace(/\B(?=(\d{3})+(?!\d))/g, ",")}
                      />
                    </div>
                  </Col>
                </Row>
              </div>
            )}

            {/* Security Settings Tab */}
            {activeTab === "security" && (
              <div>
                <Title level={4} style={{ marginBottom: 24 }}>
                  <SecurityScanOutlined style={{ marginRight: 8 }} />
                  Pengaturan Keamanan Sistem
                </Title>

                <Alert
                  message="Keamanan Sistem"
                  description="Pengaturan keamanan akan mempengaruhi seluruh sistem. Pastikan Anda memahami dampak dari setiap perubahan."
                  type="warning"
                  showIcon
                  style={{ marginBottom: 24 }}
                />

                <Row gutter={[24, 16]}>
                  <Col xs={24} md={12}>
                    <Card
                      size="small"
                      title={
                        <Space>
                          <LockOutlined />
                          Mode Maintenance
                        </Space>
                      }
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          alignItems: "center",
                        }}
                      >
                        <div>
                          <Text>Aktifkan mode maintenance</Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: 12 }}>
                            Mencegah akses pengguna saat maintenance
                          </Text>
                        </div>
                        <Switch
                          checked={settings.maintenanceMode}
                          onChange={(checked) =>
                            setSettings({ ...settings, maintenanceMode: checked })
                          }
                        />
                      </div>
                    </Card>
                  </Col>
                  <Col xs={24} md={12}>
                    <Card
                      size="small"
                      title={
                        <Space>
                          <ClockCircleOutlined />
                          Session Timeout
                        </Space>
                      }
                    >
                      <Text>Timeout sesi (menit)</Text>
                      <br />
                      <InputNumber
                        style={{ width: "100%", marginTop: 8 }}
                        min={5}
                        max={480}
                        value={settings.sessionTimeout}
                        onChange={(value) =>
                          setSettings({ ...settings, sessionTimeout: value || 30 })
                        }
                        addonAfter="menit"
                      />
                    </Card>
                  </Col>
                </Row>

                <Divider />

                <Title level={5} style={{ marginBottom: 16 }}>
                  Pengaturan File Upload
                </Title>
                <Row gutter={[24, 16]}>
                  <Col xs={24} md={12}>
                    <Card size="small" title="Ukuran File Maksimal">
                      <InputNumber
                        style={{ width: "100%" }}
                        min={1}
                        max={100}
                        value={settings.maxFileSize}
                        onChange={(value) =>
                          setSettings({ ...settings, maxFileSize: value || 10 })
                        }
                        addonAfter="MB"
                      />
                    </Card>
                  </Col>
                  <Col xs={24} md={12}>
                    <Card size="small" title="Tipe File yang Diizinkan">
                      <Select
                        mode="multiple"
                        style={{ width: "100%" }}
                        placeholder="Pilih tipe file"
                        value={settings.allowedFileTypes}
                        onChange={(value) =>
                          setSettings({ ...settings, allowedFileTypes: value })
                        }
                        options={[
                          { label: "PDF", value: "pdf" },
                          { label: "DOC", value: "doc" },
                          { label: "DOCX", value: "docx" },
                          { label: "JPG", value: "jpg" },
                          { label: "PNG", value: "png" },
                          { label: "GIF", value: "gif" },
                          { label: "MP4", value: "mp4" },
                          { label: "MP3", value: "mp3" },
                        ]}
                      />
                    </Card>
                  </Col>
                </Row>
              </div>
            )}

            {/* System Info Tab */}
            {activeTab === "system" && (
              <div>
                <Title level={4} style={{ marginBottom: 24 }}>
                  <ServerOutlined style={{ marginRight: 8 }} />
                  Informasi & Status Sistem
                </Title>

                <Row gutter={[24, 16]}>
                  <Col xs={24} lg={12}>
                    <Card
                      title={
                        <Space>
                          <CloudServerOutlined />
                          Informasi Sistem
                        </Space>
                      }
                    >
                      <Space direction="vertical" size={16} style={{ width: "100%" }}>
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <Text>Versi Aplikasi</Text>
                          <Tag color="blue">v2.1.0</Tag>
                        </div>
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <Text>Environment</Text>
                          <Tag color="green">Production</Tag>
                        </div>
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <Text>Database</Text>
                          <Tag color="purple">PostgreSQL 14</Tag>
                        </div>
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <Text>Last Update</Text>
                          <Text type="secondary">
                            {new Date().toLocaleDateString("id-ID")}
                          </Text>
                        </div>
                      </Space>
                    </Card>
                  </Col>

                  <Col xs={24} lg={12}>
                    <Card
                      title={
                        <Space>
                          <MonitorOutlined />
                          Performance Monitor
                        </Space>
                      }
                    >
                      <Space direction="vertical" size={16} style={{ width: "100%" }}>
                        <div>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginBottom: 8,
                            }}
                          >
                            <Text>CPU Usage</Text>
                            <Text strong>{systemStats.cpuUsage}%</Text>
                          </div>
                          <Progress
                            percent={systemStats.cpuUsage}
                            status={systemStats.cpuUsage > 80 ? "exception" : "active"}
                            strokeColor={
                              systemStats.cpuUsage > 80
                                ? "#ff4d4f"
                                : systemStats.cpuUsage > 60
                                ? "#faad14"
                                : "#52c41a"
                            }
                          />
                        </div>
                        <div>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginBottom: 8,
                            }}
                          >
                            <Text>Memory Usage</Text>
                            <Text strong>{systemStats.memoryUsage}%</Text>
                          </div>
                          <Progress
                            percent={systemStats.memoryUsage}
                            status={systemStats.memoryUsage > 80 ? "exception" : "active"}
                            strokeColor={
                              systemStats.memoryUsage > 80
                                ? "#ff4d4f"
                                : systemStats.memoryUsage > 60
                                ? "#faad14"
                                : "#52c41a"
                            }
                          />
                        </div>
                        <div>
                          <div
                            style={{
                              display: "flex",
                              justifyContent: "space-between",
                              marginBottom: 8,
                            }}
                          >
                            <Text>Disk Usage</Text>
                            <Text strong>{systemStats.diskUsage}%</Text>
                          </div>
                          <Progress
                            percent={systemStats.diskUsage}
                            status={systemStats.diskUsage > 80 ? "exception" : "active"}
                            strokeColor={
                              systemStats.diskUsage > 80
                                ? "#ff4d4f"
                                : systemStats.diskUsage > 60
                                ? "#faad14"
                                : "#52c41a"
                            }
                          />
                        </div>
                      </Space>
                    </Card>
                  </Col>
                </Row>

                <Divider />

                <Title level={5} style={{ marginBottom: 16 }}>
                  Status Komponen Sistem
                </Title>
                <Row gutter={[16, 16]}>
                  {[
                    { name: "Database PostgreSQL", status: "healthy", icon: <DatabaseOutlined /> },
                    { name: "File Storage", status: "healthy", icon: <CloudServerOutlined /> },
                    { name: "Email Service", status: "healthy", icon: <MailOutlined /> },
                    { name: "Backup Service", status: "healthy", icon: <SafetyOutlined /> },
                  ].map((component, index) => (
                    <Col xs={24} md={12} key={index}>
                      <Card size="small">
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <Space>
                            {component.icon}
                            <Text strong>{component.name}</Text>
                          </Space>
                          <Space>
                            <CheckCircleOutlined style={{ color: "#52c41a" }} />
                            <Tag color="green">Healthy</Tag>
                          </Space>
                        </div>
                      </Card>
                    </Col>
                  ))}
                </Row>
              </div>
            )}

            {/* Notifications Tab */}
            {activeTab === "notifications" && (
              <div>
                <Title level={4} style={{ marginBottom: 24 }}>
                  <BellOutlined style={{ marginRight: 8 }} />
                  Pengaturan Notifikasi
                </Title>

                <Row gutter={[24, 16]}>
                  <Col xs={24} md={12}>
                    <Card
                      title={
                        <Space>
                          <MailOutlined />
                          Email Notifications
                        </Space>
                      }
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          alignItems: "center",
                          marginBottom: 16,
                        }}
                      >
                        <div>
                          <Text strong>Aktifkan Email</Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: 12 }}>
                            Kirim notifikasi via email
                          </Text>
                        </div>
                        <Switch
                          checked={settings.emailNotifications}
                          onChange={(checked) =>
                            setSettings({ ...settings, emailNotifications: checked })
                          }
                        />
                      </div>
                      <Divider style={{ margin: "12px 0" }} />
                      <Space direction="vertical" size={8} style={{ width: "100%" }}>
                        <Text type="secondary" style={{ fontSize: 12 }}>
                          Jenis notifikasi email:
                        </Text>
                        <div style={{ paddingLeft: 16 }}>
                          <div>ÔÇó Ujian baru dibuat</div>
                          <div>ÔÇó Raport siap diunduh</div>
                          <div>ÔÇó Backup berhasil</div>
                          <div>ÔÇó Error sistem</div>
                        </div>
                      </Space>
                    </Card>
                  </Col>

                  <Col xs={24} md={12}>
                    <Card
                      title={
                        <Space>
                          <BellOutlined />
                          SMS Notifications
                        </Space>
                      }
                    >
                      <div
                        style={{
                          display: "flex",
                          justifyContent: "space-between",
                          alignItems: "center",
                          marginBottom: 16,
                        }}
                      >
                        <div>
                          <Text strong>Aktifkan SMS</Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: 12 }}>
                            Kirim notifikasi via SMS
                          </Text>
                        </div>
                        <Switch
                          checked={settings.smsNotifications}
                          onChange={(checked) =>
                            setSettings({ ...settings, smsNotifications: checked })
                          }
                        />
                      </div>
                      <Divider style={{ margin: "12px 0" }} />
                      <Space direction="vertical" size={8} style={{ width: "100%" }}>
                        <Text type="secondary" style={{ fontSize: 12 }}>
                          Jenis notifikasi SMS:
                        </Text>
                        <div style={{ paddingLeft: 16 }}>
                          <div>ÔÇó Error kritis sistem</div>
                          <div>ÔÇó Backup gagal</div>
                          <div>ÔÇó Maintenance mode</div>
                          <div>ÔÇó Security alert</div>
                        </div>
                      </Space>
                    </Card>
                  </Col>
                </Row>
              </div>
            )}

            {/* Backup Tab */}
            {activeTab === "backup" && (
              <div>
                <Title level={4} style={{ marginBottom: 24 }}>
                  <DatabaseOutlined style={{ marginRight: 8 }} />
                  Pengaturan Backup & Recovery
                </Title>

                <Alert
                  message="Backup Otomatis Aktif"
                  description={`Backup terakhir: ${systemStats.lastBackup}. Backup otomatis berjalan setiap hari pada pukul ${settings.autoBackupHour}:00.`}
                  type="success"
                  showIcon
                  style={{ marginBottom: 24 }}
                />

                <Row gutter={[24, 16]}>
                  <Col xs={24} md={12}>
                    <Card
                      title={
                        <Space>
                          <SafetyOutlined />
                          Pengaturan Backup
                        </Space>
                      }
                    >
                      <Space direction="vertical" size={16} style={{ width: "100%" }}>
                        <div
                          style={{
                            display: "flex",
                            justifyContent: "space-between",
                            alignItems: "center",
                          }}
                        >
                          <div>
                            <Text strong>Backup Otomatis</Text>
                            <br />
                            <Text type="secondary" style={{ fontSize: 12 }}>
                              Backup harian otomatis
                            </Text>
                          </div>
                          <Switch
                            checked={settings.backupEnabled}
                            onChange={(checked) =>
                              setSettings({ ...settings, backupEnabled: checked })
                            }
                          />
                        </div>
                        <div>
                          <Text strong>Jam Backup Otomatis</Text>
                          <br />
                          <InputNumber
                            style={{ width: "100%", marginTop: 8 }}
                            min={0}
                            max={23}
                            value={settings.autoBackupHour}
                            onChange={(value) =>
                              setSettings({ ...settings, autoBackupHour: value || 2 })
                            }
                            addonAfter=":00"
                          />
                        </div>
                      </Space>
                    </Card>
                  </Col>

                  <Col xs={24} md={12}>
                    <Card
                      title={
                        <Space>
                          <HistoryOutlined />
                          Manual Backup
                        </Space>
                      }
                    >
                      <Space direction="vertical" size={16} style={{ width: "100%" }}>
                        <Text>
                          Buat backup manual untuk memastikan data terbaru tersimpan dengan aman.
                        </Text>
                        <Button
                          type="primary"
                          icon={<DatabaseOutlined />}
                          size="large"
                          block
                          onClick={() => {
                            message.loading("Membuat backup...", 2);
                            setTimeout(() => {
                              message.success("Backup berhasil dibuat!");
                            }, 2000);
                          }}
                        >
                          Buat Backup Sekarang
                        </Button>
                        <Button
                          icon={<EyeOutlined />}
                          size="large"
                          block
                          onClick={() => {
                            message.info("Menampilkan riwayat backup...");
                          }}
                        >
                          Lihat Riwayat Backup
                        </Button>
                      </Space>
                    </Card>
                  </Col>
                </Row>

                <Divider />

                <Title level={5} style={{ marginBottom: 16 }}>
                  Riwayat Backup Terbaru
                </Title>
                <div style={{ background: "#fafafa", padding: 16, borderRadius: 8 }}>
                  {[
                    { date: "2025-11-06 02:00", size: "2.4 GB", status: "success" },
                    { date: "2025-11-05 02:00", size: "2.3 GB", status: "success" },
                    { date: "2025-11-04 02:00", size: "2.3 GB", status: "success" },
                    { date: "2025-11-03 02:00", size: "2.2 GB", status: "success" },
                  ].map((backup, index) => (
                    <div
                      key={index}
                      style={{
                        display: "flex",
                        justifyContent: "space-between",
                        alignItems: "center",
                        padding: "8px 0",
                        borderBottom: index < 3 ? "1px solid #e8e8e8" : "none",
                      }}
                    >
                      <Space>
                        <CheckCircleOutlined style={{ color: "#52c41a" }} />
                        <Text>{backup.date}</Text>
                      </Space>
                      <Space>
                        <Text type="secondary">{backup.size}</Text>
                        <Tag color="green">Success</Tag>
                      </Space>
                    </div>
                  ))}
                </div>
              </div>
            )}
          </div>
        </Card>

        {/* Action Buttons */}
        <div
          style={{
            marginTop: 24,
            display: "flex",
            justifyContent: "space-between",
            alignItems: "center",
          }}
        >
          <Button
            danger
            icon={<DeleteOutlined />}
            onClick={handleResetSettings}
          >
            Reset ke Default
          </Button>
          <Space>
            <Button icon={<ReloadOutlined />} onClick={fetchSystemStats}>
              Refresh Data
            </Button>
            <Button
              type="primary"
              icon={<SaveOutlined />}
              size="large"
              loading={loading}
              onClick={handleSaveSettings}
            >
              Simpan Semua Pengaturan
            </Button>
          </Space>
        </div>
      </div>
    </LayoutApp>
  );
}

'use client'

import { useState, useEffect, useCallback } from 'react'
import { Card, CardContent, CardHeader, CardTitle } from '@/components/ui/card'
import { Button } from '@/components/ui/button'
import { Badge } from '@/components/ui/badge'
import { Tabs, TabsContent, TabsList, TabsTrigger } from '@/components/ui/tabs'
import { Plus, Edit, Trash2, CheckCircle, Calendar, Settings, BookOpen, Zap, BarChart3 } from 'lucide-react'
import { TahunAkademikDialog } from '@/components/admin/tahun-akademik/TahunAkademikDialog'
import { AutoGenerateDialog } from '@/components/admin/tahun-akademik/AutoGenerateDialog'
import { TahunAkademikSelector } from '@/components/admin/tahun-akademik/TahunAkademikSelector'
import LayoutApp from '@/components/layout/LayoutApp'
import { useToast } from '@/hooks/use-toast'
import { format } from 'date-fns'
import { id } from 'date-fns/locale'

interface TahunAkademik {
  id: number
  tahunMulai: number
  tahunSelesai: number
  semester: 'S1' | 'S2'
  namaLengkap: string
  tanggalMulai: string
  tanggalSelesai: string
  isActive: boolean
  createdAt: string
  updatedAt: string
  creator?: {
    namaLengkap: string
  }
  _count?: {
    templateUjian: number
    templateRaport: number
    ujianSantri: number
    raportSantri: number
  }
}

export default function TahunAkademikPage() {
  const [tahunAkademik, setTahunAkademik] = useState<TahunAkademik[]>([])
  const [loading, setLoading] = useState(true)
  const [selectedTahun, setSelectedTahun] = useState<TahunAkademik | null>(null)
  const [showDialog, setShowDialog] = useState(false)
  const [showAutoGenerate, setShowAutoGenerate] = useState(false)
  const [activeTahunAkademik, setActiveTahunAkademik] = useState<TahunAkademik | null>(null)
  const { toast } = useToast()

  useEffect(() => {
    fetchTahunAkademik()
  }, [fetchTahunAkademik])

  const fetchTahunAkademik = useCallback(async () => {
    try {
      const response = await fetch('/api/admin/tahun-akademik')
      if (response.ok) {
        const result = await response.json()
        if (result.success) {
          setTahunAkademik(result.data)
        }
      }
    } catch (error) {
      toast({
        title: "Error",
        description: "Gagal memuat data tahun akademik",
        variant: "destructive"
      })
    } finally {
      setLoading(false)
    }
  }, [toast])

  const handleDelete = async (id: number) => {
    if (!confirm('Yakin ingin menghapus tahun akademik ini?')) return

    try {
      const response = await fetch(`/api/admin/tahun-akademik/${id}`, {
        method: 'DELETE'
      })

      if (response.ok) {
        toast({
          title: "Berhasil",
          description: "Tahun akademik berhasil dihapus"
        })
        fetchTahunAkademik()
      } else {
        const error = await response.json()
        throw new Error(error.message || 'Gagal menghapus tahun akademik')
      }
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Gagal menghapus tahun akademik",
        variant: "destructive"
      })
    }
  }

  const handleSetActive = async (id: number) => {
    try {
      const response = await fetch('/api/admin/tahun-akademik/active', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ tahunAjaranId: id })
      })

      const result = await response.json()

      if (result.success) {
        toast({
          title: "Berhasil",
          description: result.message
        })
        fetchTahunAkademik()
      } else {
        throw new Error(result.error || 'Gagal mengaktifkan tahun akademik')
      }
    } catch (error: any) {
      toast({
        title: "Error",
        description: error.message || "Gagal mengaktifkan tahun akademik",
        variant: "destructive"
      })
    }
  }

  const getSemesterIcon = (semester: string) => {
    return semester === 'S1' ? '­ƒî×' : 'ÔØä´©Å'
  }

  const getSemesterLabel = (semester: string) => {
    return semester === 'S1' ? 'Semester 1' : 'Semester 2'
  }

  const formatDateRange = (mulai: string, selesai: string) => {
    const startDate = new Date(mulai).toLocaleDateString('id-ID', { 
      day: 'numeric', 
      month: 'short' 
    })
    const endDate = new Date(selesai).toLocaleDateString('id-ID', { 
      day: 'numeric', 
      month: 'short', 
      year: 'numeric' 
    })
    return `${startDate} - ${endDate}`
  }

  const handleAutoGenerateSuccess = () => {
    fetchTahunAkademik()
    setShowAutoGenerate(false)
  }

  const formatDate = (dateString: string) => {
    return format(new Date(dateString), 'dd MMMM yyyy', { locale: id })
  }

  if (loading) {
    return (
      <LayoutApp>
        <div className="flex items-center justify-center h-64">
          <div className="animate-spin rounded-full h-8 w-8 border-b-2 border-primary"></div>
        </div>
      </LayoutApp>
    )
  }

  return (
    <LayoutApp>
      <div className="space-y-6">
        <div className="flex justify-between items-center">
          <div>
            <h1 className="text-3xl font-bold">Tahun Akademik</h1>
            <p className="text-muted-foreground">
              Kelola pengaturan tahun akademik dan semester otomatis
            </p>
          </div>
          <div className="flex gap-2">
            <Button
              onClick={() => setShowAutoGenerate(true)}
              className="flex items-center gap-2"
              variant="outline"
            >
              <Zap className="w-4 h-4" />
              Auto Generate
            </Button>
            <Button
              onClick={() => {
                setSelectedTahun(null)
                setShowDialog(true)
              }}
              className="flex items-center gap-2"
            >
              <Plus className="w-4 h-4" />
              Tambah Manual
            </Button>
          </div>
        </div>

        <Tabs defaultValue="overview" className="space-y-6">
          <TabsList>
            <TabsTrigger value="overview" className="flex items-center gap-2">
              <BarChart3 className="w-4 h-4" />
              Overview
            </TabsTrigger>
            <TabsTrigger value="manage" className="flex items-center gap-2">
              <Settings className="w-4 h-4" />
              Kelola Data
            </TabsTrigger>
          </TabsList>

          <TabsContent value="overview" className="space-y-6">
            {/* Tahun Akademik Selector */}
            <TahunAkademikSelector
              onTahunAkademikChange={setActiveTahunAkademik}
              showStats={true}
              allowChange={true}
            />

            {/* Quick Stats */}
            <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Total Tahun Akademik</CardTitle>
                  <Calendar className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">{tahunAkademik.length}</div>
                  <p className="text-xs text-muted-foreground">
                    {tahunAkademik.filter(ta => ta.isActive).length} aktif
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Semester Saat Ini</CardTitle>
                  <BookOpen className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {activeTahunAkademik ? getSemesterIcon(activeTahunAkademik.semester) : '­ƒôà'}
                  </div>
                  <p className="text-xs text-muted-foreground">
                    {activeTahunAkademik ? getSemesterLabel(activeTahunAkademik.semester) : 'Belum ada yang aktif'}
                  </p>
                </CardContent>
              </Card>

              <Card>
                <CardHeader className="flex flex-row items-center justify-between space-y-0 pb-2">
                  <CardTitle className="text-sm font-medium">Data Tersimpan</CardTitle>
                  <CheckCircle className="h-4 w-4 text-muted-foreground" />
                </CardHeader>
                <CardContent>
                  <div className="text-2xl font-bold">
                    {activeTahunAkademik?._count ? 
                      (activeTahunAkademik._count.templateUjian + 
                       activeTahunAkademik._count.templateRaport + 
                       activeTahunAkademik._count.ujianSantri + 
                       activeTahunAkademik._count.raportSantri) : 0
                    }
                  </div>
                  <p className="text-xs text-muted-foreground">
                    Total data tahun ini
                  </p>
                </CardContent>
              </Card>
            </div>
          </TabsContent>

          <TabsContent value="manage" className="space-y-6">
            <div className="grid gap-4">
              {tahunAkademik.map((tahun) => (
                <Card key={tahun.id} className={tahun.isActive ? 'ring-2 ring-primary' : ''}>
                  <CardHeader>
                    <div className="flex justify-between items-start">
                      <div>
                        <CardTitle className="flex items-center gap-2">
                          <span>{getSemesterIcon(tahun.semester)}</span>
                          {tahun.namaLengkap}
                          <Badge variant={tahun.isActive ? "default" : "secondary"}>
                            {tahun.isActive ? "Aktif" : "Nonaktif"}
                          </Badge>
                        </CardTitle>
                        <div className="flex items-center gap-4 mt-2 text-sm text-muted-foreground">
                          <div className="flex items-center gap-1">
                            <Calendar className="h-4 w-4" />
                            <span>{formatDateRange(tahun.tanggalMulai, tahun.tanggalSelesai)}</span>
                          </div>
                          {tahun.creator && (
                            <span>Dibuat oleh: {tahun.creator.namaLengkap}</span>
                          )}
                        </div>
                      </div>
                      <div className="flex gap-2">
                        {!tahun.isActive && (
                          <Button
                            variant="outline"
                            size="sm"
                            onClick={() => handleSetActive(tahun.id)}
                            title="Aktifkan tahun akademik ini"
                          >
                            <CheckCircle className="h-4 w-4" />
                          </Button>
                        )}
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => {
                            setSelectedTahun(tahun)
                            setShowDialog(true)
                          }}
                          title="Edit tahun akademik"
                        >
                          <Edit className="h-4 w-4" />
                        </Button>
                        <Button
                          variant="outline"
                          size="sm"
                          onClick={() => handleDelete(tahun.id)}
                          disabled={tahun.isActive}
                          title="Hapus tahun akademik"
                        >
                          <Trash2 className="h-4 w-4" />
                        </Button>
                      </div>
                    </div>
                  </CardHeader>
                  {tahun._count && (
                    <CardContent>
                      <div className="grid grid-cols-4 gap-4 text-sm">
                        <div className="text-center">
                          <p className="font-medium text-green-600">{tahun._count.templateUjian}</p>
                          <p className="text-muted-foreground">Template Ujian</p>
                        </div>
                        <div className="text-center">
                          <p className="font-medium text-blue-600">{tahun._count.templateRaport}</p>
                          <p className="text-muted-foreground">Template Raport</p>
                        </div>
                        <div className="text-center">
                          <p className="font-medium text-orange-600">{tahun._count.ujianSantri}</p>
                          <p className="text-muted-foreground">Ujian Santri</p>
                        </div>
                        <div className="text-center">
                          <p className="font-medium text-purple-600">{tahun._count.raportSantri}</p>
                          <p className="text-muted-foreground">Raport Santri</p>
                        </div>
                      </div>
                    </CardContent>
                  )}
                </Card>
              ))}

              {tahunAkademik.length === 0 && (
                <Card>
                  <CardContent className="text-center py-8">
                    <Calendar className="w-12 h-12 text-muted-foreground mx-auto mb-4" />
                    <p className="text-muted-foreground mb-4">
                      Belum ada tahun akademik. Gunakan Auto Generate untuk membuat tahun akademik otomatis.
                    </p>
                    <Button onClick={() => setShowAutoGenerate(true)}>
                      <Zap className="w-4 h-4 mr-2" />
                      Auto Generate Tahun Akademik
                    </Button>
                  </CardContent>
                </Card>
              )}
            </div>
          </TabsContent>
        </Tabs>

        {/* Dialogs */}
        <TahunAkademikDialog
          open={showDialog}
          onOpenChange={setShowDialog}
          tahunAkademik={selectedTahun}
          onSuccess={() => {
            fetchTahunAkademik()
            setSelectedTahun(null)
          }}
        />

        <AutoGenerateDialog
          open={showAutoGenerate}
          onOpenChange={setShowAutoGenerate}
          onSuccess={handleAutoGenerateSuccess}
        />
      </div>
    </LayoutApp>
  )
}

