"use client";

import { useEffect, useState } from "react";
import {
    Row,
    Col,
    Card,
    Button,
    Modal,
    Form,
    Space,
    message,
    Table,
    TimePicker,
    Typography,
    Tag,
} from "antd";
import {
    EditOutlined,
    CalendarOutlined,
    ClockCircleOutlined,
    TeamOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import dayjs from "dayjs";

interface Jadwal {
    id: number;
    hari: string;
    jamMulai: Date | string;
    jamSelesai: Date | string;
    halaqah: {
        id: number;
        namaHalaqah: string;
        jumlahSantri: number;
        santri: Array<{
            id: number;
            namaLengkap: string;
        }>;
    };
}

export default function GuruJadwalPage() {
    const [jadwal, setJadwal] = useState<Jadwal[]>([]);
    const [loading, setLoading] = useState(false);
    const [isModalOpen, setIsModalOpen] = useState(false);
    const [editingJadwal, setEditingJadwal] = useState<Jadwal | null>(null);
    const [form] = Form.useForm();

    // Fetch data
    const fetchJadwal = async () => {
        try {
            setLoading(true);
            const res = await fetch("/api/guru/jadwal");
            if (!res.ok) throw new Error("Failed to fetch jadwal");
            const data = await res.json();
            setJadwal(data);
        } catch (error: any) {
            console.error("Error fetching jadwal:", error);
            message.error("Error fetching jadwal");
        } finally {
            setLoading(false);
        }
    };

    useEffect(() => {
        fetchJadwal();
    }, []);

    // Update jadwal (hanya jam)
    const openModal = (jadwal: Jadwal) => {
        setEditingJadwal(jadwal);
        form.setFieldsValue({
            jamMulai: dayjs(jadwal.jamMulai),
            jamSelesai: dayjs(jadwal.jamSelesai),
        });
        setIsModalOpen(true);
    };

    const handleSave = async () => {
        try {
            const values = await form.validateFields();
            const payload = {
                jadwalId: editingJadwal?.id,
                jamMulai: values.jamMulai.format("HH:mm:ss"),
                jamSelesai: values.jamSelesai.format("HH:mm:ss"),
            };

            const res = await fetch("/api/guru/jadwal", {
                method: "PUT",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify(payload),
            });

            if (!res.ok) {
                let errorData;
                try {
                    errorData = await res.json();
                } catch {
                    errorData = { error: `Server error (${res.status})` };
                }
                throw new Error(errorData.error || `Failed to update jadwal (${res.status})`);
            }

            const data = await res.json();
            message.success("Jadwal berhasil diperbarui");
            setIsModalOpen(false);
            form.resetFields();
            fetchJadwal();
        } catch (error: any) {
            console.error("Error updating jadwal:", error);
            message.error(error.message || "Error updating jadwal");
        }
    };

    const getHariColor = (hari: string) => {
        const colors: { [key: string]: string } = {
            'Senin': 'blue',
            'Selasa': 'green',
            'Rabu': 'orange',
            'Kamis': 'red',
            'Jumat': 'purple',
            'Sabtu': 'cyan',
            'Minggu': 'magenta'
        };
        return colors[hari] || 'default';
    };

    const columns = [
        {
            title: "Halaqah",
            dataIndex: "halaqah",
            key: "halaqah",
            render: (halaqah: any) => (
                <div>
                    <div style={{ fontWeight: 'bold' }}>{halaqah.namaHalaqah}</div>
                    <div style={{ fontSize: '12px', color: '#666' }}>
                        {halaqah.jumlahSantri} santri
                    </div>
                </div>
            ),
        },
        {
            title: "Hari",
            dataIndex: "hari",
            key: "hari",
            render: (hari: string) => (
                <Tag color={getHariColor(hari)}>{hari}</Tag>
            ),
        },
        {
            title: "Waktu",
            key: "waktu",
            render: (_: unknown, record: Jadwal) => (
                <div>
                    <div style={{ fontWeight: 'bold' }}>
                        {dayjs(record.jamMulai).format("HH:mm")} - {dayjs(record.jamSelesai).format("HH:mm")}
                    </div>
                </div>
            ),
        },
        {
            title: "Actions",
            key: "actions",
            width: 120,
            render: (_: unknown, record: Jadwal) => (
                <Button
                    type="text"
                    icon={<EditOutlined />}
                    onClick={() => openModal(record)}
                    size="small"
                >
                    Edit Waktu
                </Button>
            ),
        },
    ];

    const todaySchedule = jadwal.filter(j => j.hari === dayjs().format('dddd'));

    return (
        <LayoutApp>
            <div style={{ padding: "24px 0" }}>
                <div style={{ marginBottom: 24 }}>
                    <h1>Jadwal Mengajar</h1>
                    <p style={{ margin: 0, color: "#666" }}>
                        Kelola jadwal mengajar halaqah Anda
                    </p>
                </div>

                {/* Statistics Cards */}
                <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
                    <Col xs={24} sm={12} md={8}>
                        <Card>
                            <div style={{ display: 'flex', alignItems: 'center' }}>
                                <CalendarOutlined style={{ fontSize: '24px', color: '#1890ff', marginRight: 12 }} />
                                <div>
                                    <div style={{ fontSize: '14px', color: '#666' }}>Total Jadwal</div>
                                    <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#1890ff' }}>
                                        {jadwal.length}
                                    </div>
                                </div>
                            </div>
                        </Card>
                    </Col>
                    <Col xs={24} sm={12} md={8}>
                        <Card>
                            <div style={{ display: 'flex', alignItems: 'center' }}>
                                <ClockCircleOutlined style={{ fontSize: '24px', color: '#52c41a', marginRight: 12 }} />
                                <div>
                                    <div style={{ fontSize: '14px', color: '#666' }}>Hari Ini</div>
                                    <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#52c41a' }}>
                                        {todaySchedule.length}
                                    </div>
                                </div>
                            </div>
                        </Card>
                    </Col>
                    <Col xs={24} sm={12} md={8}>
                        <Card>
                            <div style={{ display: 'flex', alignItems: 'center' }}>
                                <TeamOutlined style={{ fontSize: '24px', color: '#722ed1', marginRight: 12 }} />
                                <div>
                                    <div style={{ fontSize: '14px', color: '#666' }}>Total Santri</div>
                                    <div style={{ fontSize: '24px', fontWeight: 'bold', color: '#722ed1' }}>
                                        {jadwal.reduce((sum, j) => sum + j.halaqah.jumlahSantri, 0)}
                                    </div>
                                </div>
                            </div>
                        </Card>
                    </Col>
                </Row>

                {/* Today's Schedule */}
                {todaySchedule.length > 0 && (
                    <Card title="Jadwal Hari Ini" style={{ marginBottom: 24 }}>
                        <Row gutter={[16, 16]}>
                            {todaySchedule.map((j) => (
                                <Col xs={24} sm={12} md={8} key={j.id}>
                                    <Card size="small" style={{ backgroundColor: '#f6ffed', border: '1px solid #b7eb8f' }}>
                                        <div style={{ textAlign: 'center' }}>
                                            <div style={{ fontWeight: 'bold', fontSize: '16px' }}>
                                                {j.halaqah.namaHalaqah}
                                            </div>
                                            <div style={{ color: '#666', margin: '8px 0' }}>
                                                {dayjs(j.jamMulai).format("HH:mm")} - {dayjs(j.jamSelesai).format("HH:mm")}
                                            </div>
                                            <div style={{ fontSize: '12px', color: '#666' }}>
                                                {j.halaqah.jumlahSantri} santri
                                            </div>
                                        </div>
                                    </Card>
                                </Col>
                            ))}
                        </Row>
                    </Card>
                )}

                {/* Main Content */}
                <Card title="Semua Jadwal">
                    <Table
                        dataSource={jadwal}
                        columns={columns}
                        rowKey="id"
                        loading={loading}
                        size="small"
                        scroll={{ x: 600 }}
                        pagination={{ pageSize: 10 }}
                    />
                </Card>

                {/* Modal */}
                <Modal
                    title={
                        <Space>
                            <ClockCircleOutlined />
                            Edit Waktu Jadwal
                        </Space>
                    }
                    open={isModalOpen}
                    onCancel={() => setIsModalOpen(false)}
                    onOk={handleSave}
                    okText="Simpan"
                    cancelText="Batal"
                    width={500}
                >
                    {editingJadwal && (
                        <div style={{ marginBottom: 16 }}>
                            <Typography.Text strong>Halaqah: </Typography.Text>
                            <Typography.Text>{editingJadwal.halaqah.namaHalaqah}</Typography.Text>
                            <br />
                            <Typography.Text strong>Hari: </Typography.Text>
                            <Tag color={getHariColor(editingJadwal.hari)}>{editingJadwal.hari}</Tag>
                        </div>
                    )}

                    <Form form={form} layout="vertical" size="large">
                        <Row gutter={16}>
                            <Col span={12}>
                                <Form.Item
                                    label="Jam Mulai"
                                    name="jamMulai"
                                    rules={[{ required: true, message: "Please select start time" }]}
                                >
                                    <TimePicker
                                        format="HH:mm"
                                        placeholder="Start time"
                                        style={{ width: '100%' }}
                                    />
                                </Form.Item>
                            </Col>
                            <Col span={12}>
                                <Form.Item
                                    label="Jam Selesai"
                                    name="jamSelesai"
                                    rules={[{ required: true, message: "Please select end time" }]}
                                >
                                    <TimePicker
                                        format="HH:mm"
                                        placeholder="End time"
                                        style={{ width: '100%' }}
                                    />
                                </Form.Item>
                            </Col>
                        </Row>
                    </Form>
                </Modal>
            </div>
        </LayoutApp>
    );
}

"use client";

import { useEffect, useState } from "react";
import { Card, Progress, Typography, List, Tag, Button, Empty, Spin, Select, Input, Statistic, Tabs } from "antd";
import {
  BookOutlined, 
  CalendarOutlined, 
  CheckCircleOutlined, 
  ClockCircleOutlined, 
  FireOutlined, 
  UserOutlined, 
  AimOutlined, 
  LineChartOutlined, 
  BarChartOutlined,
  RiseOutlined,
  EyeOutlined,
  DashboardOutlined,
  HistoryOutlined
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import { DetailHafalanModal } from "@/components/santri/hafalan/DetailHafalanModal";
import { TargetHafalanDetail } from "@/components/santri/hafalan/TargetHafalanDetail";
import dayjs from "dayjs";
import dynamic from "next/dynamic";

const XAxis = dynamic(() => import("recharts").then(mod => mod.XAxis), { ssr: false });
const YAxis = dynamic(() => import("recharts").then(mod => mod.YAxis), { ssr: false });
const CartesianGrid = dynamic(() => import("recharts").then(mod => mod.CartesianGrid), { ssr: false });
const Tooltip = dynamic(() => import("recharts").then(mod => mod.Tooltip), { ssr: false });
const ResponsiveContainer = dynamic(() => import("recharts").then(mod => mod.ResponsiveContainer), { ssr: false });
const Area = dynamic(() => import("recharts").then(mod => mod.Area), { ssr: false });
const AreaChart = dynamic(() => import("recharts").then(mod => mod.AreaChart), { ssr: false });

const { Text } = Typography;
const { Option } = Select;
const { Search } = Input;

interface HafalanProgress {
  date: string;
  ziyadah: number;
  murajaah: number;
  total: number;
  cumulative: number;
}

interface RecentHafalan {
  id: number;
  tanggal: string;
  jenis: 'ziyadah' | 'murajaah';
  surah: string;
  ayat: string;
  guru: string;
  nilai?: number;
  catatan?: string;
}

interface TargetHafalan {
  id: number;
  judul: string;
  deskripsi: string;
  targetAyat: number;
  currentAyat: number;
  deadline: string;
  status: 'active' | 'completed' | 'overdue';
  kategori: 'ziyadah' | 'murajaah';
  createdBy: string;
  priority: 'high' | 'medium' | 'low';
}

interface DashboardStats {
  totalAyat: number;
  totalSetoran: number;
  streakDays: number;
  averageDaily: number;
  monthlyProgress: number;
  targetCompletion: number;
}

export default function SantriHafalanPage() {
  const [hafalanProgress, setHafalanProgress] = useState<HafalanProgress[]>([]);
  const [recentHafalan, setRecentHafalan] = useState<RecentHafalan[]>([]);
  const [targets, setTargets] = useState<TargetHafalan[]>([]);
  const [stats, setStats] = useState<DashboardStats | null>(null);
  const [loading, setLoading] = useState(true);
  
  // Filters
  const [filterJenis, setFilterJenis] = useState<string>('all');
  const [filterPeriod, setFilterPeriod] = useState<string>('7days');
  const [searchTerm, setSearchTerm] = useState<string>('');
  const [selectedTarget, setSelectedTarget] = useState<string>('all');
  
  // Modal state
  const [selectedHafalan, setSelectedHafalan] = useState<RecentHafalan | null>(null);
  const [isModalOpen, setIsModalOpen] = useState(false);
  
  // Tab state
  const [activeTab, setActiveTab] = useState('dashboard');

  useEffect(() => {
    const fetchData = async () => {
      setLoading(true);
      try {
        const response = await fetch('/api/santri/hafalan');
        if (response.ok) {
          const result = await response.json();
          if (result.success) {
            setHafalanProgress(result.data.hafalanProgress || []);
            setRecentHafalan(result.data.recentHafalan || []);
            setTargets(result.data.targets || []);
            setStats(result.data.stats || null);
          } else {
            throw new Error(result.message);
          }
        } else {
          throw new Error('Failed to fetch data');
        }
      } catch (error) {
        console.error('Error fetching data:', error);
        // Fallback to empty data
        setHafalanProgress([]);
        setRecentHafalan([]);
        setTargets([]);
        setStats({
          totalAyat: 0,
          totalSetoran: 0,
          streakDays: 0,
          averageDaily: 0,
          monthlyProgress: 0,
          targetCompletion: 0
        });
      } finally {
        setLoading(false);
      }
    };

    fetchData();
  }, []);

  // Filter functions
  const filteredHafalan = recentHafalan.filter(item => {
    const matchesJenis = filterJenis === 'all' || item.jenis === filterJenis;
    const matchesSearch = searchTerm === '' || 
      item.surah.toLowerCase().includes(searchTerm.toLowerCase()) ||
      item.ayat.includes(searchTerm) ||
      item.guru.toLowerCase().includes(searchTerm.toLowerCase());
    return matchesJenis && matchesSearch;
  });

  const filteredTargets = targets.filter(target => {
    return selectedTarget === 'all' || target.status === selectedTarget;
  });

  const getJenisColor = (jenis: string) => {
    return jenis === 'ziyadah' ? '#1890ff' : '#52c41a';
  };

  const getJenisIcon = (jenis: string) => {
    return jenis === 'ziyadah' ? <FireOutlined /> : <BookOutlined />;
  };

  const getPriorityColor = (priority: string) => {
    switch (priority) {
      case 'high': return '#ff4d4f';
      case 'medium': return '#faad14';
      case 'low': return '#52c41a';
      default: return '#d9d9d9';
    }
  };

  const getNilaiColor = (nilai: number) => {
    if (nilai >= 90) return '#52c41a';
    if (nilai >= 80) return '#1890ff';
    if (nilai >= 70) return '#faad14';
    return '#ff4d4f';
  };

  if (loading) {
    return (
      <LayoutApp>
        <div className="flex justify-center items-center min-h-[60vh] flex-col gap-4">
          <Spin size="large" />
          <Text type="secondary">Memuat data hafalan Anda...</Text>
        </div>
      </LayoutApp>
    );
  }

  return (
    <LayoutApp>
      <div className="p-6 max-w-7xl mx-auto space-y-6">
        {/* Header Section */}
        <div className="bg-gradient-to-br from-blue-600 via-blue-700 to-indigo-800 rounded-3xl p-8 text-white relative overflow-hidden">
          <div className="absolute top-0 right-0 w-32 h-32 bg-white/10 rounded-full -translate-y-16 translate-x-16"></div>
          <div className="absolute bottom-0 left-0 w-24 h-24 bg-white/5 rounded-full translate-y-12 -translate-x-12"></div>
          
          <div className="relative z-10">
            <div className="flex items-center justify-between mb-6">
              <div>
                <h1 className="text-4xl font-bold mb-2 flex items-center gap-3">
                  <BookOutlined className="text-3xl" />
                  Dashboard Hafalan
                </h1>
                <p className="text-blue-100 text-lg">
                  Pantau progress hafalan dan pencapaian target Anda
                </p>
              </div>
              <div className="text-right">
                <div className="bg-white/20 backdrop-blur-sm rounded-2xl p-4">
                  <div className="text-2xl font-bold">{stats?.streakDays || 0}</div>
                  <div className="text-sm text-blue-100">Hari Berturut</div>
                </div>
              </div>
            </div>
          </div>
        </div>

        {/* Stats Overview */}
        <div className="grid grid-cols-1 md:grid-cols-2 lg:grid-cols-4 gap-6">
          <Card className="border-0 shadow-lg hover:shadow-xl transition-all duration-300">
            <Statistic
              title="Total Ayat Dihafal"
              value={stats?.totalAyat || 0}
              prefix={<BookOutlined className="text-blue-500" />}
              valueStyle={{ color: '#1890ff', fontSize: '28px', fontWeight: 'bold' }}
            />
            <div className="mt-2 flex items-center text-sm text-gray-500">
              <RiseOutlined className="text-green-500 mr-1" />
              +15 ayat minggu ini
            </div>
          </Card>

          <Card className="border-0 shadow-lg hover:shadow-xl transition-all duration-300">
            <Statistic
              title="Total Setoran"
              value={stats?.totalSetoran || 0}
              prefix={<CheckCircleOutlined className="text-green-500" />}
              valueStyle={{ color: '#52c41a', fontSize: '28px', fontWeight: 'bold' }}
            />
            <div className="mt-2 flex items-center text-sm text-gray-500">
              <RiseOutlined className="text-green-500 mr-1" />
              +3 setoran minggu ini
            </div>
          </Card>

          <Card className="border-0 shadow-lg hover:shadow-xl transition-all duration-300">
            <Statistic
              title="Rata-rata Harian"
              value={stats?.averageDaily || 0}
              precision={1}
              suffix="ayat"
              prefix={<BarChartOutlined className="text-purple-500" />}
              valueStyle={{ color: '#722ed1', fontSize: '28px', fontWeight: 'bold' }}
            />
            <div className="mt-2 flex items-center text-sm text-gray-500">
              <RiseOutlined className="text-green-500 mr-1" />
              Konsisten baik
            </div>
          </Card>

          <Card className="border-0 shadow-lg hover:shadow-xl transition-all duration-300">
            <Statistic
              title="Progress Target"
              value={stats?.targetCompletion || 0}
              suffix="%"
              prefix={<AimOutlined className="text-orange-500" />}
              valueStyle={{ color: '#fa8c16', fontSize: '28px', fontWeight: 'bold' }}
            />
            <div className="mt-2">
              <Progress 
                percent={stats?.targetCompletion || 0} 
                size="small" 
                strokeColor="#fa8c16"
                showInfo={false}
              />
            </div>
          </Card>
        </div>

        {/* Tabs Navigation */}
        <Tabs
          activeKey={activeTab}
          onChange={setActiveTab}
          size="large"
          className="custom-tabs"
          items={[
            {
              key: 'dashboard',
              label: (
                <span className="flex items-center gap-2">
                  <DashboardOutlined />
                  Dashboard
                </span>
              ),
              children: (
                <div className="space-y-6">
                  {/* Main Content */}
                  <div className="grid grid-cols-1 xl:grid-cols-3 gap-6">
                    {/* Progress Chart */}
                    <div className="xl:col-span-2">
                      <Card 
                        title={
                          <div className="flex items-center justify-between">
                            <span className="text-lg font-semibold flex items-center gap-2">
                              <LineChartOutlined className="text-blue-500" />
                              Grafik Progress Hafalan
                            </span>
                            <Select
                              value={filterPeriod}
                              onChange={setFilterPeriod}
                              size="small"
                              className="w-32"
                            >
                              <Option value="7days">7 Hari</Option>
                              <Option value="30days">30 Hari</Option>
                              <Option value="90days">90 Hari</Option>
                            </Select>
                          </div>
                        }
                        className="border-0 shadow-lg h-full"
                      >
                        <ResponsiveContainer width="100%" height={400}>
                          <AreaChart data={hafalanProgress}>
                            <defs>
                              <linearGradient id="ziyadahGradient" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#1890ff" stopOpacity={0.3}/>
                                <stop offset="95%" stopColor="#1890ff" stopOpacity={0}/>
                              </linearGradient>
                              <linearGradient id="murajaahGradient" x1="0" y1="0" x2="0" y2="1">
                                <stop offset="5%" stopColor="#52c41a" stopOpacity={0.3}/>
                                <stop offset="95%" stopColor="#52c41a" stopOpacity={0}/>
                              </linearGradient>
                            </defs>
                            <CartesianGrid strokeDasharray="3 3" stroke="#f0f0f0" />
                            <XAxis 
                              dataKey="date" 
                              tickFormatter={(value) => dayjs(value).format('DD/MM')}
                              stroke="#666"
                            />
                            <YAxis stroke="#666" />
                            <Tooltip
                              contentStyle={{
                                background: 'white',
                                border: 'none',
                                borderRadius: '12px',
                                boxShadow: '0 8px 32px rgba(0,0,0,0.1)'
                              }}
                              labelFormatter={(value) => `Tanggal: ${dayjs(value).format('DD/MM/YYYY')}`}
                            />
                            <Area
                              type="monotone"
                              dataKey="ziyadah"
                              stackId="1"
                              stroke="#1890ff"
                              fill="url(#ziyadahGradient)"
                              strokeWidth={2}
                              name="Ziyadah"
                            />
                            <Area
                              type="monotone"
                              dataKey="murajaah"
                              stackId="1"
                              stroke="#52c41a"
                              fill="url(#murajaahGradient)"
                              strokeWidth={2}
                              name="Murajaah"
                            />
                          </AreaChart>
                        </ResponsiveContainer>
                      </Card>
                    </div>

                    {/* Target Progress */}
                    <div>
                      <Card
                        title={
                          <div className="flex items-center justify-between">
                            <span className="text-lg font-semibold flex items-center gap-2">
                              <AimOutlined className="text-green-500" />
                              Target Hafalan
                            </span>
                            <Select
                              value={selectedTarget}
                              onChange={setSelectedTarget}
                              size="small"
                              className="w-24"
                            >
                              <Option value="all">Semua</Option>
                              <Option value="active">Aktif</Option>
                              <Option value="completed">Selesai</Option>
                            </Select>
                          </div>
                        }
                        className="border-0 shadow-lg h-full"
                      >
                        <div className="space-y-4 max-h-96 overflow-y-auto">
                          {filteredTargets.slice(0, 5).map((target) => {
                            const progress = Math.round((target.currentAyat / target.targetAyat) * 100);
                            const daysLeft = dayjs(target.deadline).diff(dayjs(), 'day');
                            
                            return (
                              <div key={target.id} className="bg-gray-50 rounded-xl p-4 hover:bg-gray-100 transition-colors">
                                <div className="flex items-start justify-between mb-3">
                                  <div className="flex-1">
                                    <h4 className="font-semibold text-gray-800 mb-1">{target.judul}</h4>
                                    <p className="text-sm text-gray-600 mb-2">{target.deskripsi}</p>
                                  </div>
                                  <div className="flex gap-1">
                                    <Tag color={getPriorityColor(target.priority)} size="small">
                                      {target.priority.toUpperCase()}
                                    </Tag>
                                    <Tag color={target.kategori === 'ziyadah' ? 'blue' : 'green'} size="small">
                                      {target.kategori}
                                    </Tag>
                                  </div>
                                </div>
                                
                                <div className="mb-3">
                                  <div className="flex justify-between items-center mb-1">
                                    <span className="text-sm text-gray-600">
                                      {target.currentAyat} / {target.targetAyat} ayat
                                    </span>
                                    <span className="text-sm font-semibold text-blue-600">
                                      {progress}%
                                    </span>
                                  </div>
                                  <Progress 
                                    percent={progress} 
                                    size="small" 
                                    strokeColor={target.kategori === 'ziyadah' ? '#1890ff' : '#52c41a'}
                                    showInfo={false}
                                  />
                                </div>
                                
                                <div className="flex justify-between items-center text-xs">
                                  <span className="text-gray-500">
                                    <CalendarOutlined className="mr-1" />
                                    {dayjs(target.deadline).format('DD/MM/YYYY')}
                                  </span>
                                  <span className={`font-medium ${
                                    daysLeft < 0 ? 'text-red-500' : 
                                    daysLeft <= 3 ? 'text-orange-500' : 'text-green-500'
                                  }`}>
                                    {daysLeft < 0 ? `${Math.abs(daysLeft)} hari terlambat` :
                                     daysLeft === 0 ? 'Hari ini' :
                                     `${daysLeft} hari lagi`}
                                  </span>
                                </div>
                              </div>
                            );
                          })}
                        </div>
                      </Card>
                    </div>
                  </div>


                </div>
              )
            },

            {
              key: 'targets',
              label: (
                <span className="flex items-center gap-2">
                  <AimOutlined />
                  Target Hafalan
                </span>
              ),
              children: (
                <TargetHafalanDetail 
                  targets={targets}
                  onTargetSelect={(target) => {
                    // TODO: Handle target selection (show detail modal, etc.)
                  }}
                />
              )
            },
            {
              key: 'history',
              label: (
                <span className="flex items-center gap-2">
                  <HistoryOutlined />
                  Riwayat Setoran
                </span>
              ),
              children: (
                <Card
                  title={
                    <div className="flex items-center justify-between">
                      <span className="text-lg font-semibold flex items-center gap-2">
                        <ClockCircleOutlined className="text-purple-500" />
                        Riwayat Setoran Lengkap
                      </span>
                      <div className="flex gap-2">
                        <Search
                          placeholder="Cari surah, ayat..."
                          value={searchTerm}
                          onChange={(e) => setSearchTerm(e.target.value)}
                          style={{ width: 200 }}
                          size="small"
                        />
                        <Select
                          value={filterJenis}
                          onChange={setFilterJenis}
                          size="small"
                          className="w-32"
                        >
                          <Option value="all">Semua</Option>
                          <Option value="ziyadah">Ziyadah</Option>
                          <Option value="murajaah">Murajaah</Option>
                        </Select>
                      </div>
                    </div>
                  }
                  className="border-0 shadow-lg"
                >
                  {filteredHafalan.length > 0 ? (
                    <List
                      dataSource={filteredHafalan}
                      renderItem={(item) => (
                        <List.Item className="hover:bg-gray-50 rounded-lg transition-colors px-4">
                          <List.Item.Meta
                            avatar={
                              <div className={`w-12 h-12 rounded-xl flex items-center justify-center text-white font-semibold`}
                                   style={{ backgroundColor: getJenisColor(item.jenis) }}>
                                {getJenisIcon(item.jenis)}
                              </div>
                            }
                            title={
                              <div className="flex items-center justify-between">
                                <div>
                                  <span className="font-semibold text-gray-800">
                                    {item.surah} <span className="text-gray-500">({item.ayat})</span>
                                  </span>
                                  <div className="flex gap-2 mt-1">
                                    <Tag color={item.jenis === 'ziyadah' ? 'blue' : 'green'} size="small">
                                      {item.jenis === 'ziyadah' ? 'Ziyadah' : 'Murajaah'}
                                    </Tag>
                                    {item.nilai && (
                                      <Tag color={getNilaiColor(item.nilai)} size="small">
                                        Nilai: {item.nilai}
                                      </Tag>
                                    )}
                                  </div>
                                </div>
                                <Button 
                                  type="text" 
                                  size="small" 
                                  icon={<EyeOutlined />}
                                  onClick={() => {
                                    setSelectedHafalan(item);
                                    setIsModalOpen(true);
                                  }}
                                >
                                  Detail
                                </Button>
                              </div>
                            }
                            description={
                              <div className="space-y-1">
                                <div className="flex items-center justify-between text-sm">
                                  <span className="text-gray-500">
                                    <CalendarOutlined className="mr-1" />
                                    {dayjs(item.tanggal).format('DD/MM/YYYY')}
                                  </span>
                                  <span className="text-gray-500">
                                    <UserOutlined className="mr-1" />
                                    {item.guru}
                                  </span>
                                </div>
                                {item.catatan && (
                                  <div className="text-sm text-gray-600 bg-gray-100 rounded-lg p-2 mt-2">
                                    <strong>Catatan:</strong> {item.catatan}
                                  </div>
                                )}
                              </div>
                            }
                          />
                        </List.Item>
                      )}
                      pagination={{
                        pageSize: 10,
                        showSizeChanger: false,
                        showQuickJumper: true,
                        showTotal: (total, range) => `${range[0]}-${range[1]} dari ${total} setoran`
                      }}
                    />
                  ) : (
                    <Empty
                      image={Empty.PRESENTED_IMAGE_SIMPLE}
                      description={
                        <div>
                          <Text type="secondary">
                            {searchTerm || filterJenis !== 'all' 
                              ? 'Tidak ada setoran yang sesuai dengan filter'
                              : 'Belum ada setoran hafalan'
                            }
                          </Text>
                          <br />
                          <Text type="secondary" style={{ fontSize: '12px' }}>
                            Setoran akan diinput oleh guru Anda
                          </Text>
                        </div>
                      }
                    />
                  )}
                </Card>
              )
            }
          ]}
        />

        {/* Detail Modal */}
        <DetailHafalanModal
          open={isModalOpen}
          onClose={() => {
            setIsModalOpen(false);
            setSelectedHafalan(null);
          }}
          hafalan={selectedHafalan}
        />
      </div>
    </LayoutApp>
  );
}

"use client";

import { useEffect, useState } from "react";
import { Row, Col, Card, Statistic, Space, Spin } from "antd";
import {
  UserOutlined,
  TeamOutlined,
  BookOutlined,
  CalendarOutlined,
  DatabaseOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";

interface DashboardData {
  overview: {
    totalSantri: number;
    totalGuru: number;
    totalAdmin: number;
    totalSuperAdmin: number;
    totalOrtu: number;
    totalYayasan: number;
    totalHalaqah: number;
    totalJadwal: number;
    totalPengumuman: number;
    totalUsers: number;
    totalRoles: number;
  };
  performance: {
    attendanceRate: number;
    hafalanRate: number;
  };
  halaqahStats: Array<{
    id: number;
    namaHalaqah: string;
    santriCount: number;
    hafalanCount: number;
    attendanceRate: number;
    hafalanRate: number;
  }>;
  recentActivities: {
    hafalan: Array<{
      id: number;
      type: string;
      description: string;
      date: string;
    }>;
    absensi: Array<{
      id: number;
      type: string;
      description: string;
      date: string;
    }>;
  };
}

export default function SuperAdminDashboard() {
   const [dashboardData, setDashboardData] = useState<DashboardData | null>(null);
   const [loading, setLoading] = useState(false);
   const [lastUpdate, setLastUpdate] = useState<Date>(new Date());

   // Fetch dashboard data
   const fetchDashboardData = async () => {
     try {
       setLoading(true);
       const res = await fetch("/api/analytics/dashboard");
       if (!res.ok) throw new Error("Failed to fetch dashboard data");
        const data = await res.json();
        setDashboardData(data);
       setLastUpdate(new Date());
     } catch (error) {
       console.error("Dashboard error:", error);
       // Handle error silently for dashboard
     } finally {
       setLoading(false);
     }
   };

   useEffect(() => {
     fetchDashboardData();
     // Auto refresh every 30 seconds to keep data synchronized
     const interval = setInterval(fetchDashboardData, 30000);
     return () => clearInterval(interval);
   }, []);

   // Statistics from API data
   const totalUsers = dashboardData?.overview?.totalUsers ?? 0;
   const totalSantri = dashboardData?.overview?.totalSantri ?? 0;
   const totalGuru = dashboardData?.overview?.totalGuru ?? 0;
   const totalAdmin = dashboardData?.overview?.totalAdmin ?? 0;
   const totalSuperAdmin = dashboardData?.overview?.totalSuperAdmin ?? 0;
   const totalOrtu = dashboardData?.overview?.totalOrtu ?? 0;
   const totalYayasan = dashboardData?.overview?.totalYayasan ?? 0;
   const hafalanRate = dashboardData?.performance?.hafalanRate ?? 0;
   const attendanceRate = dashboardData?.performance?.attendanceRate ?? 0;

  return (
    <LayoutApp>
      <div style={{ padding: "24px", maxWidth: '1400px', margin: '0 auto' }}>
        <div style={{ marginBottom: 32, textAlign: 'center' }}>
          <h1 style={{ marginBottom: 8, color: '#1f2937', fontSize: '28px', fontWeight: 'bold' }}>
            ­ƒîÖ Super Admin Dashboard
          </h1>
          <p style={{ margin: 0, color: "#6b7280", fontSize: '16px' }}>
            Overview of system statistics and user management
          </p>
          <div style={{ marginTop: 8, fontSize: '12px', color: '#9ca3af' }}>
            Data auto-refreshes every 30 seconds ÔÇó Last updated: {lastUpdate.toLocaleTimeString()}
          </div>
        </div>

        {loading ? (
          <div style={{ textAlign: 'center', padding: '80px 20px', background: '#fafafa', borderRadius: '12px', margin: '20px 0' }}>
            <Spin size="large" />
            <p style={{ marginTop: 16, color: '#6b7280', fontSize: '16px' }}>Loading dashboard data...</p>
          </div>
        ) : (
          <>
            {/* Statistics Cards - First Row (4 cards) */}
            <Row gutter={[16, 16]} style={{ marginBottom: 16 }}>
              <Col xs={24} sm={12} md={6}>
