/* eslint-disable @typescript-eslint/no-explicit-any */
"use client";

import { useState, useEffect, useCallback } from "react";
import Image from "next/image";
import {
  Card,
  Table,
  Button,
  Space,
  Modal,
  Form,
  Input,
  Select,
  message,
  Popconfirm,
  Tag,
  Typography,
  Row,
  Col,
  Avatar,
  Tooltip,
  Badge,
  Tabs,
  Upload,
  Descriptions
} from "antd";
import {
  PlusOutlined,
  EditOutlined,
  DeleteOutlined,
  UserOutlined,
  UnlockOutlined,
  TeamOutlined,
  UserSwitchOutlined,
  SettingOutlined,
  InfoCircleOutlined,
  CameraOutlined,
  UploadOutlined
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import PageHeader from "@/components/layout/PageHeader";
import PhoneNumberInput from "@/components/common/PhoneNumberInput";
import { formatPhoneNumberDisplay } from "@/lib/utils/phoneFormatter";

const { Title, Text } = Typography;
const { Option } = Select;

interface User {
  id: number;
  username: string;
  namaLengkap: string;
  email?: string;
  noTlp?: string;
  foto?: string;
  passCode?: string;
  alamat?: string;
  createdAt: string;
  updatedAt: string;
  role: {
    id: number;
    name: string;
  };
}

interface Role {
  id: number;
  name: string;
}

export default function SuperAdminUsersManagement() {
  const [roles, setRoles] = useState<Role[]>([]);
  const [loading, setLoading] = useState(false);
  const [rolesLoading, setRolesLoading] = useState(false);
  const [modalVisible, setModalVisible] = useState(false);
  const [roleModalVisible, setRoleModalVisible] = useState(false);
  const [detailModalVisible, setDetailModalVisible] = useState(false);
  const [photoModalVisible, setPhotoModalVisible] = useState(false);
  const [editingUser, setEditingUser] = useState<User | null>(null);
  const [editingRole, setEditingRole] = useState<Role | null>(null);
  const [selectedUser, setSelectedUser] = useState<User | null>(null);
  const [activeTab, setActiveTab] = useState('users');
  const [uploadedPhoto, setUploadedPhoto] = useState<string>('');
  const [santriList, setSantriList] = useState<User[]>([]);
  const [selectedChildren, setSelectedChildren] = useState<number[]>([]);
  const [allUsers, setAllUsers] = useState<User[]>([]);
  const [filteredUsers, setFilteredUsers] = useState<User[]>([]);
  const [filterRole, setFilterRole] = useState<string>('');
  const [filterName, setFilterName] = useState<string>('');
  const [usedSantriIds, setUsedSantriIds] = useState<number[]>([]);
  const [santriAssignments, setSantriAssignments] = useState<Record<number, { santri: any; parents: any[] }>>({});
  const [passcodeValidation, setPasscodeValidation] = useState<{
    isValid: boolean;
    message: string;
    isChecking: boolean;
  }>({ isValid: true, message: '', isChecking: false });
  const [form] = Form.useForm();
  const [roleForm] = Form.useForm();

  // Fetch users
  const fetchUsers = async () => {
    try {
      setLoading(true);
      const response = await fetch('/api/users');
      if (!response.ok) throw new Error('Failed to fetch users');
      const data = await response.json();
      setAllUsers(data);
      setFilteredUsers(data);
    } catch (error) {
      console.error('Error fetching users:', error);
      message.error('Gagal memuat data user');
    } finally {
      setLoading(false);
    }
  };

  // Fetch roles
  const fetchRoles = async () => {
    try {
      setRolesLoading(true);
      const response = await fetch('/api/roles');
      if (!response.ok) throw new Error('Failed to fetch roles');
      const data = await response.json();
      setRoles(data);
    } catch (error) {
      console.error('Error fetching roles:', error);
      message.error('Gagal memuat data role');
    } finally {
      setRolesLoading(false);
    }
  };

  // Fetch santri list for ortu selection
  const fetchSantriList = async () => {
    try {
      const response = await fetch('/api/users?role=santri');
      if (!response.ok) throw new Error('Failed to fetch santri');
      const data = await response.json();
      setSantriList(data);
    } catch (error) {
      console.error('Error fetching santri:', error);
      message.error('Gagal memuat data santri');
    }
  };

  // Fetch used santri IDs (santri yang sudah punya ortu)
  const fetchUsedSantriIds = async () => {
    try {
      const response = await fetch('/api/ortu/used-santri');
      if (!response.ok) throw new Error('Failed to fetch used santri');
      const data = await response.json();
      setUsedSantriIds(data);
    } catch (error) {
      console.error('Error fetching used santri:', error);
      // Don't show error as this is optional
    }
  };

  // Fetch detailed santri assignments
  const fetchSantriAssignments = async () => {
    try {
      const response = await fetch('/api/ortu/santri-assignments');
      if (!response.ok) throw new Error('Failed to fetch santri assignments');
      const data = await response.json();
      setSantriAssignments(data);
    } catch (error) {
      console.error('Error fetching santri assignments:', error);
    }
  };

  // Fetch children for specific user (ortu)
  const fetchUserChildren = async (userId: number) => {
    try {
      const response = await fetch(`/api/users/${userId}/children`);
      if (!response.ok) throw new Error('Failed to fetch user children');
      const childrenIds = await response.json();
      setSelectedChildren(childrenIds);

      // Refresh used santri list to get latest data
      refreshAssignmentData();
    } catch (error) {
      console.error('Error fetching user children:', error);
      setSelectedChildren([]);
    }
  };

  // Refresh all assignment data efficiently
  const refreshAssignmentData = async () => {
    try {
      const response = await fetch('/api/ortu/refresh-assignments', {
        method: 'POST'
      });
      if (!response.ok) throw new Error('Failed to refresh assignments');
      const data = await response.json();

      setUsedSantriIds(data.usedSantriIds);
      setSantriAssignments(data.santriAssignments);
    } catch (error) {
      console.error('Error refreshing assignment data:', error);
      // Fallback to individual fetches
      fetchUsedSantriIds();
      fetchSantriAssignments();
    }
  };

  // Check passcode uniqueness
  const checkPasscodeUniqueness = async (passcode: string, excludeUserId?: number) => {
    if (!passcode || passcode.length < 6 || passcode.length > 10) {
      setPasscodeValidation({ isValid: false, message: '', isChecking: false });
      return false;
    }

    // Validate passcode is alphanumeric (huruf dan angka)
    if (!/^[a-zA-Z0-9]+$/.test(passcode)) {
      setPasscodeValidation({ 
        isValid: false, 
        message: 'Passcode hanya boleh huruf dan angka (tanpa spasi atau simbol)', 
        isChecking: false 
      });
      return false;
    }

    setPasscodeValidation({ isValid: false, message: '', isChecking: true });

    try {
      const response = await fetch('/api/users/check-passcode', {
        method: 'POST',
        headers: { 
          'Content-Type': 'application/json',
          'Cache-Control': 'no-cache'
        },
        body: JSON.stringify({ 
          passCode: passcode,
          excludeUserId: excludeUserId || null
        })
      });

      if (!response.ok) {
        throw new Error('Failed to check passcode');
      }

      const data = await response.json();
      if (data.exists) {
        setPasscodeValidation({
          isValid: false,
          message: `Passcode sudah digunakan oleh ${data.user.namaLengkap} (@${data.user.username})`,
          isChecking: false
        });
        return false;
      } else {
        setPasscodeValidation({
          isValid: true,
          message: 'Ô£ô Passcode tersedia dan dapat digunakan',
          isChecking: false
        });
        return true;
      }
    } catch (error) {
      console.error('ÔØî Error checking passcode:', error);
      setPasscodeValidation({
        isValid: false,
        message: 'Gagal mengecek passcode. Silakan coba lagi.',
        isChecking: false
      });
      return false;
    }
  };

  // Filter users based on role and name
  const applyFilters = useCallback(() => {
    let filtered = [...allUsers];

    // Filter by role
    if (filterRole) {
      filtered = filtered.filter(user =>
        user.role.name.toLowerCase() === filterRole.toLowerCase()
      );
    }

    // Filter by name
    if (filterName) {
      filtered = filtered.filter(user =>
        user.namaLengkap.toLowerCase().includes(filterName.toLowerCase()) ||
        user.username.toLowerCase().includes(filterName.toLowerCase())
      );
    }

    setFilteredUsers(filtered);
  }, [allUsers, filterRole, filterName]);



  // Create or update role
  const handleRoleSubmit = async (values: { name: string }) => {
    try {
      const url = editingRole ? `/api/roles/${editingRole.id}` : '/api/roles';
      const method = editingRole ? 'PUT' : 'POST';

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(values),
      });

      if (!response.ok) throw new Error('Failed to save role');

      if (editingRole) {
        message.success(`Role "${values.name}" berhasil diperbarui. Perubahan akan tersinkronisasi dengan semua user.`);
      } else {
        message.success(`Role "${values.name}" telah berhasil ditambahkan ke sistem dengan hak akses dasar.`);
      }

      setRoleModalVisible(false);
      setEditingRole(null);
      roleForm.resetFields();
      fetchRoles();
    } catch (error) {
      console.error('Error saving role:', error);
      message.error('Gagal menyimpan role');
    }
  };

  // Delete role
  const handleDeleteRole = async (role: Role) => {
    try {
      const response = await fetch(`/api/roles/${role.id}`, {
        method: 'DELETE',
      });

      if (!response.ok) throw new Error('Failed to delete role');

      message.success(`Role "${role.name}" berhasil dihapus`);
      fetchRoles();
    } catch (error) {
      console.error('Error deleting role:', error);
      message.error('Gagal menghapus role');
    }
  };

  // Create or update user
  const handleSubmit = async (values: any) => {
    try {
      // Validate passcode if provided
      if (values.passCode) {
        if (!passcodeValidation.isValid) {
          message.error('Passcode tidak valid atau sudah digunakan. Silakan gunakan passcode lain.');
          return;
        }
      }

      const url = editingUser ? `/api/users/${editingUser.id}` : '/api/users';
      const method = editingUser ? 'PUT' : 'POST';

      // Add children data for ortu role
      const userData = { ...values };
      if (values.roleId) {
        const selectedRole = roles.find(r => r.id === values.roleId);
        if (selectedRole?.name.toLowerCase() === 'ortu') {
          userData.children = selectedChildren;
        }
      }

      const response = await fetch(url, {
        method,
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify(userData),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to save user');
      }

      if (editingUser) {
        message.success(`User "${values.namaLengkap}" berhasil diperbarui`);
      } else {
        message.success(`User "${values.namaLengkap}" berhasil ditambahkan`);
      }

      setModalVisible(false);
      setEditingUser(null);
      setSelectedChildren([]);
      setPasscodeValidation({ isValid: false, message: '', isChecking: false });
      form.resetFields();
      fetchUsers(); // This will refresh the table with updated passcode data
      refreshAssignmentData(); // Refresh assignment data efficiently
    } catch (error: any) {
      console.error('Error saving user:', error);
      message.error(error.message || 'Gagal menyimpan user');
    }
  };



  // Delete user
  const handleDelete = async (user: User) => {
    try {
      const response = await fetch(`/api/users/${user.id}`, {
        method: 'DELETE',
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to delete user');
      }

      message.success(`User "${user.namaLengkap}" berhasil dihapus`);
      fetchUsers();
      refreshAssignmentData(); // Refresh assignment data efficiently
    } catch (error: any) {
      console.error('Error deleting user:', error);
      message.error(error.message || 'Gagal menghapus user');
    }
  };



  // Open detail modal
  const handleViewDetail = (user: User) => {
    setSelectedUser(user);
    setDetailModalVisible(true);
  };

  // Open photo modal
  const handleManagePhoto = (user: User) => {
    setSelectedUser(user);
    setUploadedPhoto(user.foto || '');
    setPhotoModalVisible(true);
  };

  // Update photo
  const handleUpdatePhoto = async () => {
    try {
      const response = await fetch(`/api/users/${selectedUser?.id}/photo`, {
        method: 'PUT',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ foto: uploadedPhoto }),
      });

      if (!response.ok) {
        const errorData = await response.json();
        throw new Error(errorData.error || 'Failed to update photo');
      }

      message.success(`Foto untuk "${selectedUser?.namaLengkap}" berhasil diperbarui`);
      setPhotoModalVisible(false);
      setSelectedUser(null);
      setUploadedPhoto('');
      fetchUsers();
    } catch (error: any) {
      console.error('Error updating photo:', error);
      message.error(error.message || 'Gagal memperbarui foto');
    }
  };

  // Handle photo upload
  const handlePhotoUpload = (info: any) => {
    if (info.file.status === 'done') {
      const photoUrl = info.file.response?.url || `/uploads/users/${info.file.response?.filename}`;
      setUploadedPhoto(photoUrl);
      message.success('Foto berhasil diupload');
    } else if (info.file.status === 'error') {
      message.error('Gagal mengupload foto');
    }
  };

  useEffect(() => {
    fetchUsers();
    fetchRoles();
    fetchSantriList();
    fetchUsedSantriIds();
    fetchSantriAssignments();
  }, []);

  // Apply filters when filter values change
  useEffect(() => {
    applyFilters();
  }, [applyFilters]);

  const userColumns = [
    {
      title: 'User',
      key: 'user',
      render: (record: User) => (
        <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
          <Avatar
            size={50}
            src={record.foto}
            icon={<UserOutlined />}
            style={{
              backgroundColor: '#1890ff',
              border: '2px solid #f0f0f0',
              cursor: record.foto ? 'pointer' : 'default'
            }}
            onClick={() => {
              if (record.foto) {
                // Show photo preview modal
                Modal.info({
                  title: `Foto ${record.namaLengkap}`,
                  content: (
                    <div style={{ textAlign: 'center', padding: '20px 0' }}>
                      <Image
                        src={record.foto || '/default-avatar.png'}
                        alt={record.namaLengkap || 'Avatar'}
                        width={400}
                        height={400}
                        style={{
                          maxWidth: '100%',
                          maxHeight: '400px',
                          borderRadius: '8px',
                          boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                          objectFit: 'contain'
                        }}
                      />
                    </div>
                  ),
                  width: 500,
                  okText: 'Tutup'
                });
              }
            }}
          />
          <div>
            <Text strong>{record.namaLengkap}</Text>
            <br />
            <Text type="secondary" style={{ fontSize: 12 }}>
              @{record.username}
            </Text>
          </div>
        </div>
      ),
    },
    {
      title: 'Role',
      dataIndex: ['role', 'name'],
      key: 'role',
      render: (roleName: string) => {
        const roleColors: Record<string, string> = {
          'super_admin': 'red',
          'admin': 'orange',
          'yayasan': 'purple',
          'guru': 'blue',
          'santri': 'green',
          'ortu': 'cyan'
        };
        return (
          <Tag color={roleColors[roleName.toLowerCase()] || 'default'}>
            {roleName}
          </Tag>
        );
      },
    },
    {
      title: 'Anak (Santri)',
      key: 'children',
      render: (record: User) => {
        // Only show for ortu role
        if (record.role.name.toLowerCase() !== 'ortu') {
          return <Text type="secondary">-</Text>;
        }

        // Get children for this ortu from santriAssignments
        const ortuAssignments = Object.values(santriAssignments || {}).filter(
          (assignment: any) => assignment.parents.some((parent: any) => parent.id === record.id)
        );

        if (ortuAssignments.length === 0) {
          return <Text type="secondary" style={{ fontSize: 12 }}>Belum ada anak</Text>;
        }

        return (
          <div style={{ textAlign: 'center' }}>
            <Badge
              count={ortuAssignments.length}
              style={{ backgroundColor: '#52c41a' }}
              title={`Total ${ortuAssignments.length} anak`}
            />
            <div style={{ fontSize: 11, color: '#666', marginTop: 4 }}>
              {ortuAssignments.length} anak
            </div>
          </div>
        );
      },
    },
    {
      title: 'No. Telepon',
      key: 'phone',
      render: (record: User) => (
        <div>
          {record.noTlp ? (
            <Text style={{ fontSize: 12 }}>
              {formatPhoneNumberDisplay(record.noTlp)}
            </Text>
          ) : (
            <Text type="secondary" style={{ fontSize: 12 }}>
              Belum diset
            </Text>
          )}
        </div>
      ),
    },
    {
      title: 'Passcode Login',
      key: 'passcode',
      render: (record: User) => (
        <div style={{ display: 'flex', flexDirection: 'column', gap: 4 }}>
          <div style={{ display: 'flex', alignItems: 'center', gap: 8 }}>
            {record.passCode ? (
              <>
                <Badge status="success" />
                <Text strong style={{ fontFamily: 'monospace', fontSize: 14 }}>
                  {record.passCode}
                </Text>
              </>
            ) : (
              <Badge status="default" text="Belum diset" />
            )}
          </div>
          {record.passCode && (
            <Text type="secondary" style={{ fontSize: 11 }}>
              Login: {record.passCode}
            </Text>
          )}
        </div>
      ),
    },
    {
      title: 'Aksi',
      key: 'actions',
      render: (record: User) => (
        <Space wrap>
          <Tooltip title="Lihat Detail">
            <Button
              type="default"
              size="small"
              icon={<InfoCircleOutlined />}
              onClick={() => handleViewDetail(record)}
            />
          </Tooltip>
          <Tooltip title="Edit User">
            <Button
              type="default"
              size="small"
              icon={<EditOutlined />}
              onClick={() => {
                setEditingUser(record);
                // Set validation to valid for existing passcode
                if (record.passCode) {
                  setPasscodeValidation({ 
                    isValid: true, 
                    message: 'Passcode saat ini valid', 
                    isChecking: false 
                  });
                } else {
                  setPasscodeValidation({ 
                    isValid: false, 
                    message: '', 
                    isChecking: false 
                  });
                }
                // Load existing children for ortu
                if (record.role.name.toLowerCase() === 'ortu') {
                  // Fetch children data for this ortu
                  fetchUserChildren(record.id);
                }
                form.setFieldsValue({
                  ...record,
                  roleId: record.role.id
                });
                setModalVisible(true);
              }}
            />
          </Tooltip>
          {record.role.name.toLowerCase() === 'santri' && (
            <Tooltip title="Kelola Foto">
              <Button
                type="default"
                size="small"
                icon={<CameraOutlined />}
                onClick={() => handleManagePhoto(record)}
              />
            </Tooltip>
          )}
          <Popconfirm
            title="Hapus User"
            description={`Yakin ingin menghapus user "${record.namaLengkap}"?`}
            onConfirm={() => handleDelete(record)}
            okText="Ya"
            cancelText="Tidak"
          >
            <Button
              danger
              size="small"
              icon={<DeleteOutlined />}
            />
          </Popconfirm>
        </Space>
      ),
    },
  ];

  const roleColumns = [
    {
      title: 'Nama Role',
      dataIndex: 'name',
      key: 'name',
      render: (name: string) => (
        <Space>
          <UserSwitchOutlined style={{ color: '#1890ff' }} />
          <Text strong>{name}</Text>
        </Space>
      ),
    },
    {
      title: 'Jumlah User',
      dataIndex: ['_count', 'users'],
      key: 'userCount',
      render: (count: number) => (
        <Tag color="blue" icon={<TeamOutlined />}>
          {count || 0} user
        </Tag>
      ),
    },
    {
      title: 'Aksi',
      key: 'actions',
      render: (record: Role) => (
        <Space>
          <Button
            type="default"
            size="small"
            icon={<EditOutlined />}
            onClick={() => {
              setEditingRole(record);
              roleForm.setFieldsValue(record);
              setRoleModalVisible(true);
            }}
          >
            Edit
          </Button>
          <Popconfirm
            title="Hapus Role"
            description={`Yakin ingin menghapus role "${record.name}"?`}
            onConfirm={() => handleDeleteRole(record)}
            okText="Ya"
            cancelText="Tidak"
          >
            <Button
              danger
              size="small"
              icon={<DeleteOutlined />}
            >
              Hapus
            </Button>
          </Popconfirm>
        </Space>
      ),
    },
  ];

  return (
    <LayoutApp>
      <div style={{ display: "flex", flexDirection: "column", gap: 24 }}>
        <PageHeader
          title="Manajemen User & Role (Super Admin)"
          subtitle="Kelola data pengguna, role, dan hak akses sistem - Akses Eksklusif Super Admin"
          breadcrumbs={[
            { title: "Super Admin Dashboard", href: "/super-admin/dashboard" },
            { title: "Manajemen User & Role" }
          ]}
          extra={
            <Space>
              {activeTab === 'users' && (
                <>

                  <Button
                    type="primary"
                    icon={<PlusOutlined />}
                    onClick={() => {
                      setEditingUser(null);
                      setSelectedChildren([]);
                      setPasscodeValidation({ isValid: false, message: '', isChecking: false });
                      form.resetFields();
                      setModalVisible(true);
                    }}
                  >
                    Tambah User Baru
                  </Button>
                </>
              )}
              {activeTab === 'roles' && (
                <Button
                  type="primary"
                  icon={<PlusOutlined />}
                  onClick={() => {
                    setEditingRole(null);
                    roleForm.resetFields();
                    setRoleModalVisible(true);
                  }}
                >
                  Tambah Role Baru
                </Button>
              )}
            </Space>
          }
        />

        {/* Info Card */}
        <Card>
          <Row gutter={[16, 16]}>
            <Col xs={24} md={8}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <UnlockOutlined style={{ fontSize: 24, color: '#52c41a' }} />
                <div>
                  <Title level={5} style={{ margin: 0 }}>Super Admin Access</Title>
                  <Text type="secondary">
                    Akses penuh untuk mengelola user, role, dan passcode
                  </Text>
                </div>
              </div>
            </Col>
            <Col xs={24} md={8}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <TeamOutlined style={{ fontSize: 24, color: '#1890ff' }} />
                <div>
                  <Title level={5} style={{ margin: 0 }}>Akses Eksklusif</Title>
                  <Text type="secondary">
                    Halaman ini hanya dapat diakses oleh Super Admin
                  </Text>
                </div>
              </div>
            </Col>
            <Col xs={24} md={8}>
              <div style={{ display: 'flex', alignItems: 'center', gap: 12 }}>
                <SettingOutlined style={{ fontSize: 24, color: '#fa8c16' }} />
                <div>
                  <Title level={5} style={{ margin: 0 }}>Sinkronisasi Data</Title>
                  <Text type="secondary">
                    Perubahan tersinkronisasi dengan semua modul
                  </Text>
                </div>
              </div>
            </Col>
          </Row>
        </Card>

        {/* Tabs for Users and Roles */}
        <Card>
          <Tabs
            activeKey={activeTab}
            onChange={setActiveTab}
            items={[
              {
                key: 'users',
                label: (
                  <span>
                    <UserOutlined />
                    Manajemen User
                  </span>
                ),
                children: (
                  <div>
                    {/* Filter Section */}
                    <Card size="small" style={{ marginBottom: 16 }}>
                      <Row gutter={16}>
                        <Col xs={24} sm={8}>
                          <Select
                            placeholder="Filter berdasarkan role"
                            value={filterRole}
                            onChange={setFilterRole}
                            allowClear
                            style={{ width: '100%' }}
                          >
                            {roles.map(role => (
                              <Option key={role.name} value={role.name}>
                                <Tag color={
                                  role.name.toLowerCase() === 'super_admin' ? 'red' :
                                    role.name.toLowerCase() === 'admin' ? 'orange' :
                                      role.name.toLowerCase() === 'yayasan' ? 'purple' :
                                        role.name.toLowerCase() === 'guru' ? 'blue' :
                                          role.name.toLowerCase() === 'santri' ? 'green' :
                                            role.name.toLowerCase() === 'ortu' ? 'cyan' : 'default'
                                }>
                                  {role.name}
                                </Tag>
                              </Option>
                            ))}
                          </Select>
                        </Col>
                        <Col xs={24} sm={8}>
                          <Input
                            placeholder="Cari berdasarkan nama atau username"
                            value={filterName}
                            onChange={(e) => setFilterName(e.target.value)}
                            allowClear
                          />
                        </Col>
                        <Col xs={24} sm={8}>
                          <Text type="secondary">
                            Menampilkan {filteredUsers.length} dari {allUsers.length} user
                          </Text>
                        </Col>
                      </Row>
                    </Card>

                    <Table
                      columns={userColumns}
                      dataSource={filteredUsers}
                      rowKey="id"
                      loading={loading}
                      pagination={{
                        pageSize: 10,
                        showSizeChanger: true,
                        showQuickJumper: true,
                        showTotal: (total) => `Total ${total} user`,
                      }}
                    />
                  </div>
                ),
              },
              {
                key: 'roles',
                label: (
                  <span>
                    <UserSwitchOutlined />
                    Manajemen Role
                  </span>
                ),
                children: (
                  <Table
                    columns={roleColumns}
                    dataSource={roles}
                    rowKey="id"
                    loading={rolesLoading}
                    pagination={{
                      pageSize: 10,
                      showSizeChanger: true,
                      showQuickJumper: true,
                      showTotal: (total) => `Total ${total} role`,
                    }}
                  />
                ),
              },
            ]}
          />
        </Card>

        {/* Add/Edit Role Modal */}
        <Modal
          title={editingRole ? "Edit Role" : "Tambah Role Baru"}
          open={roleModalVisible}
          onCancel={() => {
            setRoleModalVisible(false);
            setEditingRole(null);
            roleForm.resetFields();
          }}
          footer={null}
        >
          <Form
            form={roleForm}
            layout="vertical"
            onFinish={handleRoleSubmit}
          >
            <Form.Item
              name="name"
              label="Nama Role"
              rules={[
                { required: true, message: 'Nama role harus diisi' },
                { min: 3, message: 'Nama role minimal 3 karakter' },
              ]}
            >
              <Input placeholder="Contoh: koordinator, pengawas, dll" />
            </Form.Item>

            {!editingRole && (
              <div style={{
                background: '#f6ffed',
                border: '1px solid #b7eb8f',
                borderRadius: 6,
                padding: 12,
                marginBottom: 16
              }}>
                <Text type="secondary">
                  <SettingOutlined style={{ color: '#52c41a', marginRight: 8 }} />
                  Role baru akan otomatis mendapat hak akses dasar (dashboard, profil, pengumuman)
                </Text>
              </div>
            )}

            <Form.Item style={{ marginBottom: 0, textAlign: 'right' }}>
              <Space>
                <Button onClick={() => setRoleModalVisible(false)}>
                  Batal
                </Button>
                <Button type="primary" htmlType="submit">
                  {editingRole ? 'Update' : 'Simpan'}
                </Button>
              </Space>
            </Form.Item>
          </Form>
        </Modal>

        {/* Add/Edit User Modal */}
        <Modal
          title={editingUser ? "Edit User" : "Tambah User Baru"}
          open={modalVisible}
          onCancel={() => {
            setModalVisible(false);
            setEditingUser(null);
            setPasscodeValidation({ isValid: false, message: '', isChecking: false });
            form.resetFields();
          }}
          footer={null}
          width={600}
        >
          <Form
            form={form}
            layout="vertical"
            onFinish={handleSubmit}
          >
            <Row gutter={16}>
              <Col xs={24} sm={12}>
                <Form.Item
                  name="username"
                  label="Username (Nama Tampilan)"
                  rules={[
                    { required: true, message: 'Username harus diisi' },
                    { min: 3, message: 'Username minimal 3 karakter' },
                  ]}
                  extra="Username untuk tampilan profil, bukan untuk login"
                >
                  <Input placeholder="Contoh: ahmad_santri, guru_ali" />
                </Form.Item>
              </Col>
              <Col xs={24} sm={12}>
                <Form.Item
                  name="namaLengkap"
                  label="Nama Lengkap (Data Profil)"
                  rules={[
                    { required: true, message: 'Nama lengkap harus diisi' },
                  ]}
                  extra="Nama lengkap untuk data profil dan identitas"
                >
                  <Input placeholder="Contoh: Ahmad Fauzi, Dr. Ali Rahman" />
                </Form.Item>
              </Col>
            </Row>

            <Row gutter={16}>
              <Col xs={24} sm={12}>
                <Form.Item
                  name="email"
                  label="Email"
                  rules={[
                    { type: 'email', message: 'Format email tidak valid' },
                  ]}
                >
                  <Input placeholder="email@example.com" />
                </Form.Item>
              </Col>
              <Col xs={24} sm={12}>
                <Form.Item
                  name="noTlp"
                  label="No. Telepon"
                >
                  <PhoneNumberInput placeholder="Masukkan nomor telepon" />
                </Form.Item>
              </Col>
            </Row>

            <Form.Item
              name="roleId"
              label="Role"
              rules={[
                { required: true, message: 'Role harus dipilih' },
              ]}
            >
              <Select
                placeholder="Pilih role user"
                onChange={(value) => {
                  const selectedRole = roles.find(r => r.id === value);
                  if (selectedRole?.name.toLowerCase() !== 'ortu') {
                    setSelectedChildren([]);
                  }
                }}
              >
                {roles.map(role => (
                  <Option key={role.id} value={role.id}>
                    {role.name}
                  </Option>
                ))}
              </Select>
            </Form.Item>

            {/* Children selection for ortu role */}
            {(() => {
              const selectedRoleId = form.getFieldValue('roleId');
              const selectedRole = roles.find(r => r.id === selectedRoleId);

              if (selectedRole?.name.toLowerCase() !== 'ortu') return null;

              // Filter available santri (exclude already used ones, except current selection)
              const currentEditingId = editingUser?.id;
              const availableSantri = santriList.filter(santri => {
                // If editing, allow current children to be selected
                if (currentEditingId && selectedChildren.includes(santri.id)) {
                  return true;
                }
                // Otherwise, exclude santri that are already assigned to other ortu
                return !usedSantriIds.includes(santri.id);
              });

              return (
                <Form.Item
                  label="Pilih Anak (Santri)"
                  extra={
                    <div>
                      <div>Pilih santri yang menjadi anak dari orang tua ini. {availableSantri.length} santri tersedia.</div>
                      {usedSantriIds.length > 0 && (
                        <div style={{ color: '#ff4d4f', fontSize: 12, marginTop: 4 }}>
                          ÔÜá´©Å Santri yang sudah dipilih orang tua lain tidak dapat dipilih lagi.
                          Hapus hubungan orang tua-santri yang lama terlebih dahulu jika ingin mengubah.
                        </div>
                      )}
                    </div>
                  }
                >
                  <Select
                    mode="multiple"
                    placeholder="Pilih santri sebagai anak"
                    value={selectedChildren}
                    onChange={setSelectedChildren}
                    style={{ width: '100%' }}
                    showSearch
                    filterOption={(input, option) => {
                      const santri = santriList.find(s => s.id === option?.value);
                      return santri ?
                        santri.namaLengkap.toLowerCase().includes(input.toLowerCase()) ||
                        santri.username.toLowerCase().includes(input.toLowerCase())
                        : false;
                    }}
                    tagRender={(props) => {
                      const { label, value, closable, onClose } = props;
                      const santri = santriList.find(s => s.id === value);

                      return (
                        <Tag
                          closable={closable}
                          onClose={onClose}
                          style={{
                            display: 'inline-flex',
                            alignItems: 'center',
                            gap: 4,
                            margin: '2px',
                            padding: '2px 8px',
                            backgroundColor: '#f6ffed',
                            border: '1px solid #b7eb8f',
                            borderRadius: '6px'
                          }}
                        >
                          <Avatar
                            size={16}
                            src={santri?.foto}
                            icon={<UserOutlined />}
                            style={{
                              backgroundColor: '#52c41a',
                              flexShrink: 0
                            }}
                          />
                          <span style={{ verticalAlign: 'middle' }}>
                            {santri?.namaLengkap || label}
                          </span>
                        </Tag>
                      );
                    }}
                  >
                    {availableSantri.map(santri => {
                      const isUsed = usedSantriIds.includes(santri.id) && !selectedChildren.includes(santri.id);
                      const assignment = santriAssignments[santri.id];
                      return (
                        <Option
                          key={santri.id}
                          value={santri.id}
                          disabled={isUsed}
                        >
                          <div style={{
                            display: 'flex',
                            alignItems: 'center',
                            gap: 8,
                            opacity: isUsed ? 0.5 : 1
                          }}>
                            <Avatar size={20} src={santri.foto} icon={<UserOutlined />} />
                            <div style={{ flex: 1 }}>
                              <div style={{ fontWeight: isUsed ? 400 : 500 }}>
                                {santri.namaLengkap}
                              </div>
                              <div style={{ fontSize: 11, color: '#666' }}>
                                @{santri.username}
                                {isUsed && (
                                  <span style={{ color: '#ff4d4f', fontWeight: 500 }}>
                                    {' ÔÇó Sudah dipilih oleh: {parentNames}'}
                                  </span>
                                )}
                              </div>
                            </div>
                            {isUsed && (
                              <div style={{
                                fontSize: 10,
                                color: '#ff4d4f',
                                background: '#fff2f0',
                                padding: '2px 6px',
                                borderRadius: 4,
                                border: '1px solid #ffccc7'
                              }}>
                                Tidak Tersedia
                              </div>
                            )}
                          </div>
                        </Option>
                      );
                    })}
                  </Select>


                </Form.Item>
              );
            })()}



            <Form.Item
              name="passCode"
              label="Passcode Login (6-10 karakter)"
              rules={[
                { required: true, message: 'Passcode harus diisi' },
                { min: 6, message: 'Passcode minimal 6 karakter' },
                { max: 10, message: 'Passcode maksimal 10 karakter' },
                { pattern: /^[a-zA-Z0-9]+$/, message: 'Passcode hanya boleh huruf dan angka' },
              ]}
              extra="Passcode 6-10 karakter (huruf/angka) untuk login ke sistem"
              validateStatus={
                passcodeValidation.isChecking ? 'validating' :
                passcodeValidation.isValid ? 'success' : 'error'
              }
              help={
                passcodeValidation.isChecking ? 'Mengecek ketersediaan passcode...' :
                passcodeValidation.message || 'Masukkan 6-10 karakter unik (huruf/angka) untuk login'
              }
            >
              <Input
                placeholder="Contoh: guru123, santri01, admin2024"
                maxLength={10}
                onChange={(e) => {
                  const value = e.target.value;
                  
                  // If empty, reset validation
                  if (!value) {
                    setPasscodeValidation({ isValid: false, message: '', isChecking: false });
                    return;
                  }
                  
                  // If editing and passcode hasn't changed, keep it valid
                  if (editingUser && value === editingUser.passCode) {
                    setPasscodeValidation({ 
                      isValid: true, 
                      message: 'Ô£ô Passcode saat ini (tidak berubah)', 
                      isChecking: false 
                    });
                    return;
                  }
                  
                  // Validate format first
                  if (value.length < 6) {
                    setPasscodeValidation({ 
                      isValid: false, 
                      message: 'Passcode minimal 6 karakter', 
                      isChecking: false 
                    });
                    return;
                  }
                  
                  if (!/^[a-zA-Z0-9]+$/.test(value)) {
                    setPasscodeValidation({ 
                      isValid: false, 
                      message: 'Passcode hanya boleh huruf dan angka (tanpa spasi/simbol)', 
                      isChecking: false 
                    });
                    return;
                  }
                  
                  // Check uniqueness for new passcode
                  if (value.length >= 6 && value.length <= 10) {
                    checkPasscodeUniqueness(value, editingUser?.id);
                  }
                }}
                suffix={
                  <div style={{ minWidth: '20px', textAlign: 'center' }}>
                    {passcodeValidation.isChecking ? (
                      <span style={{ color: '#1890ff' }}>ÔÅ│</span>
                    ) : passcodeValidation.isValid && form.getFieldValue('passCode')?.length >= 6 ? (
                      <span style={{ color: '#52c41a' }}>Ô£ô</span>
                    ) : form.getFieldValue('passCode')?.length >= 6 ? (
                      <span style={{ color: '#ff4d4f' }}>Ô£ù</span>
                    ) : (
                      <span style={{ opacity: 0 }}>-</span>
                    )}
                  </div>
                }
              />
            </Form.Item>

            <Form.Item
              name="alamat"
              label="Alamat"
            >
              <Input.TextArea rows={3} placeholder="Alamat lengkap" />
            </Form.Item>

            <Form.Item style={{ marginBottom: 0, textAlign: 'right' }}>
              <Space>
                <Button onClick={() => setModalVisible(false)}>
                  Batal
                </Button>
                <Button 
                  type="primary" 
                  htmlType="submit"
                  disabled={
                    passcodeValidation.isChecking ||
                    (form.getFieldValue('passCode') && (
                      !passcodeValidation.isValid ||
                      form.getFieldValue('passCode')?.length < 6 ||
                      form.getFieldValue('passCode')?.length > 10
                    ))
                  }
                  loading={loading}
                >
                  {editingUser ? 'Update' : 'Simpan'}
                </Button>
              </Space>
            </Form.Item>
          </Form>
        </Modal>

        {/* User Detail Modal */}
        <Modal
          title={`Detail User - ${selectedUser?.namaLengkap}`}
          open={detailModalVisible}
          onCancel={() => {
            setDetailModalVisible(false);
            setSelectedUser(null);
          }}
          footer={[
            <Button key="close" onClick={() => setDetailModalVisible(false)}>
              Tutup
            </Button>
          ]}
          width={600}
        >
          {selectedUser && (
            <div>
              <div style={{ textAlign: 'center', marginBottom: 24 }}>
                {selectedUser.foto ? (
                  <div>
                    <Image
                      src={selectedUser.foto || '/default-avatar.png'}
                      alt={selectedUser.namaLengkap || 'Avatar'}
                      width={120}
                      height={120}
                      style={{
                        width: '120px',
                        height: '120px',
                        borderRadius: '50%',
                        objectFit: 'cover',
                        border: '3px solid #1890ff',
                        boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                        cursor: 'pointer'
                      }}
                      onClick={() => {
                        Modal.info({
                          title: `Foto ${selectedUser.namaLengkap}`,
                          content: (
                            <div style={{ textAlign: 'center', padding: '20px 0' }}>
                              <Image
                                src={selectedUser.foto || '/default-avatar.png'}
                                alt={selectedUser.namaLengkap || 'Avatar'}
                                width={400}
                                height={400}
                                style={{
                                  maxWidth: '100%',
                                  maxHeight: '400px',
                                  borderRadius: '8px',
                                  boxShadow: '0 4px 12px rgba(0,0,0,0.15)',
                                  objectFit: 'contain'
                                }}
                              />
                            </div>
                          ),
                          width: 500,
                          okText: 'Tutup'
                        });
                      }}
                    />
                    <div style={{ marginTop: 8 }}>
                      <Text type="secondary" style={{ fontSize: 12 }}>
                        Klik foto untuk memperbesar
                      </Text>
                    </div>
                  </div>
                ) : (
                  <Avatar
                    size={120}
                    icon={<UserOutlined />}
                    style={{ backgroundColor: '#1890ff' }}
                  />
                )}
              </div>

              <Descriptions bordered column={1}>
                <Descriptions.Item label="Username (Nama Tampilan)">
                  <div>
                    <Text strong>@{selectedUser.username}</Text>
                    <br />
                    <Text type="secondary" style={{ fontSize: 12 }}>
                      Nama tampilan profil (bukan untuk login)
                    </Text>
                  </div>
                </Descriptions.Item>
                <Descriptions.Item label="Nama Lengkap">
                  {selectedUser.namaLengkap}
                </Descriptions.Item>
                <Descriptions.Item label="Role">
                  <Tag color={
                    selectedUser.role.name.toLowerCase() === 'super_admin' ? 'red' :
                      selectedUser.role.name.toLowerCase() === 'admin' ? 'orange' :
                        selectedUser.role.name.toLowerCase() === 'yayasan' ? 'purple' :
                          selectedUser.role.name.toLowerCase() === 'guru' ? 'blue' :
                            selectedUser.role.name.toLowerCase() === 'santri' ? 'green' :
                              selectedUser.role.name.toLowerCase() === 'ortu' ? 'cyan' : 'default'
                  }>
                    {selectedUser.role.name}
                  </Tag>
                </Descriptions.Item>
                <Descriptions.Item label="Email">
                  {selectedUser.email || '-'}
                </Descriptions.Item>
                <Descriptions.Item label="No. Telepon">
                  {selectedUser.noTlp ? formatPhoneNumberDisplay(selectedUser.noTlp) : '-'}
                </Descriptions.Item>
                <Descriptions.Item label="Alamat">
                  {selectedUser.alamat || '-'}
                </Descriptions.Item>
                <Descriptions.Item label="Passcode Login">
                  {selectedUser.passCode ? (
                    <div>
                      <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 4 }}>
                        <Badge status="success" />
                        <Text strong style={{ fontFamily: 'monospace', fontSize: 16 }}>
                          {selectedUser.passCode}
                        </Text>
                      </div>
                      <Text type="secondary" style={{ fontSize: 12 }}>
                        Passcode 6-10 digit untuk login ke sistem
                      </Text>
                    </div>
                  ) : (
                    <div>
                      <Badge status="default" text="Belum diset" />
                      <br />
                      <Text type="secondary" style={{ fontSize: 12 }}>
                        User belum bisa login tanpa passcode
                      </Text>
                    </div>
                  )}
                </Descriptions.Item>
                {selectedUser.role.name.toLowerCase() === 'ortu' && (
                  <Descriptions.Item label="Anak (Santri)">
                    {(() => {
                      const ortuAssignments = Object.values(santriAssignments || {}).filter(
                        (assignment: any) => assignment.parents.some((parent: any) => parent.id === selectedUser.id)
                      );

                      if (ortuAssignments.length === 0) {
                        return <Text type="secondary">Belum ada anak yang terdaftar</Text>;
                      }

                      return (
                        <div>
                          <div style={{ marginBottom: 8 }}>
                            <Badge
                              count={ortuAssignments.length}
                              style={{ backgroundColor: '#52c41a' }}
                            />
                            <Text style={{ marginLeft: 8 }}>Total {ortuAssignments.length} anak</Text>
                          </div>
                          <div style={{ display: 'flex', flexWrap: 'wrap', gap: 8 }}>
                            {ortuAssignments.map((assignment: any) => (
                              <div
                                key={assignment.santri.id}
                                style={{
                                  display: 'flex',
                                  alignItems: 'center',
                                  gap: 8,
                                  padding: '8px 12px',
                                  border: '1px solid #d9d9d9',
                                  borderRadius: '6px',
                                  backgroundColor: '#f6ffed',
                                  minWidth: 200
                                }}
                              >
                                <Avatar
                                  size={32}
                                  src={assignment.santri.foto}
                                  icon={<UserOutlined />}
                                  style={{ backgroundColor: '#52c41a' }}
                                />
                                <div>
                                  <Text strong style={{ fontSize: 13 }}>
                                    {assignment.santri.namaLengkap}
                                  </Text>
                                  <br />
                                  <Text type="secondary" style={{ fontSize: 11 }}>
                                    @{assignment.santri.username}
                                  </Text>
                                </div>
                              </div>
                            ))}
                          </div>
                        </div>
                      );
                    })()}
                  </Descriptions.Item>
                )}
                <Descriptions.Item label="Tanggal Dibuat">
                  {new Date(selectedUser.createdAt).toLocaleDateString('id-ID', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit'
                  })}
                </Descriptions.Item>
                <Descriptions.Item label="Terakhir Diupdate">
                  {new Date(selectedUser.updatedAt).toLocaleDateString('id-ID', {
                    year: 'numeric',
                    month: 'long',
                    day: 'numeric',
                    hour: '2-digit',
                    minute: '2-digit'
                  })}
                </Descriptions.Item>
              </Descriptions>
            </div>
          )}
        </Modal>

        {/* Photo Management Modal */}
        <Modal
          title={`Kelola Foto - ${selectedUser?.namaLengkap}`}
          open={photoModalVisible}
          onCancel={() => {
            setPhotoModalVisible(false);
            setSelectedUser(null);
            setUploadedPhoto('');
          }}
          footer={[
            <Button key="cancel" onClick={() => setPhotoModalVisible(false)}>
              Batal
            </Button>,
            <Button key="save" type="primary" onClick={handleUpdatePhoto}>
              Simpan Foto
            </Button>
          ]}
        >
          {selectedUser && (
            <div>
              <div style={{
                background: '#f6ffed',
                border: '1px solid #b7eb8f',
                borderRadius: 6,
                padding: 16,
                marginBottom: 16
              }}>
                <div style={{ display: 'flex', alignItems: 'center', gap: 8, marginBottom: 8 }}>
                  <CameraOutlined style={{ color: '#52c41a' }} />
                  <Text strong>Kelola Foto Santri</Text>
                </div>
                <Text type="secondary" style={{ fontSize: 12 }}>
                  Hanya Super Admin yang dapat mengedit foto santri. Santri tidak dapat mengedit foto sendiri di profil.
                </Text>
              </div>

              <div style={{ textAlign: 'center', marginBottom: 24 }}>
                {(uploadedPhoto || selectedUser.foto) ? (
                  <div>
                    <Image
                      src={uploadedPhoto || selectedUser.foto || '/default-avatar.png'}
                      alt={selectedUser.namaLengkap || 'Avatar'}
                      width={150}
                      height={150}
                      style={{
                        width: '150px',
                        height: '150px',
                        borderRadius: '50%',
                        objectFit: 'cover',
                        border: '3px solid #1890ff',
                        boxShadow: '0 4px 12px rgba(0,0,0,0.15)'
                      }}
                    />
                    <div style={{ marginTop: 8 }}>
                      <Text type="secondary" style={{ fontSize: 12 }}>
                        {uploadedPhoto ? 'Preview foto baru' : 'Foto saat ini'}
                      </Text>
                    </div>
                  </div>
                ) : (
                  <Avatar
                    size={150}
                    icon={<UserOutlined />}
                    style={{ backgroundColor: '#1890ff' }}
                  />
                )}
              </div>

              <Upload
                name="photo"
                listType="picture"
                maxCount={1}
                accept="image/*"
                action="/api/upload/photo" // You need to implement this endpoint
                onChange={handlePhotoUpload}
                showUploadList={false}
              >
                <Button icon={<UploadOutlined />} block>
                  Upload Foto Baru
                </Button>
              </Upload>

              {uploadedPhoto && (
                <div style={{ marginTop: 16, textAlign: 'center' }}>
                  <Text type="success">Foto baru berhasil diupload</Text>
                </div>
              )}
            </div>
          )}
        </Modal>


      </div>
    </LayoutApp>
  );
}

 
"use client";

import { useEffect, useState } from "react";
import { Row, Col, Card, Statistic, Button, Spin, Progress, Table, Select, DatePicker, Tag } from "antd";
import {
  BookOutlined,
  CalendarOutlined,
  TrophyOutlined,
  DownloadOutlined,
  ReloadOutlined,
  PieChartOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import PageHeader from "@/components/layout/PageHeader";
import { useSearchParams } from "next/navigation";

const { Option } = Select;

interface GlobalReportData {
  totalHafalan?: number;
  hafalanByStatus?: Array<{ status: string; _count: { status: number } }>;
  topSantri?: Array<{ namaLengkap: string; _count: { Hafalan: number } }>;
  totalAbsensi?: number;
  absensiByStatus?: Array<{ status: string; _count: { status: number } }>;
  attendanceByHalaqah?: Array<{
    namaHalaqah: string;
    attendanceRate: number;
    totalSantri: number;
  }>;
  totalPrestasi?: number;
  prestasiByCategory?: Array<{ kategori: string; _count: { kategori: number } }>;
  topAchievers?: Array<{ namaLengkap: string; _count: { Prestasi: number } }>;
  halaqahStats?: Array<{
    namaHalaqah: string;
    santriCount: number;
    attendanceRate: number;
    totalPrestasi: number;
  }>;
}

export default function LaporanGlobal() {
  const [reportData, setReportData] = useState<GlobalReportData | null>(null);
  const [loading, setLoading] = useState(false);
  const [reportType, setReportType] = useState('hafalan');
  const searchParams = useSearchParams();

  const fetchReportData = async (type: string) => {
    try {
      setLoading(true);
      const res = await fetch(`/api/analytics/global-reports?type=${type}`);
      if (!res.ok) throw new Error("Failed to fetch report data");
      const data = await res.json();
      setReportData(data);
    } catch (error) {
      console.error("Report fetch error:", error);
    } finally {
      setLoading(false);
    }
  };

  // Handle query params from URL
  useEffect(() => {
    const typeFromUrl = searchParams.get('type');
    if (typeFromUrl && ['hafalan', 'absensi', 'prestasi', 'halaqah'].includes(typeFromUrl)) {
      setReportType(typeFromUrl);
    }
  }, [searchParams]);

  useEffect(() => {
    fetchReportData(reportType);
  }, [reportType]);

  const renderHafalanReport = () => (
    <div>
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Total Hafalan"
              value={reportData?.totalHafalan || 0}
              prefix={<BookOutlined />}
              valueStyle={{ color: '#1890ff' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Ziyadah"
              value={reportData?.hafalanByStatus?.find(s => s.status === 'ziyadah')?._count.status || 0}
              prefix={<BookOutlined />}
              valueStyle={{ color: '#52c41a' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Murojaah"
              value={reportData?.hafalanByStatus?.find(s => s.status === 'murojaah')?._count.status || 0}
              prefix={<BookOutlined />}
              valueStyle={{ color: '#fa8c16' }}
            />
          </Card>
        </Col>
      </Row>

      <Row gutter={[16, 16]}>
        <Col xs={24} md={12}>
          <Card title="Top 10 Santri Hafalan" variant="borderless">
            <Table
              dataSource={reportData?.topSantri?.slice(0, 10) || []}
              rowKey="id"
              columns={[
                {
                  title: 'Nama Santri',
                  dataIndex: 'namaLengkap',
                  key: 'namaLengkap',
                },
                {
                  title: 'Total Hafalan',
                  dataIndex: ['_count', 'Hafalan'],
                  key: 'totalHafalan',
                },
              ]}
              pagination={false}
              size="small"
            />
          </Card>
        </Col>
        <Col xs={24} md={12}>
          <Card title="Distribusi Hafalan" variant="borderless">
            {reportData?.hafalanByStatus?.map((item) => (
              <div key={item.status} style={{ marginBottom: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                  <span style={{ textTransform: 'capitalize' }}>{item.status}</span>
                  <span>{item._count.status}</span>
                </div>
                <Progress
                  percent={reportData.totalHafalan ? (item._count.status / reportData.totalHafalan) * 100 : 0}
                  size="small"
                  strokeColor={item.status === 'ziyadah' ? '#52c41a' : '#fa8c16'}
                />
              </div>
            ))}
          </Card>
        </Col>
      </Row>
    </div>
  );

  const renderAbsensiReport = () => (
    <div>
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Total Absensi"
              value={reportData?.totalAbsensi || 0}
              prefix={<CalendarOutlined />}
              valueStyle={{ color: '#1890ff' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Masuk"
              value={reportData?.absensiByStatus?.find(s => s.status === 'masuk')?._count.status || 0}
              prefix={<CalendarOutlined />}
              valueStyle={{ color: '#52c41a' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Izin"
              value={reportData?.absensiByStatus?.find(s => s.status === 'izin')?._count.status || 0}
              prefix={<CalendarOutlined />}
              valueStyle={{ color: '#fa8c16' }}
            />
          </Card>
        </Col>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Alpha"
              value={reportData?.absensiByStatus?.find(s => s.status === 'alpha')?._count.status || 0}
              prefix={<CalendarOutlined />}
              valueStyle={{ color: '#ff4d4f' }}
            />
          </Card>
        </Col>
      </Row>

      <Row gutter={[16, 16]}>
        <Col xs={24}>
          <Card title="Tingkat Kehadiran Per Halaqah" variant="borderless">
            <Table
              dataSource={reportData?.attendanceByHalaqah || []}
              columns={[
                {
                  title: 'Nama Halaqah',
                  dataIndex: 'namaHalaqah',
                  key: 'namaHalaqah',
                },
                {
                  title: 'Jumlah Santri',
                  dataIndex: 'totalSantri',
                  key: 'totalSantri',
                },
                {
                  title: 'Tingkat Kehadiran',
                  dataIndex: 'attendanceRate',
                  key: 'attendanceRate',
                  render: (rate: number) => (
                    <div>
                      <Progress percent={rate} size="small" />
                      <span>{rate.toFixed(1)}%</span>
                    </div>
                  ),
                },
              ]}
              pagination={false}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );

  const renderPrestasiReport = () => (
    <div>
      <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
        <Col xs={24} sm={12} md={6}>
          <Card>
            <Statistic
              title="Total Prestasi"
              value={reportData?.totalPrestasi || 0}
              prefix={<TrophyOutlined />}
              valueStyle={{ color: '#1890ff' }}
            />
          </Card>
        </Col>
      </Row>

      <Row gutter={[16, 16]}>
        <Col xs={24} md={12}>
          <Card title="Top 10 Pencapaian Santri" variant="borderless">
            <Table
              dataSource={reportData?.topAchievers?.slice(0, 10) || []}
              columns={[
                {
                  title: 'Nama Santri',
                  dataIndex: 'namaLengkap',
                  key: 'namaLengkap',
                },
                {
                  title: 'Total Prestasi',
                  dataIndex: ['_count', 'Prestasi'],
                  key: 'totalPrestasi',
                },
              ]}
              pagination={false}
              size="small"
            />
          </Card>
        </Col>
        <Col xs={24} md={12}>
          <Card title="Distribusi Prestasi" variant="borderless">
            {reportData?.prestasiByCategory?.map((item) => (
              <div key={item.kategori || 'Uncategorized'} style={{ marginBottom: 16 }}>
                <div style={{ display: 'flex', justifyContent: 'space-between', marginBottom: 4 }}>
                  <span>{item.kategori || 'Uncategorized'}</span>
                  <span>{item._count.kategori}</span>
                </div>
                <Progress
                  percent={reportData.totalPrestasi ? (item._count.kategori / reportData.totalPrestasi) * 100 : 0}
                  size="small"
                  strokeColor="#fa8c16"
                />
              </div>
            ))}
          </Card>
        </Col>
      </Row>
    </div>
  );

  const renderHalaqahReport = () => (
    <div>
      <Row gutter={[16, 16]}>
        <Col xs={24}>
          <Card title="Performa Halaqah" variant="borderless">
            <Table
              dataSource={reportData?.halaqahStats || []}
              columns={[
                {
                  title: 'Nama Halaqah',
                  dataIndex: 'namaHalaqah',
                  key: 'namaHalaqah',
                },
                {
                  title: 'Jumlah Santri',
                  dataIndex: 'santriCount',
                  key: 'santriCount',
                },
                {
                  title: 'Kehadiran',
                  dataIndex: 'attendanceRate',
                  key: 'attendanceRate',
                  render: (rate: number) => `${rate.toFixed(1)}%`,
                },
                {
                  title: 'Total Prestasi',
                  dataIndex: 'totalPrestasi',
                  key: 'totalPrestasi',
                },
              ]}
              pagination={false}
            />
          </Card>
        </Col>
      </Row>
    </div>
  );

  return (
    <LayoutApp>
      <div style={{ display: "flex", flexDirection: "column", gap: 32 }}>
        {/* Header */}
        <PageHeader
          title="Laporan Global"
          subtitle="Comprehensive reports across all halaqah activities"
          breadcrumbs={[
            { title: "Yayasan Dashboard", href: "/yayasan/dashboard" },
            { title: "Laporan Global" }
          ]}
          extra={
            <Tag icon={<PieChartOutlined />} color="purple" style={{ padding: '8px 16px', fontSize: 14 }}>
              Yayasan Panel
            </Tag>
          }
        />

        {/* Report Type Selector */}
        <Card style={{ marginBottom: 24 }}>
          <div style={{ display: 'flex', justifyContent: 'space-between', alignItems: 'center', flexWrap: 'wrap', gap: 16 }}>
            <div>
              <h3 style={{ margin: 0 }}>Pilih Jenis Laporan</h3>
            </div>
            <div style={{ display: 'flex', gap: 16, alignItems: 'center' }}>
              <Select
                value={reportType}
                onChange={setReportType}
                style={{ width: 200 }}
              >
                <Option value="hafalan">­ƒôû Hafalan Santri</Option>
                <Option value="absensi">­ƒôà Absensi</Option>
                <Option value="prestasi">­ƒÅå Prestasi</Option>
                <Option value="halaqah">­ƒæÑ Per Halaqah</Option>
              </Select>
              <Button
                icon={<ReloadOutlined />}
                onClick={() => fetchReportData(reportType)}
                loading={loading}
              >
                Refresh
              </Button>
              <Button icon={<DownloadOutlined />} type="primary">
                Export
              </Button>
            </div>
          </div>
        </Card>

        {/* Report Content */}
        {loading ? (
          <div style={{ textAlign: 'center', padding: '80px 20px' }}>
            <Spin size="large" />
            <p style={{ marginTop: 16, color: '#6b7280' }}>Loading report data...</p>
          </div>
        ) : (
          <>
            {reportType === 'hafalan' && renderHafalanReport()}
            {reportType === 'absensi' && renderAbsensiReport()}
            {reportType === 'prestasi' && renderPrestasiReport()}
            {reportType === 'halaqah' && renderHalaqahReport()}
          </>
        )}

        {/* Footer */}
        <Card style={{ marginTop: 32 }}>
          <div style={{ display: "flex", justifyContent: "space-between", alignItems: "center", flexWrap: "wrap", gap: 16 }}>
            <div>
              <h4 style={{ margin: 0, color: "#1e293b", fontWeight: 600 }}>Sistem AR-Hafalan v2.0</h4>
              <p style={{ margin: 0, color: "#64748b", fontSize: 14 }}>Laporan Global - Comprehensive Reports</p>
            </div>
            <div style={{ textAlign: "right" }}>
              <p style={{ margin: 0, color: "#64748b", fontSize: 14 }}>Auto-refresh: 30s ÔÇó Last updated</p>
              <p style={{ margin: 0, color: "#1e293b", fontWeight: 500, fontSize: 14 }}>{new Date().toLocaleTimeString()}</p>
            </div>
          </div>
        </Card>
      </div>
    </LayoutApp>
  );
}

"use client";

import { useEffect, useState, useCallback } from "react";
import { 
  Card, 
  Typography, 
  Row, 
  Col, 
  Button,
  Space,
  Avatar,
  Dropdown,
  Modal,
  Statistic,
  Empty,
  Spin
} from "antd";
import {
  BellOutlined,
  CheckOutlined,
  DeleteOutlined,
  MoreOutlined,
  BookOutlined,
  CalendarOutlined,
  TrophyOutlined,
  InfoCircleOutlined,
  ClockCircleOutlined,
  SettingOutlined,
  ClearOutlined
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import dayjs from "dayjs";
import relativeTime from "dayjs/plugin/relativeTime";
import 'dayjs/locale/id';

dayjs.extend(relativeTime);
dayjs.locale('id');

const { Title } = Typography;

interface Notifikasi {
  id: number;
  judul: string;
  pesan: string;
  tipe: 'hafalan' | 'target' | 'pengumuman' | 'jadwal' | 'prestasi' | 'sistem';
  prioritas: 'tinggi' | 'sedang' | 'rendah';
  status: 'unread' | 'read';
  tanggal: string;
  pengirim: string;
  aksi?: {
    label: string;
    url: string;
  };
  metadata?: {
    targetId?: number;
    hafalanId?: number;
    pengumumanId?: number;
  };
  fullContent?: string;
  targetAudience?: string;
  tanggalKadaluarsa?: string;
}

export default function NotifikasiPage() {
  const [notifikasiList, setNotifikasiList] = useState<Notifikasi[]>([]);
  const [filteredData, setFilteredData] = useState<Notifikasi[]>([]);
  const [loading, setLoading] = useState(false);
  const [filterStatus, setFilterStatus] = useState<string>('all');
  const [filterTipe] = useState<string>('all');
  const [selectedNotifikasi, setSelectedNotifikasi] = useState<Notifikasi | null>(null);
  const [isDetailModalOpen, setIsDetailModalOpen] = useState(false);

  // Fetch unified notifications from API
  const fetchNotifikasi = useCallback(async () => {
    try {
      setLoading(true);
      
      const notifRes = await fetch('/api/notifikasi');
      const notifData = notifRes.ok ? await notifRes.json() : { data: [] };
      
      const transformedNotifications = (notifData.data || []).map((item: any) => ({
        id: item.id,
        judul: item.metadata?.judul || getNotifikasiTitle(item.type),
        pesan: item.metadata?.isi || item.pesan,
        tipe: mapNotifikasiType(item.type),
        prioritas: getPriorityFromType(item.type),
        status: item.isRead ? 'read' : 'unread',
        tanggal: item.tanggal,
        pengirim: item.metadata?.creator || 'Sistem',
        fullContent: item.metadata?.fullContent || item.pesan,
        targetAudience: item.metadata?.targetAudience,
        tanggalKadaluarsa: item.metadata?.tanggalKadaluarsa,
        aksi: getNotifikasiAction(item.type),
        metadata: {
          targetId: item.type === 'target' ? item.refId : undefined,
          hafalanId: item.type === 'hafalan' ? item.refId : undefined,
          pengumumanId: item.type === 'pengumuman' ? item.refId : undefined,
        }
      }));
      
      setNotifikasiList(transformedNotifications);
      setFilteredData(transformedNotifications);
    } catch (error) {
      console.error('Error fetching notifications:', error);
      setNotifikasiList([]);
      setFilteredData([]);
    } finally {
      setLoading(false);
    }
  }, []);

  useEffect(() => {
    fetchNotifikasi();
  }, [fetchNotifikasi]);

  // Helper functions
  const getNotifikasiTitle = (type: string) => {
    switch (type) {
      case 'pengumuman': return 'Pengumuman Baru';
      case 'hafalan': return 'Update Hafalan';
      case 'target': return 'Target Hafalan';
      case 'absensi': return 'Update Absensi';
      default: return 'Notifikasi';
    }
  };

  const mapNotifikasiType = (apiType: string) => {
    const typeMap: { [key: string]: string } = {
      'pengumuman': 'pengumuman',
      'hafalan': 'hafalan',
      'target': 'target',
      'absensi': 'jadwal',
      'rapot': 'prestasi',
      'user': 'sistem'
    };
    return typeMap[apiType] || 'sistem';
  };

  const getPriorityFromType = (type: string) => {
    switch (type) {
      case 'pengumuman': return 'tinggi';
      case 'target': return 'tinggi';
      case 'hafalan': return 'sedang';
      default: return 'rendah';
    }
  };

  const getNotifikasiAction = (type: string) => {
    switch (type) {
      case 'pengumuman':
        return { label: 'Baca Detail', url: '#' };
      case 'hafalan':
        return { label: 'Lihat Laporan', url: '/yayasan/laporan' };
      case 'target':
        return { label: 'Lihat Laporan', url: '/yayasan/laporan' };
      case 'absensi':
        return { label: 'Lihat Laporan', url: '/yayasan/laporan' };
      default:
        return undefined;
    }
  };

  const handleNotificationClick = async (notifikasi: Notifikasi) => {
    if (notifikasi.status === 'unread') {
      handleMarkAsRead(notifikasi.id);
    }

    if (notifikasi.tipe === 'pengumuman') {
      setSelectedNotifikasi(notifikasi);
      setIsDetailModalOpen(true);
    } else if (notifikasi.aksi && notifikasi.aksi.url !== '#') {
      window.location.href = notifikasi.aksi.url;
    }
  };

  useEffect(() => {
    let filtered = notifikasiList;
    if (filterStatus !== 'all') {
      filtered = filtered.filter(item => item.status === filterStatus);
    }
    if (filterTipe !== 'all') {
      filtered = filtered.filter(item => item.tipe === filterTipe);
    }
    setFilteredData(filtered);
  }, [filterStatus, filterTipe, notifikasiList]);

  const getTipeIcon = (tipe: string) => {
    switch (tipe) {
      case 'hafalan': return <BookOutlined />;
      case 'target': return <CalendarOutlined />;
      case 'pengumuman': return <BellOutlined />;
      case 'jadwal': return <ClockCircleOutlined />;
      case 'prestasi': return <TrophyOutlined />;
      case 'sistem': return <SettingOutlined />;
      default: return <InfoCircleOutlined />;
    }
  };

  const getTipeColor = (tipe: string) => {
    switch (tipe) {
      case 'hafalan': return '#1890ff';
      case 'target': return '#52c41a';
      case 'pengumuman': return '#fa8c16';
      case 'jadwal': return '#722ed1';
      case 'prestasi': return '#faad14';
      case 'sistem': return '#13c2c2';
      default: return '#666';
    }
  };

  const handleMarkAsRead = async (id: number | string) => {
    try {
      const res = await fetch(`/api/notifikasi/${id}`, {
        method: 'PATCH',
        headers: { 'Content-Type': 'application/json' },
        body: JSON.stringify({ action: 'mark_read' })
      });

      if (res.ok) {
        setNotifikasiList(prev => 
          prev.map(notif => 
            notif.id === id ? { ...notif, status: 'read' } : notif
          )
        );
      }
    } catch (error) {
      console.error('Error marking notification as read:', error);
      setNotifikasiList(prev => 
        prev.map(notif => 
          notif.id === id ? { ...notif, status: 'read' } : notif
        )
      );
    }
  };

  const handleMarkAllAsRead = () => {
    setNotifikasiList(prev => 
      prev.map(notif => ({ ...notif, status: 'read' }))
    );
  };

  const handleDelete = (id: number) => {
    Modal.confirm({
      title: 'Hapus Notifikasi',
      content: 'Apakah Anda yakin ingin menghapus notifikasi ini?',
      okText: 'Ya, Hapus',
      cancelText: 'Batal',
      okType: 'danger',
      onOk: () => {
        setNotifikasiList(prev => prev.filter(notif => notif.id !== id));
      }
    });
  };

  const handleClearAll = () => {
    Modal.confirm({
      title: 'Hapus Semua Notifikasi',
      content: 'Apakah Anda yakin ingin menghapus semua notifikasi?',
      okText: 'Ya, Hapus Semua',
      cancelText: 'Batal',
      okType: 'danger',
      onOk: () => {
        setNotifikasiList([]);
      }
    });
  };

  const unreadCount = notifikasiList.filter(n => n.status === 'unread').length;
  const todayCount = notifikasiList.filter(n => 
    dayjs(n.tanggal).format('YYYY-MM-DD') === dayjs().format('YYYY-MM-DD')
  ).length;
  const thisWeekCount = notifikasiList.filter(n => 
    dayjs(n.tanggal).isAfter(dayjs().startOf('week'))
  ).length;

  return (
    <LayoutApp>
      <div style={{ padding: "24px 0" }}>
        {/* Header */}
        <Row justify="space-between" align="middle" style={{ marginBottom: 24 }}>
          <Col>
            <Title level={2} style={{
              background: 'linear-gradient(135deg, #FA8C16 0%, #D46B08 100%)',
              WebkitBackgroundClip: 'text',
              WebkitTextFillColor: 'transparent',
              backgroundClip: 'text',
              margin: 0,
              fontSize: '28px',
              fontWeight: '700'
            }}>
              <BellOutlined style={{ marginRight: 12, color: '#FA8C16' }} />
              Notifikasi & Pengumuman
            </Title>
            <div style={{
              fontSize: '14px',
              color: '#666',
              marginTop: '4px',
              fontWeight: '500'
            }}>
              Update laporan, pengumuman, dan informasi terbaru dari sekolah
            </div>
          </Col>
          <Col>
            <Space>
              <Button
                icon={<CheckOutlined />}
                onClick={handleMarkAllAsRead}
                disabled={unreadCount === 0}
              >
                Tandai Semua Dibaca
              </Button>
              <Button
                icon={<ClearOutlined />}
                onClick={handleClearAll}
                disabled={notifikasiList.length === 0}
                danger
              >
                Hapus Semua
              </Button>
            </Space>
          </Col>
        </Row>

        {/* Statistics Cards */}
        <Row gutter={[16, 16]} style={{ marginBottom: 24 }}>
          <Col xs={24} sm={8}>
            <Card
              style={{
                borderRadius: '16px',
                background: 'linear-gradient(135deg, #FA8C16 0%, #D46B08 100%)',
                border: 'none',
                boxShadow: '0 8px 32px rgba(250, 140, 22, 0.2)'
              }}
              styles={{ body: { padding: '20px' } }}
            >
              <Statistic
                title={<span style={{ color: 'rgba(255,255,255,0.9)' }}>Belum Dibaca</span>}
                value={unreadCount}
                valueStyle={{ color: 'white', fontSize: '28px', fontWeight: 'bold' }}
                prefix={<BellOutlined style={{ color: 'white' }} />}
              />
            </Card>
          </Col>
          <Col xs={24} sm={8}>
            <Card
              style={{
                borderRadius: '16px',
                background: 'linear-gradient(135deg, #00B894 0%, #00CEC9 100%)',
                border: 'none',
                boxShadow: '0 8px 32px rgba(0, 184, 148, 0.2)'
              }}
              styles={{ body: { padding: '20px' } }}
            >
              <Statistic
                title={<span style={{ color: 'rgba(255,255,255,0.9)' }}>Hari Ini</span>}
                value={todayCount}
                valueStyle={{ color: 'white', fontSize: '28px', fontWeight: 'bold' }}
                prefix={<CalendarOutlined style={{ color: 'white' }} />}
              />
            </Card>
          </Col>
          <Col xs={24} sm={8}>
            <Card
              style={{
                borderRadius: '16px',
                background: 'linear-gradient(135deg, #13C2C2 0%, #08979C 100%)',
                border: 'none',
                boxShadow: '0 8px 32px rgba(19, 194, 194, 0.2)'
              }}
              styles={{ body: { padding: '20px' } }}
            >
              <Statistic
                title={<span style={{ color: 'rgba(255,255,255,0.9)' }}>Minggu Ini</span>}
                value={thisWeekCount}
                valueStyle={{ color: 'white', fontSize: '28px', fontWeight: 'bold' }}
                prefix={<ClockCircleOutlined style={{ color: 'white' }} />}
              />
            </Card>
          </Col>
        </Row>

        {/* Filter Section */}
        <Card 
          style={{ 
            marginBottom: 16, 
            borderRadius: '16px',
            background: 'linear-gradient(135deg, #fff7e6 0%, #ffecc7 100%)',
            border: '1px solid #ffd591'
          }}
        >
          <Row gutter={[16, 16]} align="middle" justify="center">
            {/* Filter Status */}
            <Col xs={24} style={{ textAlign: 'center' }}>
              <Space size="small" wrap>
                <span style={{ fontWeight: 'bold', color: '#FA8C16', fontSize: '14px' }}>­ƒôï Status:</span>
                <Button
                  type={filterStatus === 'all' ? 'primary' : 'default'}
                  size="small"
                  onClick={() => setFilterStatus('all')}
                  style={{ borderRadius: '20px' }}
                >
                  Semua ({notifikasiList.length})
                </Button>
                <Button
                  type={filterStatus === 'unread' ? 'primary' : 'default'}
                  size="small"
                  onClick={() => setFilterStatus('unread')}
                  style={{ borderRadius: '20px' }}
                >
                  Belum Dibaca ({unreadCount})
                </Button>
                <Button
                  type={filterStatus === 'read' ? 'primary' : 'default'}
                  size="small"
                  onClick={() => setFilterStatus('read')}
                  style={{ borderRadius: '20px' }}
                >
                  Sudah Dibaca ({notifikasiList.length - unreadCount})
                </Button>
              </Space>
            </Col>
            

          </Row>
        </Card>

        {/* Notifications List */}
        <Card
          title={
            <div style={{ display: 'flex', alignItems: 'center', gap: '12px' }}>
              <div style={{
                width: '12px',
                height: '12px',
                borderRadius: '50%',
                background: 'linear-gradient(135deg, #FA8C16, #D46B08)',
                boxShadow: '0 0 15px rgba(250, 140, 22, 0.4)'
              }} />
              <span style={{
                background: 'linear-gradient(135deg, #FA8C16 0%, #D46B08 100%)',
                WebkitBackgroundClip: 'text',
                WebkitTextFillColor: 'transparent',
                backgroundClip: 'text',
                fontSize: '20px',
                fontWeight: '800'
              }}>
                ­ƒôï Daftar Notifikasi & Pengumuman
              </span>
            </div>
          }
          style={{
            borderRadius: '20px',
            boxShadow: '0 12px 40px rgba(0, 0, 0, 0.1)',
            border: '1px solid rgba(250, 140, 22, 0.1)',
            background: 'linear-gradient(145deg, #ffffff 0%, #fff7e6 100%)'
          }}
        >
          <Spin spinning={loading}>
            {filteredData.length > 0 ? (
              <div style={{ padding: '20px' }}>
                {filteredData.map((item) => (
                  <div
                    key={item.id}
                    style={{
                      padding: '20px',
                      marginBottom: '16px',
                      borderRadius: '16px',
                      background: item.status === 'unread' 
                        ? 'linear-gradient(135deg, #fff7e6 0%, #ffecc7 100%)'
                        : 'linear-gradient(135deg, #fafafa 0%, #f5f5f5 100%)',
                      border: item.status === 'unread' 
                        ? '2px solid #ffd591' 
                        : '1px solid #f0f0f0',
                      cursor: 'pointer',
                      transition: 'all 0.3s ease'
                    }}
                    onClick={() => handleNotificationClick(item)}
                  >
                    <div style={{ display: 'flex', alignItems: 'flex-start', gap: '16px' }}>
                      <Avatar
                        style={{
                          backgroundColor: getTipeColor(item.tipe),
                          color: 'white'
                        }}
                        icon={getTipeIcon(item.tipe)}
                        size={56}
                      />
                      <div style={{ flex: 1 }}>
                        <div style={{ 
                          fontSize: '18px',
                          fontWeight: item.status === 'unread' ? 'bold' : '600',
                          color: item.status === 'unread' ? '#FA8C16' : '#333',
                          marginBottom: '8px'
                        }}>
                          {item.judul}
                        </div>
                        <div style={{ 
                          fontSize: '15px',
                          color: '#666',
                          marginBottom: '12px'
                        }}>
                          {item.pesan}
                        </div>
                        <div style={{ 
                          display: 'flex', 
                          justifyContent: 'space-between', 
                          alignItems: 'center'
                        }}>
                          <span style={{ fontSize: '13px', color: '#999' }}>
                            {dayjs(item.tanggal).fromNow()}
                          </span>
                          <Dropdown 
                            menu={{
                              items: [
                                ...(item.status === 'unread' ? [{
                                  key: 'read',
                                  icon: <CheckOutlined />,
                                  label: 'Tandai Dibaca',
                                  onClick: () => handleMarkAsRead(item.id)
                                }] : []),
                                {
                                  key: 'delete',
                                  icon: <DeleteOutlined />,
                                  label: 'Hapus',
                                  onClick: () => handleDelete(item.id),
                                  danger: true
                                }
                              ]
                            }}
                            trigger={['click']}
                          >
                            <Button 
                              type="text" 
                              icon={<MoreOutlined />} 
                              size="small"
                            />
                          </Dropdown>
                        </div>
                      </div>
                    </div>
                  </div>
                ))}
              </div>
            ) : (
              <Empty description="Belum ada notifikasi" />
            )}
          </Spin>
        </Card>

        {/* Detail Modal */}
        <Modal
          title="Detail Pengumuman"
          open={isDetailModalOpen}
          onCancel={() => setIsDetailModalOpen(false)}
          footer={null}
          width={800}
        >
          {selectedNotifikasi && (
            <div>
              <h3>{selectedNotifikasi.judul}</h3>
              <p>{selectedNotifikasi.fullContent || selectedNotifikasi.pesan}</p>
              <div style={{ marginTop: 16, fontSize: '12px', color: '#666' }}>
                Dari: {selectedNotifikasi.pengirim} ÔÇó {dayjs(selectedNotifikasi.tanggal).format("DD MMMM YYYY, HH:mm")}
              </div>
            </div>
          )}
        </Modal>
      </div>
    </LayoutApp>
  );
}

/* eslint-disable @typescript-eslint/no-explicit-any */
"use client";

import { useEffect, useState, useCallback } from "react";
import { Row, Col, Card, Input, Select, Button, Table, Avatar, Tag, Progress, Spin, Statistic, Tabs, Descriptions, Badge, Modal } from "antd";
import {
  UserOutlined,
  SearchOutlined,
  BookOutlined,
  CalendarOutlined,
  TrophyOutlined,
  TeamOutlined,
  CheckCircleOutlined,
  ClockCircleOutlined,
  CloseCircleOutlined,
  ExclamationCircleOutlined,
  StarOutlined,
  FileDoneOutlined,
} from "@ant-design/icons";
import LayoutApp from "@/components/layout/LayoutApp";
import PageHeader from "@/components/layout/PageHeader";
import { useRouter } from "next/navigation";

const { Option } = Select;
const { Search } = Input;

interface SantriData {
  id: number;
  namaLengkap: string;
  namaPanggilan?: string;
  username: string;
  role: string;
  foto?: string;
  halaqah: Array<{
    id: number;
    namaHalaqah: string;
    guru: {
      namaLengkap: string;
      username: string;
    };
    jadwal: Array<{
      hari: string;
      waktuMulai: string;
      waktuSelesai: string;
    }>;
  }>;
  orangTua?: Array<{
    id: number;
    namaLengkap: string;
    username: string;
    noTlp?: string;
  }>;
  statistics: {
    totalAyatHafal: number;
    hafalanByType: Array<{ status: string; _count: { status: number } }>;
    attendanceRate: number;
    attendanceStats: Array<{ status: string; _count: { status: number } }>;
    totalTargets: number;
    completedTargets: number;
    totalAchievements: number;
    rankingHafalan?: number;
    totalSantri?: number;
  };
  recentHafalan: Array<{
    id: number;
    tanggal: string;
    jenis: string;
    surah: string;
    ayat: string;
    guru: string;
    status: string;
    catatan?: string;
  }>;
  allHafalan: Array<{
    id: number;
    tanggal: string;
    jenis: string;
    surah: string;
    ayatMulai: number;
    ayatSelesai: number;
    status: string;
    catatan?: string;
    guru: {
      namaLengkap: string;
    };
  }>;
  targets: Array<{
    id: number;
    surah: string;
    ayatMulai: number;
    ayatSelesai: number;
    targetSelesai: string;
    status: string;
    progress: number;
  }>;
  absensi: Array<{
    id: number;
    tanggal: string;
    status: string;
    keterangan?: string;
    halaqah: {
      namaHalaqah: string;
    };
  }>;
  ujian: Array<{
    id: number;
    tanggal: string;
    jenis: string;
    surah: string;
    ayatMulai: number;
    ayatSelesai: number;
    nilai: number;
    catatan?: string;
    penguji: {
      namaLengkap: string;
    };
  }>;
  rapot: Array<{
    id: number;
    periode: string;
    semester: string;
    tahunAjaran: string;
    totalHafalan: number;
    nilaiRataRata: number;
    kehadiran: number;
    catatan?: string;
  }>;
  achievements: any[];
  monthlyProgress: any[];
}

export default function DetailSantri() {
  const [santriList, setSantriList] = useState<any[]>([]);
  const [filteredSantri, setFilteredSantri] = useState<any[]>([]);
  const [selectedSantri, setSelectedSantri] = useState<SantriData | null>(null);
  const [loading, setLoading] = useState(false);
  const [detailLoading, setDetailLoading] = useState(false);
  const [searchText, setSearchText] = useState('');
  const [halaqahFilter, setHalaqahFilter] = useState('');
  const [modalVisible, setModalVisible] = useState(false);
  const router = useRouter();

  // Fetch all santri list
  const fetchSantriList = useCallback(async () => {
    try {
      setLoading(true);
      const res = await fetch('/api/users?role=santri');
      if (!res.ok) throw new Error('Failed to fetch santri list');
      const data = await res.json();
      setSantriList(data);
      setFilteredSantri(data);
    } catch (error) {
      console.error('Error fetching santri list:', error);
    } finally {
      setLoading(false);
    }
  }, []);

  // Fetch detailed santri data
  const fetchSantriDetail = useCallback(async (santriId: number) => {
    try {
      setDetailLoading(true);
      setModalVisible(true);
      const res = await fetch(`/api/analytics/santri-detail?santriId=${santriId}`);
      
      if (!res.ok) {
        const errorData = await res.json().catch(() => ({ error: 'Unknown error' }));
        console.error('ÔØî API Error:', errorData);
        alert(`Error: ${errorData.error || 'Failed to fetch santri details'}\nDetails: ${errorData.details || 'No details'}`);
        throw new Error(errorData.error || 'Failed to fetch santri details');
      }
      
      const data = await res.json();
      setSelectedSantri(data);
    } catch (error: any) {
      console.error('ÔØî Error fetching santri details:', error);
      setModalVisible(false);
    } finally {
      setDetailLoading(false);
    }
  }, []);

  const handleCloseModal = () => {
    setModalVisible(false);
    setSelectedSantri(null);
  };

  useEffect(() => {
    fetchSantriList();
  }, [fetchSantriList]);

  // Filter santri based on search and halaqah
  useEffect(() => {
    let filtered = santriList;

    if (searchText) {
      filtered = filtered.filter(santri =>
        santri.namaLengkap.toLowerCase().includes(searchText.toLowerCase()) ||
        santri.username.toLowerCase().includes(searchText.toLowerCase())
      );
    }

    if (halaqahFilter) {
      filtered = filtered.filter(santri =>
        santri.halaqah?.some((h: any) => h.namaHalaqah === halaqahFilter)
      );
    }

    setFilteredSantri(filtered);
  }, [searchText, halaqahFilter, santriList]);

  const santriColumns = [
    {
      title: 'Foto',
      dataIndex: 'foto',
      key: 'foto',
      render: (foto: string) => (
        <Avatar src={foto || undefined} icon={<UserOutlined />} />
      ),
    },
    {
      title: 'Nama Santri',
      dataIndex: 'namaLengkap',
      key: 'namaLengkap',
      sorter: (a: any, b: any) => a.namaLengkap.localeCompare(b.namaLengkap),
    },
    {
      title: 'Username',
      dataIndex: 'username',
      key: 'username',
    },
    {
      title: 'Halaqah',
      dataIndex: 'halaqah',
      key: 'halaqah',
      render: (halaqah: any[]) => (
        <div>
          {halaqah?.map((h, index) => (
            <Tag key={index} color="blue">{h.namaHalaqah}</Tag>
          )) || 'Belum ditentukan'}
        </div>
      ),
    },
    {
      title: 'Aksi',
      key: 'action',
      render: (record: any) => (
        <Button
          type="primary"
          size="small"
          onClick={() => fetchSantriDetail(record.id)}
        >
          Lihat Detail
        </Button>
      ),
    },
  ];

  const renderSantriDetail = () => {
    if (!selectedSantri) return null;

    const getStatusColor = (status: string) => {
      const statusColors: Record<string, string> = {
        'ziyadah': 'green',
        'muraja\'ah': 'blue',
        'masuk': 'green',
        'izin': 'orange',
        'sakit': 'orange',
        'alpha': 'red',
        'selesai': 'green',
        'berlangsung': 'blue',
        'tertunda': 'orange',
      };
      return statusColors[status.toLowerCase()] || 'default';
    };

    const getStatusIcon = (status: string) => {
      const statusIcons: Record<string, any> = {
        'masuk': <CheckCircleOutlined />,
        'izin': <ClockCircleOutlined />,
        'sakit': <ExclamationCircleOutlined />,
        'alpha': <CloseCircleOutlined />,
        'selesai': <CheckCircleOutlined />,
        'berlangsung': <ClockCircleOutlined />,
      };
      return statusIcons[status.toLowerCase()] || null;
    };

    const tabItems = [
      {
        key: '1',
        label: (
          <span>
            <TeamOutlined /> Halaqah
          </span>
        ),
        children: (
          <Card>
            {selectedSantri.halaqah && selectedSantri.halaqah.length > 0 ? (
              selectedSantri.halaqah.map((h) => (
                <Card key={h.id} size="small" style={{ marginBottom: 16 }}>
                  <Descriptions title={h.namaHalaqah} bordered column={2}>
                    <Descriptions.Item label="Guru">
                      {h.guru.namaLengkap} (@{h.guru.username})
                    </Descriptions.Item>
                    <Descriptions.Item label="Jadwal">
                      {h.jadwal && h.jadwal.length > 0 ? (
                        <div>
                          {h.jadwal.map((j, idx) => (
                            <Tag key={idx} color="blue">
                              {j.hari}: {j.waktuMulai} - {j.waktuSelesai}
                            </Tag>
                          ))}
                        </div>
                      ) : (
                        'Belum ada jadwal'
                      )}
                    </Descriptions.Item>
                  </Descriptions>
                </Card>
              ))
            ) : (
              <div style={{ textAlign: 'center', padding: 40, color: '#999' }}>
                Belum terdaftar di halaqah manapun
              </div>
            )}
          </Card>
        ),
      },
      {
        key: '2',
        label: (
          <span>
            <BookOutlined /> Hafalan ({selectedSantri.allHafalan?.length || 0})
          </span>
        ),
        children: (
          <Table
            dataSource={selectedSantri.allHafalan || []}
            rowKey="id"
            pagination={{ 
              pageSize: 10,
              showSizeChanger: true,
              showQuickJumper: true,
              showTotal: (total, range) => `${range[0]}-${range[1]} dari ${total} data`
            }}
            columns={[
              {
                title: 'Tanggal',
                dataIndex: 'tanggal',
                key: 'tanggal',
                render: (date: string) => new Date(date).toLocaleDateString('id-ID'),
                sorter: (a, b) => new Date(a.tanggal).getTime() - new Date(b.tanggal).getTime(),
              },
              {
                title: 'Jenis',
                dataIndex: 'jenis',
                key: 'jenis',
                render: (jenis: string) => (
                  <Tag color={jenis === 'ziyadah' ? 'green' : 'blue'}>
                    {jenis.toUpperCase()}
                  </Tag>
                ),
                filters: [
                  { text: 'Ziyadah', value: 'ziyadah' },
                  { text: 'Muraja\'ah', value: 'muraja\'ah' },
                ],
                onFilter: (value, record) => record.jenis === value,
              },
              {
                title: 'Surah',
                dataIndex: 'surah',
                key: 'surah',
              },
              {
                title: 'Ayat',
                key: 'ayat',
                render: (record: any) => `${record.ayatMulai} - ${record.ayatSelesai}`,
              },
              {
                title: 'Status',
                dataIndex: 'status',
                key: 'status',
