import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';
import { ApiResponse, withAuth } from '@/lib/api-helpers';

export async function GET(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    // Ensure user is admin or super-admin
    if (!['admin', 'super_admin'].includes(user.role.name)) {
      return ApiResponse.forbidden('Access denied');
    }

    const { searchParams } = new URL(request.url);
    const halaqahId = searchParams.get('halaqahId');

    if (!halaqahId) {
      return ApiResponse.error('halaqahId is required', 400);
    }

    // Get santri that are available (not assigned to any halaqah) 
    // OR assigned to the specified halaqah (for editing purposes)
    const availableSantri = await prisma.user.findMany({
      where: {
        role: {
          name: 'santri'
        },
        OR: [
          // Santri not assigned to any halaqah
          {
            HalaqahSantri: {
              none: {}
            }
          },
          // Santri assigned to the specified halaqah
          {
            HalaqahSantri: {
              some: {
                halaqahId: parseInt(halaqahId)
              }
            }
          }
        ]
      },
      select: {
        id: true,
        username: true,
        namaLengkap: true,
        role: {
          select: {
            name: true
          }
        }
      },
      orderBy: {
        namaLengkap: 'asc'
      }
    });

    return ApiResponse.success(availableSantri);

  } catch (error) {
    console.error('Error fetching available santri:', error);
    return ApiResponse.serverError('Failed to fetch available santri');
  }
}

import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';
import { ApiResponse, withAuth } from '@/lib/api-helpers';

export async function GET(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    // Ensure user is admin or super-admin
    if (!['admin', 'super_admin'].includes(user.role.name)) {
      return ApiResponse.forbidden('Access denied');
    }

    const { searchParams } = new URL(request.url);
    const role = searchParams.get('role');
    const excludeAssigned = searchParams.get('excludeAssigned') === 'true';
    const excludeHalaqahId = searchParams.get('excludeHalaqahId');

    const whereClause: any = {};

    if (role) {
      whereClause.role = {
        name: role
      };
    }

    // If excludeAssigned is true and role is santri, filter out santri already assigned to halaqah
    if (excludeAssigned && role === 'santri') {
      const assignedSantriQuery: any = {};
      
      // If excludeHalaqahId is provided, exclude santri from that specific halaqah
      if (excludeHalaqahId) {
        assignedSantriQuery.halaqahId = {
          not: parseInt(excludeHalaqahId)
        };
      }

      // Get all santri IDs that are already assigned to halaqah (excluding the specified halaqah if provided)
      const assignedSantriIds = await prisma.halaqahSantri.findMany({
        where: assignedSantriQuery,
        select: {
          santriId: true
        }
      });

      const assignedIds = assignedSantriIds.map(hs => hs.santriId);

      if (assignedIds.length > 0) {
        whereClause.id = {
          notIn: assignedIds
        };
      }
    }

    const users = await prisma.user.findMany({
      where: whereClause,
      select: {
        id: true,
        username: true,
        namaLengkap: true,
        role: {
          select: {
            name: true
          }
        }
      },
      orderBy: {
        namaLengkap: 'asc'
      }
    });

    return ApiResponse.success(users);

  } catch (error) {
    console.error('Error fetching users:', error);
    return ApiResponse.serverError('Failed to fetch users');
  }
}

import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const santriId = searchParams.get('santriId');

    console.log('­ƒôè Fetching santri detail for ID:', santriId);

    if (!santriId) {
      return NextResponse.json({ error: 'Santri ID is required' }, { status: 400 });
    }

    // Get santri basic info
    const santri = await prisma.user.findUnique({
      where: { id: Number(santriId) },
      include: { role: true,
        HalaqahSantri: {
          include: {
            halaqah: {
              include: {
                guru: {
                  select: {
                    id: true,
                    namaLengkap: true,
                    username: true
                  }
                },
                jadwal: true
              }
            }
          }
        }
      }
    });

    if (!santri) {
      console.log('ÔØî Santri not found with ID:', santriId);
      return NextResponse.json({ error: 'Santri not found' }, { status: 404 });
    }

    console.log('Ô£à Santri found:', santri.namaLengkap);

    // Get hafalan statistics
    const hafalanStats = await prisma.hafalan.groupBy({
      by: ['status'],
      where: { santriId: Number(santriId) },
      _count: { status: true },
      _sum: {
        ayatMulai: true,
        ayatSelesai: true
      }
    });

    const totalAyatHafal = hafalanStats.reduce((sum, stat) => {
      return sum + (stat._sum.ayatSelesai || 0) - (stat._sum.ayatMulai || 0) + stat._count.status;
    }, 0);

    // Get all hafalan with guru info
    const allHafalan = await prisma.hafalan.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { tanggal: 'desc' },
      include: {
        santri: {
          include: {
            HalaqahSantri: {
              include: {
                halaqah: {
                  include: {
                    guru: {
                      select: {
                        namaLengkap: true
                      }
                    }
                  }
                }
              }
            }
          }
        }
      }
    });

    // Get recent hafalan (last 10)
    const recentHafalan = allHafalan.slice(0, 10);

    // Get attendance statistics
    const attendanceStats = await prisma.absensi.groupBy({
      by: ['status'],
      where: { santriId: Number(santriId) },
      _count: { status: true }
    });

    const totalAbsensi = attendanceStats.reduce((sum, stat) => sum + stat._count.status, 0);
    const presentCount = attendanceStats.find(stat => stat.status === 'masuk')?._count.status || 0;
    const attendanceRate = totalAbsensi > 0 ? (presentCount / totalAbsensi) * 100 : 0;

    // Get target progress with calculated progress percentage
    const targets = await prisma.targetHafalan.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { deadline: 'desc' }
    });

    // Get absensi (without halaqah relation for now)
    const absensi = await prisma.absensi.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { tanggal: 'desc' }
    });

    // Get ujian from both Ujian and UjianGuru models
    const ujianRegular = await prisma.ujian.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { tanggal: 'desc' },
      include: {
        halaqah: {
          include: {
            guru: {
              select: {
                namaLengkap: true
              }
            }
          }
        }
      }
    });

    const ujianGuru = await prisma.ujianGuru.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { tanggalUjian: 'desc' },
      include: {
        guru: {
          select: {
            namaLengkap: true
          }
        }
      }
    });

    // Get rapot
    const rapot = await prisma.raportSantri.findMany({
      where: { santriId: Number(santriId) },
      orderBy: { createdAt: 'desc' }
    });

    // Calculate ranking hafalan
    const allSantriHafalan = await prisma.user.findMany({
      where: {
        role: {
          name: 'santri'
        }
      },
      include: {
        Hafalan: {
          select: {
            ayatMulai: true,
            ayatSelesai: true
          }
        }
      }
    });

    const santriRankings = allSantriHafalan.map(s => ({
      id: s.id,
      totalAyat: s.Hafalan.reduce((sum, h) => sum + (h.ayatSelesai - h.ayatMulai + 1), 0)
    })).sort((a, b) => b.totalAyat - a.totalAyat);

    const rankingHafalan = santriRankings.findIndex(s => s.id === Number(santriId)) + 1;
    const totalSantri = santriRankings.length;

    console.log('­ƒôè Statistics calculated:', {
      totalAyatHafal,
      rankingHafalan,
