import { NextRequest, NextResponse } from 'next/server'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const semester = searchParams.get('semester') || 'S1'
    const tahunAjaran = searchParams.get('tahunAjaran') || '2024/2025'

    console.log('Tahfidz Reports - Semester:', semester, 'Tahun Ajaran:', tahunAjaran)

    // Get comprehensive tahfidz reports
    const reports = await getTahfidzReports(semester, tahunAjaran)

    return NextResponse.json({
      success: true,
      data: {
        reports,
        summary: {
          totalSantri: reports.length,
          averageNilai: reports.length > 0 ? 
            Math.round(reports.reduce((sum, r) => sum + r.nilaiAkhir, 0) / reports.length * 100) / 100 : 0,
          averageKehadiran: reports.length > 0 ? 
            Math.round(reports.reduce((sum, r) => sum + r.absensi.rate, 0) / reports.length * 100) / 100 : 0,
          averageTargetCompletion: reports.length > 0 ? 
            Math.round(reports.reduce((sum, r) => sum + r.target.rate, 0) / reports.length * 100) / 100 : 0,
          totalHafalan: reports.reduce((sum, r) => sum + r.hafalan.total, 0),
          totalPrestasi: reports.reduce((sum, r) => sum + r.prestasi, 0)
        }
      },
      metadata: {
        semester,
        tahunAjaran,
        generatedAt: new Date().toISOString()
      }
    })

  } catch (error) {
    console.error('Error generating tahfidz reports:', error)
    return NextResponse.json(
      { 
        success: false,
        message: 'Gagal mengambil data laporan tahfidz',
        error: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    )
  } finally {
    await prisma.$disconnect()
  }
}

// Get comprehensive tahfidz reports
async function getTahfidzReports(semester: string, tahunAjaran: string) {
  try {
    // Get tahun ajaran data
    const tahunAjaranData = await prisma.tahunAjaran.findFirst({
      where: {
        tahunAjaran: tahunAjaran
      }
    })

    if (!tahunAjaranData) {
      console.log('Tahun ajaran not found, using current year')
    }

    // Calculate semester date range
    const currentYear = new Date().getFullYear()
    const startDate = semester === 'S1' ? 
      new Date(currentYear, 6, 1) : // July 1st for S1
      new Date(currentYear + 1, 0, 1) // January 1st for S2
    
    const endDate = semester === 'S1' ? 
      new Date(currentYear, 11, 31) : // December 31st for S1
      new Date(currentYear + 1, 5, 30) // June 30th for S2

    // Get all santri with their data
    const santriList = await prisma.user.findMany({
      where: {
        role: {
          name: 'santri'
        }
      },
      include: {
        halaqah: {
          include: {
            guru: true
          }
        },
        hafalanSantri: {
          where: {
            createdAt: {
              gte: startDate,
              lte: endDate
            }
          },
          include: {
            surat: true
          }
        },
        ujianSantri: {
          where: {
            tanggalUjian: {
              gte: startDate,
              lte: endDate
            }
          },
          include: {
            templateUjian: true
          }
        },
        targetHafalan: {
          where: {
            createdAt: {
              gte: startDate,
              lte: endDate
            }
          }
        },
        absensiSantri: {
          where: {
            tanggal: {
              gte: startDate,
              lte: endDate
            }
          }
        },
        prestasiSantri: {
          where: {
            tanggal: {
              gte: startDate,
              lte: endDate
            }
          }
        }
      }
    })

    return santriList.map(santri => {
      // Calculate hafalan statistics
      const totalHafalan = santri.hafalanSantri.length
      const ziyadahCount = santri.hafalanSantri.filter(h => h.jenisHafalan === 'ziyadah').length
      const murojaahCount = santri.hafalanSantri.filter(h => h.jenisHafalan === 'murojaah').length
      
      const totalAyat = santri.hafalanSantri.reduce((sum, hafalan) => {
        return sum + (hafalan.ayatSampai - hafalan.ayatDari + 1)
      }, 0)

      // Calculate absensi statistics
      const totalAbsensi = santri.absensiSantri.length
      const presentCount = santri.absensiSantri.filter(abs => abs.statusKehadiran === 'hadir').length
      const absensiRate = totalAbsensi > 0 ? (presentCount / totalAbsensi) * 100 : 0

      // Calculate target statistics
      const totalTarget = santri.targetHafalan.length
      const completedTarget = santri.targetHafalan.filter(t => t.statusTarget === 'selesai').length
      const targetRate = totalTarget > 0 ? (completedTarget / totalTarget) * 100 : 0

      // Calculate prestasi
      const totalPrestasi = santri.prestasiSantri.length

      // Calculate nilai akhir (comprehensive scoring)
      const hafalanScore = Math.min((totalAyat / 100) * 30, 30) // Max 30 points for hafalan
      const absensiScore = (absensiRate / 100) * 25 // Max 25 points for attendance
      const targetScore = (targetRate / 100) * 25 // Max 25 points for target completion
      const prestasiScore = Math.min(totalPrestasi * 5, 20) // Max 20 points for prestasi
      
      const nilaiAkhir = Math.round(hafalanScore + absensiScore + targetScore + prestasiScore)

      // Determine status akhir
      let statusAkhir = 'Merah' // Default
      if (nilaiAkhir >= 80 && absensiRate >= 80) {
        statusAkhir = 'Hijau'
      } else if (nilaiAkhir >= 60 && absensiRate >= 60) {
        statusAkhir = 'Kuning'
      }

      // Generate catatan
      const catatan = generateCatatan(santri, {
        totalHafalan,
        totalAyat,
        absensiRate,
        targetRate,
        totalPrestasi,
        nilaiAkhir
      })

      return {
        santriId: santri.id,
        namaSantri: santri.namaLengkap,
        halaqah: santri.halaqah?.namaHalaqah || 'Tidak ada halaqah',
        guru: santri.halaqah?.guru?.namaLengkap || 'Tidak ada guru',
        hafalan: {
          total: totalHafalan,
          ziyadah: ziyadahCount,
          murojaah: murojaahCount,
          totalAyat
        },
        absensi: {
          total: totalAbsensi,
          present: presentCount,
          rate: Math.round(absensiRate * 100) / 100
        },
        target: {
          total: totalTarget,
          completed: completedTarget,
          rate: Math.round(targetRate * 100) / 100
        },
        prestasi: totalPrestasi,
        nilaiAkhir,
        statusAkhir,
        catatan
      }
    })
  } catch (error) {
    console.error('Error getting tahfidz reports:', error)
    return []
  }
}

// Generate catatan for santri
function generateCatatan(santri: any, stats: any) {
  const notes = []
  
  if (stats.absensiRate >= 90) {
    notes.push('Kehadiran sangat baik')
  } else if (stats.absensiRate < 60) {
    notes.push('Perlu meningkatkan kehadiran')
  }
  
  if (stats.totalAyat >= 200) {
    notes.push('Hafalan sangat produktif')
  } else if (stats.totalAyat < 50) {
    notes.push('Perlu meningkatkan hafalan')
  }
  
  if (stats.targetRate >= 80) {
    notes.push('Target tercapai dengan baik')
  } else if (stats.targetRate < 50) {
    notes.push('Perlu fokus pada target')
  }
  
  if (stats.totalPrestasi > 0) {
    notes.push(`Meraih ${stats.totalPrestasi} prestasi`)
  }
  
  if (notes.length === 0) {
    notes.push('Performa standar, perlu peningkatan')
  }
  
  return notes.join('. ') + '.'
}

import { NextRequest, NextResponse } from 'next/server'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const startDate = searchParams.get('startDate')
    const endDate = searchParams.get('endDate')
    const halaqahId = searchParams.get('halaqahId')
    const jenisUjian = searchParams.get('jenisUjian')
    const guruId = searchParams.get('guruId')

    // Build date filter
    const dateFilter = startDate && endDate ? {
      tanggalUjian: {
        gte: new Date(startDate),
        lte: new Date(endDate)
      }
    } : {}

    // Build additional filters
    const additionalFilters: any = {}
    if (halaqahId) {
      additionalFilters.santri = {
        halaqahSantri: {
          some: {
            halaqahId: parseInt(halaqahId)
          }
        }
      }
    }
    if (jenisUjian) {
      additionalFilters.templateUjian = {
        jenisUjian: jenisUjian
      }
    }
    if (guruId) {
      additionalFilters.createdBy = guruId
    }

    // Get ujian data with comprehensive relations
    const ujianData = await prisma.ujianSantri.findMany({
      where: {
        ...dateFilter,
        ...additionalFilters
      },
      include: {
        santri: {
          include: {
            halaqahSantri: {
              include: {
                halaqah: {
                  include: {
                    guru: {
                      select: {
                        id: true,
                        namaLengkap: true
                      }
                    }
                  }
                }
              }
            }
          }
        },
        templateUjian: true,
        nilaiUjian: {
          include: {
            komponenPenilaian: true
          }
        },
        tahunAjaran: true
      },
      orderBy: {
        tanggalUjian: 'desc'
      }
    })

    // Calculate comprehensive analytics
    const analytics = calculateUjianAnalytics(ujianData)

    // Get trending data (last 30 days comparison)
    const thirtyDaysAgo = new Date()
    thirtyDaysAgo.setDate(thirtyDaysAgo.getDate() - 30)
    
    const trendingData = await prisma.ujianSantri.findMany({
      where: {
        tanggalUjian: {
          gte: thirtyDaysAgo
        },
        ...additionalFilters
      },
      include: {
        santri: true,
        templateUjian: true
      }
    })

    const trendingAnalytics = calculateTrendingAnalytics(trendingData)

    return NextResponse.json({
      success: true,
      data: {
        summary: analytics.summary,
        byJenisUjian: analytics.byJenisUjian,
        byHalaqah: analytics.byHalaqah,
        byGuru: analytics.byGuru,
        performanceDistribution: analytics.performanceDistribution,
        monthlyTrend: analytics.monthlyTrend,
        topPerformers: analytics.topPerformers,
        needsAttention: analytics.needsAttention,
        trending: trendingAnalytics,
        rawData: ujianData.map(u => ({
          id: u.id,
          santri: u.santri.namaLengkap,
          jenisUjian: u.templateUjian.jenisUjian,
          nilaiAkhir: u.nilaiAkhir,
          tanggal: u.tanggalUjian,
          status: u.statusUjian,
          halaqah: u.santri.halaqahSantri[0]?.halaqah?.namaHalaqah || 'Unknown',
          guru: u.santri.halaqahSantri[0]?.halaqah?.guru?.namaLengkap || 'Unknown'
        }))
      },
      message: `Analytics berhasil digenerate untuk ${ujianData.length} ujian`
    })

  } catch (error) {
    console.error('Error generating ujian analytics:', error)
    return NextResponse.json(
      { 
        success: false,
        error: 'Gagal generate analytics ujian',
        details: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    )
  } finally {
    await prisma.$disconnect()
  }
}

function calculateUjianAnalytics(ujianData: any[]) {
  const totalUjian = ujianData.length
  const totalSantri = new Set(ujianData.map(u => u.santriId)).size
  const averageScore = ujianData.length > 0 ? 
    ujianData.reduce((sum, u) => sum + (u.nilaiAkhir || 0), 0) / ujianData.length : 0

  // Group by jenis ujian
  const byJenisUjian = ujianData.reduce((acc, ujian) => {
    const jenis = ujian.templateUjian.jenisUjian
    if (!acc[jenis]) {
      acc[jenis] = {
        count: 0,
        totalScore: 0,
        averageScore: 0,
        santriCount: new Set()
      }
    }
    acc[jenis].count++
    acc[jenis].totalScore += ujian.nilaiAkhir || 0
    acc[jenis].santriCount.add(ujian.santriId)
    return acc
  }, {} as any)

  // Calculate averages for jenis ujian
  Object.keys(byJenisUjian).forEach(jenis => {
    byJenisUjian[jenis].averageScore = byJenisUjian[jenis].totalScore / byJenisUjian[jenis].count
    byJenisUjian[jenis].santriCount = byJenisUjian[jenis].santriCount.size
  })

  // Group by halaqah
  const byHalaqah = ujianData.reduce((acc, ujian) => {
    const halaqah = ujian.santri.halaqahSantri[0]?.halaqah?.namaHalaqah || 'Unknown'
    if (!acc[halaqah]) {
      acc[halaqah] = {
        count: 0,
        totalScore: 0,
        averageScore: 0,
        santriCount: new Set(),
        guru: ujian.santri.halaqahSantri[0]?.halaqah?.guru?.namaLengkap || 'Unknown'
      }
    }
    acc[halaqah].count++
    acc[halaqah].totalScore += ujian.nilaiAkhir || 0
    acc[halaqah].santriCount.add(ujian.santriId)
    return acc
  }, {} as any)

  // Calculate averages for halaqah
  Object.keys(byHalaqah).forEach(halaqah => {
    byHalaqah[halaqah].averageScore = byHalaqah[halaqah].totalScore / byHalaqah[halaqah].count
    byHalaqah[halaqah].santriCount = byHalaqah[halaqah].santriCount.size
  })

  // Performance distribution
  const performanceDistribution = {
    excellent: ujianData.filter(u => (u.nilaiAkhir || 0) >= 90).length,
    good: ujianData.filter(u => (u.nilaiAkhir || 0) >= 80 && (u.nilaiAkhir || 0) < 90).length,
    average: ujianData.filter(u => (u.nilaiAkhir || 0) >= 70 && (u.nilaiAkhir || 0) < 80).length,
    needsImprovement: ujianData.filter(u => (u.nilaiAkhir || 0) < 70).length
  }

  // Monthly trend (last 6 months)
  const monthlyTrend = generateMonthlyTrend(ujianData)

  // Top performers
  const santriScores = ujianData.reduce((acc, ujian) => {
    const santriId = ujian.santriId
    if (!acc[santriId]) {
      acc[santriId] = {
        santri: ujian.santri.namaLengkap,
        halaqah: ujian.santri.halaqahSantri[0]?.halaqah?.namaHalaqah || 'Unknown',
        scores: [],
        totalUjian: 0
      }
    }
    acc[santriId].scores.push(ujian.nilaiAkhir || 0)
    acc[santriId].totalUjian++
    return acc
  }, {} as any)

  const topPerformers = Object.values(santriScores)
    .map((s: any) => ({
      ...s,
      averageScore: s.scores.reduce((sum: number, score: number) => sum + score, 0) / s.scores.length
    }))
    .sort((a: any, b: any) => b.averageScore - a.averageScore)
    .slice(0, 10)

  const needsAttention = Object.values(santriScores)
    .map((s: any) => ({
      ...s,
      averageScore: s.scores.reduce((sum: number, score: number) => sum + score, 0) / s.scores.length
    }))
    .filter((s: any) => s.averageScore < 70)
    .sort((a: any, b: any) => a.averageScore - b.averageScore)
    .slice(0, 10)

  return {
    summary: {
      totalUjian,
      totalSantri,
      averageScore: Math.round(averageScore * 100) / 100,
      passRate: Math.round((ujianData.filter(u => (u.nilaiAkhir || 0) >= 70).length / totalUjian) * 100),
      excellenceRate: Math.round((ujianData.filter(u => (u.nilaiAkhir || 0) >= 90).length / totalUjian) * 100)
    },
    byJenisUjian,
    byHalaqah,
    byGuru: {}, // TODO: Implement if needed
    performanceDistribution,
    monthlyTrend,
    topPerformers,
    needsAttention
  }
}

function generateMonthlyTrend(ujianData: any[]) {
  const months = []
  const now = new Date()
  
  for (let i = 5; i >= 0; i--) {
    const date = new Date(now.getFullYear(), now.getMonth() - i, 1)
    const monthName = date.toLocaleDateString('id-ID', { month: 'short', year: 'numeric' })
    
    const monthData = ujianData.filter(u => {
      const ujianDate = new Date(u.tanggalUjian)
      return ujianDate.getMonth() === date.getMonth() && ujianDate.getFullYear() === date.getFullYear()
    })
    
    months.push({
      month: monthName,
      count: monthData.length,
      averageScore: monthData.length > 0 ? 
        Math.round((monthData.reduce((sum, u) => sum + (u.nilaiAkhir || 0), 0) / monthData.length) * 100) / 100 : 0
    })
  }
  
  return months
}

function calculateTrendingAnalytics(trendingData: any[]) {
  const last7Days = trendingData.filter(u => {
    const ujianDate = new Date(u.tanggalUjian)
    const sevenDaysAgo = new Date()
    sevenDaysAgo.setDate(sevenDaysAgo.getDate() - 7)
    return ujianDate >= sevenDaysAgo
  })

  const last30Days = trendingData

  return {
    last7Days: {
      count: last7Days.length,
      averageScore: last7Days.length > 0 ? 
        Math.round((last7Days.reduce((sum, u) => sum + (u.nilaiAkhir || 0), 0) / last7Days.length) * 100) / 100 : 0
    },
    last30Days: {
      count: last30Days.length,
      averageScore: last30Days.length > 0 ? 
        Math.round((last30Days.reduce((sum, u) => sum + (u.nilaiAkhir || 0), 0) / last30Days.length) * 100) / 100 : 0
    },
    growth: {
      ujianCount: last7Days.length > 0 && last30Days.length > 0 ? 
        Math.round(((last7Days.length * 4.3) / last30Days.length - 1) * 100) : 0,
      scoreImprovement: 0 // TODO: Calculate based on historical data
    }
  }
}

import { NextRequest, NextResponse } from 'next/server';
import prisma from '@/lib/database/prisma';
import { ApiResponse } from '@/lib/api-helpers';

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { phoneNumber } = body;

    if (!phoneNumber) {
      return ApiResponse.error('Nomor telepon diperlukan', 400);
    }

    // Normalize phone number (remove spaces, dashes, and ensure starts with +62 or 08)
    let normalizedPhone = phoneNumber.replace(/[\s-]/g, '');
    
    // Convert 08 to +628
    if (normalizedPhone.startsWith('08')) {
      normalizedPhone = '+62' + normalizedPhone.substring(1);
    }
    
    // Ensure it starts with +62
    if (!normalizedPhone.startsWith('+62')) {
      normalizedPhone = '+62' + normalizedPhone;
    }

    // Search for user with this phone number
    const user = await prisma.user.findFirst({
      where: {
        OR: [
          { noTlp: phoneNumber },
          { noTlp: normalizedPhone },
          { noTlp: phoneNumber.replace(/^\+62/, '08') }, // Try 08 format
          { noTlp: phoneNumber.replace(/^08/, '+628') }   // Try +628 format
        ]
      },
      select: {
        id: true,
        namaLengkap: true,
        username: true,
        noTlp: true,
        role: {
          select: {
            name: true
          }
        }
      }
    });

    if (user) {
      // User found - generate WhatsApp message
      const adminWhatsApp = '081213923253';
      const message = `Lapor Admin: Saya lupa passcode pada AR-Hafalan dengan user ${user.namaLengkap}`;
      const whatsappUrl = `https://wa.me/${adminWhatsApp}?text=${encodeURIComponent(message)}`;

      // Log the forgot passcode attempt
      await prisma.auditLog.create({
        data: {
          action: 'FORGOT_PASSCODE_REQUEST',
          keterangan: `User ${user.namaLengkap} (${user.username}) meminta reset passcode melalui nomor ${phoneNumber}`,
          userId: user.id
        }
      });

      return ApiResponse.success({
        found: true,
        user: {
          namaLengkap: user.namaLengkap,
          username: user.username,
          role: user.role.name
        },
        whatsappUrl,
        message: `Data ditemukan! Anda akan diarahkan ke WhatsApp untuk menghubungi admin dengan pesan otomatis.`,
        adminPhone: adminWhatsApp
      });
    } else {
      // User not found
      const adminWhatsApp = '081213923253';
      const message = `Hubungi Admin ARHafalan untuk konfirmasi data dengan nomor ${phoneNumber}`;
      const whatsappUrl = `https://wa.me/${adminWhatsApp}?text=${encodeURIComponent(message)}`;

      // Note: Not logging to audit log since we don't have a userId for unknown numbers

      return ApiResponse.success({
        found: false,
        whatsappUrl,
        message: `Nomor tidak ditemukan dalam database. Silakan hubungi admin untuk konfirmasi data Anda.`,
        adminPhone: adminWhatsApp
      });
    }

  } catch (error) {
    console.error('Error in forgot passcode:', error);
    return ApiResponse.serverError('Terjadi kesalahan sistem');
  }
}

