// POST - Create forgot passcode request (from public form)
export async function POST(request: NextRequest) {
  try {
    const { phoneNumber, message } = await request.json();

    if (!phoneNumber) {
      return NextResponse.json(
        { error: 'Nomor telepon harus diisi' },
        { status: 400 }
      );
    }

    // Validate phone number format (basic validation)
    const cleanPhone = phoneNumber.replace(/\D/g, '');
    if (cleanPhone.length < 10 || cleanPhone.length > 15) {
      return NextResponse.json(
        { error: 'Format nomor telepon tidak valid' },
        { status: 400 }
      );
    }

    // Check if phone number is registered in system
    const user = await prisma.user.findFirst({
      where: { 
        noTlp: {
          contains: cleanPhone.slice(-10) // Check last 10 digits
        }
      },
      select: {
        id: true,
        namaLengkap: true,
        username: true,
        noTlp: true
      }
    });

    // Create notification for super admin
    const notification = await prisma.forgotPasscode.create({
      data: {
        phoneNumber: phoneNumber,
        message: message || 'Permintaan reset passcode melalui form',
        isRegistered: !!user,
        userId: user?.id || null
      },
      include: {
        user: {
          select: {
            id: true,
            namaLengkap: true,
            username: true,
            foto: true
          }
        }
      }
    });

    // Return appropriate response
    if (user) {
      return NextResponse.json({
        success: true,
        message: 'Permintaan reset passcode berhasil dikirim. Admin akan segera memproses permintaan Anda.',
        isRegistered: true,
        user: {
          namaLengkap: user.namaLengkap,
          username: user.username
        }
      });
    } else {
      return NextResponse.json({
        success: true,
        message: 'Nomor telepon tidak terdaftar dalam sistem. Silakan hubungi admin untuk bantuan lebih lanjut.',
        isRegistered: false
      });
    }
  } catch (error) {
    console.error('Error creating forgot passcode request:', error);
    return NextResponse.json(
      { error: 'Gagal memproses permintaan. Silakan coba lagi.' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { cookies } from 'next/headers';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

// GET - Ambil data absensi untuk guru
export async function GET(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Get user info
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user || user.role.name !== 'guru') {
      return NextResponse.json({ error: 'Access denied' }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const tanggal = searchParams.get('tanggal');
    const halaqahId = searchParams.get('halaqahId');

    if (!tanggal) {
      return NextResponse.json({ error: 'Tanggal harus diisi' }, { status: 400 });
    }

    // Get guru's own halaqah only (simplified)
    const ownHalaqahs = await prisma.halaqah.findMany({
      where: { guruId: userId },
      select: { id: true }
    });

    const halaqahIds = ownHalaqahs.map(h => h.id);

    if (halaqahIds.length === 0) {
      return NextResponse.json({
        success: true,
        data: {
          jadwals: [],
          absensi: [],
          summary: {
            totalJadwal: 0,
            totalSantri: 0,
            hadir: 0,
            izin: 0,
            alpha: 0
          }
        }
      });
    }

    // Parse tanggal dan validasi
    const targetDate = new Date(tanggal);
    const dayNames = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
    const hari = dayNames[targetDate.getDay()];

    // Validasi: tidak bisa absen untuk tanggal masa depan
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    targetDate.setHours(0, 0, 0, 0);
    
    if (targetDate > today) {
      return NextResponse.json({
        error: 'Tidak dapat mengisi absensi untuk tanggal masa depan'
      }, { status: 400 });
    }

    // Get jadwal for this day - hanya jadwal yang aktif
    const jadwals = await prisma.jadwal.findMany({
      where: {
        halaqahId: { in: halaqahIds },
        hari: hari as any,
        isActive: true // Hanya jadwal yang aktif
      },
      include: {
        halaqah: {
          include: {
            guru: {
              select: {
                id: true,
                namaLengkap: true
              }
            },
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true,
                    username: true
                  }
                }
              }
            }
          }
        }
      },
      orderBy: {
        jamMulai: 'asc'
      }
    });

    if (jadwals.length === 0) {
      return NextResponse.json({
        success: true,
        data: {
          jadwals: [],
          absensi: [],
          summary: {
            totalJadwal: 0,
            totalSantri: 0,
            hadir: 0,
            izin: 0,
            alpha: 0
          }
        }
      });
    }

    // Get existing absensi for this date
    const existingAbsensi = await prisma.absensi.findMany({
      where: {
        jadwalId: { in: jadwals.map(j => j.id) },
        tanggal: {
          gte: new Date(tanggal + 'T00:00:00.000Z'),
          lt: new Date(tanggal + 'T23:59:59.999Z')
        }
      },
      include: {
        santri: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        },
        jadwal: {
          include: {
            halaqah: {
              select: {
                id: true,
                namaHalaqah: true
              }
            }
          }
        }
      }
    });

    // Create complete absensi data with all santri
    const completeAbsensi: any[] = [];
    let totalSantri = 0;
    let hadir = 0;
    let izin = 0;
    let alpha = 0;

    for (const jadwal of jadwals) {
      for (const halaqahSantri of jadwal.halaqah.santri) {
        totalSantri++;
        
        const existingRecord = existingAbsensi.find(
          a => a.santriId === halaqahSantri.santriId && a.jadwalId === jadwal.id
        );

        if (existingRecord) {
          completeAbsensi.push(existingRecord);
          
          // Count status
          switch (existingRecord.status) {
            case 'masuk': hadir++; break;
            case 'izin': izin++; break;
            case 'alpha': alpha++; break;
          }
        } else {
          // Create placeholder for missing absensi
          const placeholder = {
            id: null,
            santriId: halaqahSantri.santriId,
            jadwalId: jadwal.id,
            tanggal: new Date(tanggal),
            status: null,
            santri: halaqahSantri.santri,
            jadwal: {
              id: jadwal.id,
              hari: jadwal.hari,
              jamMulai: jadwal.jamMulai,
              jamSelesai: jadwal.jamSelesai,
              halaqah: {
                id: jadwal.halaqah.id,
                namaHalaqah: jadwal.halaqah.namaHalaqah
              }
            }
          };
          completeAbsensi.push(placeholder);
        }
      }
    }

    // Format jadwal response
    const formattedJadwals = jadwals.map(jadwal => ({
      id: jadwal.id,
      hari: jadwal.hari,
      jamMulai: jadwal.jamMulai.toTimeString().slice(0, 5),
      jamSelesai: jadwal.jamSelesai.toTimeString().slice(0, 5),
      halaqah: {
        id: jadwal.halaqah.id,
        namaHalaqah: jadwal.halaqah.namaHalaqah,
        guru: jadwal.halaqah.guru,
        jumlahSantri: jadwal.halaqah.santri.length
      }
    }));

    return NextResponse.json({
      success: true,
      data: {
        tanggal: tanggal,
        hari: hari,
        jadwals: formattedJadwals,
        absensi: completeAbsensi,
        summary: {
          totalJadwal: jadwals.length,
          totalSantri: totalSantri,
          hadir: hadir,
          izin: izin,
          alpha: alpha,
          belumAbsen: totalSantri - hadir - izin - alpha
        }
      }
    });

  } catch (error) {
    console.error('Error fetching absensi:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

// POST - Simpan/update absensi
export async function POST(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Get user info
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user || user.role.name !== 'guru') {
      return NextResponse.json({ error: 'Access denied' }, { status: 403 });
    }

    const body = await request.json();
    const { santriId, jadwalId, tanggal, status } = body;

    // Validation
    if (!santriId || !jadwalId || !tanggal || !status) {
      return NextResponse.json({ 
        error: 'Data tidak lengkap. santriId, jadwalId, tanggal, dan status harus diisi.' 
      }, { status: 400 });
    }

    if (!['masuk', 'izin', 'alpha'].includes(status)) {
      return NextResponse.json({ 
        error: 'Status harus masuk, izin, atau alpha' 
      }, { status: 400 });
    }

    // Validasi tanggal dan waktu
    const targetDate = new Date(tanggal);
    const dayNames = ['Minggu', 'Senin', 'Selasa', 'Rabu', 'Kamis', 'Jumat', 'Sabtu'];
    const hari = dayNames[targetDate.getDay()];

    // Validasi: tidak bisa absen untuk tanggal masa depan
    const today = new Date();
    today.setHours(0, 0, 0, 0);
    targetDate.setHours(0, 0, 0, 0);
    
    if (targetDate > today) {
      return NextResponse.json({
        error: 'Tidak dapat mengisi absensi untuk tanggal masa depan'
      }, { status: 400 });
    }

    // Verify jadwal belongs to guru's own halaqah dan sesuai hari
    const jadwal = await prisma.jadwal.findFirst({
      where: {
        id: parseInt(jadwalId),
        hari: hari as any, // Validasi hari harus sesuai
        isActive: true, // Jadwal harus aktif
        halaqah: {
          guruId: userId
        }
      },
      include: {
        halaqah: {
          include: {
            santri: {
              where: {
                santriId: parseInt(santriId)
              }
            }
          }
        }
      }
    });

    if (!jadwal) {
      return NextResponse.json({ 
        error: `Jadwal tidak ditemukan, tidak aktif, atau tidak sesuai dengan hari ${hari}` 
      }, { status: 403 });
    }

    // Validasi waktu: hanya bisa absen pada hari yang sama atau dalam rentang waktu yang wajar
    const currentTime = new Date();
    const jadwalDate = new Date(tanggal);
    
    // Jika absen untuk hari ini, validasi waktu
    if (targetDate.getTime() === today.getTime()) {
      const jamMulai = new Date(jadwalDate);
      const [jamMulaiHour, jamMulaiMinute] = jadwal.jamMulai.toTimeString().slice(0, 5).split(':');
      jamMulai.setHours(parseInt(jamMulaiHour), parseInt(jamMulaiMinute), 0, 0);
      
      const jamSelesai = new Date(jadwalDate);
      const [jamSelesaiHour, jamSelesaiMinute] = jadwal.jamSelesai.toTimeString().slice(0, 5).split(':');
      jamSelesai.setHours(parseInt(jamSelesaiHour), parseInt(jamSelesaiMinute), 0, 0);
      
      // Beri toleransi 30 menit sebelum jadwal mulai dan 2 jam setelah jadwal selesai
      const toleransiMulai = new Date(jamMulai.getTime() - 30 * 60 * 1000); // 30 menit sebelum
      const toleransiSelesai = new Date(jamSelesai.getTime() + 2 * 60 * 60 * 1000); // 2 jam setelah
      
      if (currentTime < toleransiMulai || currentTime > toleransiSelesai) {
        return NextResponse.json({
          error: `Absensi hanya dapat diisi pada rentang waktu ${jadwal.jamMulai.toTimeString().slice(0, 5)} - ${jadwal.jamSelesai.toTimeString().slice(0, 5)} (dengan toleransi 30 menit sebelum dan 2 jam setelah)`
        }, { status: 400 });
      }
    }

    // Verify santri is in this halaqah
    if (jadwal.halaqah.santri.length === 0) {
      return NextResponse.json({ 
        error: 'Santri tidak terdaftar di halaqah ini' 
      }, { status: 403 });
    }

    // Check if absensi already exists
    const existingAbsensi = await prisma.absensi.findFirst({
      where: {
        santriId: parseInt(santriId),
        jadwalId: parseInt(jadwalId),
        tanggal: {
          gte: new Date(tanggal + 'T00:00:00.000Z'),
          lt: new Date(tanggal + 'T23:59:59.999Z')
        }
      }
    });

    let absensi;

    if (existingAbsensi) {
      // Update existing absensi
      absensi = await prisma.absensi.update({
        where: { id: existingAbsensi.id },
        data: { 
          status: status as any
        },
        include: {
          santri: {
            select: {
              id: true,
              namaLengkap: true,
              username: true
            }
          },
          jadwal: {
            include: {
              halaqah: {
                select: {
                  id: true,
                  namaHalaqah: true
                }
              }
            }
          }
        }
      });
    } else {
      // Create new absensi
      absensi = await prisma.absensi.create({
        data: {
          santriId: parseInt(santriId),
          jadwalId: parseInt(jadwalId),
          tanggal: new Date(tanggal),
          status: status as any
        },
        include: {
          santri: {
            select: {
              id: true,
              namaLengkap: true,
              username: true
            }
          },
          jadwal: {
            include: {
              halaqah: {
                select: {
                  id: true,
                  namaHalaqah: true
                }
              }
            }
          }
        }
      });
    }

    // Log activity
    await prisma.auditLog.create({
      data: {
        action: existingAbsensi ? 'UPDATE_ABSENSI' : 'CREATE_ABSENSI',
        keterangan: `Guru ${user.namaLengkap} ${existingAbsensi ? 'mengubah' : 'mencatat'} absensi ${absensi.santri.namaLengkap} - ${status}`,
        userId: userId
      }
    });

    return NextResponse.json({
      success: true,
      message: 'Absensi berhasil disimpan',
      data: absensi
    });

  } catch (error) {
    console.error('Error saving absensi:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { cookies } from 'next/headers';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

// GET - Ambil daftar halaqah yang bisa diakses guru (own + permitted)
export async function GET(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Get user info
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user || user.role.name !== 'guru') {
      return NextResponse.json({ error: 'Access denied' }, { status: 403 });
    }

    // Get own halaqah
    const ownHalaqahs = await prisma.halaqah.findMany({
      where: { guruId: userId },
      include: {
        guru: {
          select: {
            id: true,
            namaLengkap: true
          }
        },
        santri: {
          include: {
            santri: {
              select: {
                id: true,
                namaLengkap: true
              }
            }
          }
        }
      }
    });

    // Get permitted halaqah
    const permittedHalaqahs = await prisma.guruPermission.findMany({
      where: {
        guruId: userId,
        isActive: true
      },
      include: {
        halaqah: {
          include: {
            guru: {
              select: {
                id: true,
                namaLengkap: true
              }
            },
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      }
    });

    // Format response
    const accessibleHalaqahs = [
      // Own halaqah
      ...ownHalaqahs.map(h => ({
        id: h.id,
        namaHalaqah: h.namaHalaqah,
        guru: h.guru,
        jumlahSantri: h.santri.length,
        accessType: 'own' as const,
        permissions: {
          canAbsensi: true,
          canHafalan: true,
          canTarget: true
        }
      })),
      // Permitted halaqah
      ...permittedHalaqahs.map(p => ({
        id: p.halaqah.id,
        namaHalaqah: p.halaqah.namaHalaqah,
        guru: p.halaqah.guru,
        jumlahSantri: p.halaqah.santri.length,
        accessType: 'permitted' as const,
        permissions: {
          canAbsensi: p.canAbsensi,
          canHafalan: p.canHafalan,
          canTarget: p.canTarget
        }
      }))
    ];

    // Remove duplicates (jika ada halaqah yang own sekaligus permitted)
    const uniqueHalaqahs = accessibleHalaqahs.reduce((acc, current) => {
      const existing = acc.find(h => h.id === current.id);
      if (!existing) {
        acc.push(current);
      } else if (current.accessType === 'own') {
        // Prioritize own access over permitted
        const index = acc.findIndex(h => h.id === current.id);
        acc[index] = current;
      }
      return acc;
    }, [] as typeof accessibleHalaqahs);

    return NextResponse.json({
      success: true,
      data: uniqueHalaqahs.sort((a, b) => {
        // Sort: own first, then by name
        if (a.accessType === 'own' && b.accessType !== 'own') return -1;
        if (a.accessType !== 'own' && b.accessType === 'own') return 1;
        return a.namaHalaqah.localeCompare(b.namaHalaqah);
      })
    });

  } catch (error) {
    console.error('Error fetching accessible halaqah:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

