        santri: {
          include: {
            santri: {
              select: {
                id: true,
                namaLengkap: true,
                username: true
              }
            }
          }
        },
        jadwal: {
          select: {
            id: true,
            hari: true,
            jamMulai: true,
            jamSelesai: true
          }
        }
      }
    });

    console.log('Halaqah data found for guru:', halaqahData.length, 'halaqah');

    // Format the data for frontend
    const formattedData = halaqahData.map((halaqah: any) => ({
      id: halaqah.id,
