import { NextResponse } from 'next/server';
import { ApiResponse, withAuth } from '@/lib/api-helpers';

export async function GET(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    if (user.role.name !== 'guru') {
      return ApiResponse.forbidden('Access denied');
    }

    const { searchParams } = new URL(request.url);
    const halaqahId = searchParams.get('halaqahId');

    if (!halaqahId) {
      return ApiResponse.error('Halaqah ID is required', 400);
    }

    // Verify guru owns this halaqah
    const halaqah = await prisma.halaqah.findFirst({
      where: {
        id: Number(halaqahId),
        guruId: user.id
      },
      include: {
        santri: {
          include: {
            santri: {
              select: {
                id: true,
                namaLengkap: true,
                username: true
              }
            }
          }
        }
      }
    });

    if (!halaqah) {
      return ApiResponse.forbidden('Access denied to this halaqah');
    }

    const santriIds = halaqah.santri.map(hs => hs.santriId);

    if (santriIds.length === 0) {
      return ApiResponse.success([]);
    }

    console.log('Halaqah found:', halaqah.id, 'with', halaqah.santri.length, 'santri');

    // Get all hafalan data for santri in this halaqah in one query
    const allHafalan = await prisma.hafalan.findMany({
      where: {
        santriId: { in: santriIds }
      },
      select: {
        santriId: true,
        status: true,
        ayatMulai: true,
        ayatSelesai: true,
        tanggal: true
      },
      orderBy: {
        tanggal: 'desc'
      }
    });

    console.log('Total hafalan records found:', allHafalan.length);

    // Group hafalan by santri and calculate stats
    const santriHafalanData = halaqah.santri.map((hs) => {
      const santriHafalan = allHafalan.filter(h => h.santriId === hs.santriId);
      
      let totalAyat = 0;
      let ziyadahCount = 0;
      let murojaahCount = 0;
      let lastHafalan: any = null;

      santriHafalan.forEach(hafalan => {
        const ayatCount = hafalan.ayatSelesai - hafalan.ayatMulai + 1;
        totalAyat += ayatCount;
        
        if (hafalan.status === 'ziyadah') {
          ziyadahCount++;
        } else if (hafalan.status === 'murojaah') {
          murojaahCount++;
        }

        if (!lastHafalan && hafalan.tanggal) {
          lastHafalan = hafalan.tanggal;
        }
      });

      return {
        id: hs.santri.id,
        namaLengkap: hs.santri.namaLengkap,
        username: hs.santri.username,
        totalAyat,
        ziyadahCount,
        murojaahCount,
        lastHafalan: lastHafalan ? lastHafalan.toISOString() : null
      };
    });

    // Sort by total ayat (descending)
    const sortedData = santriHafalanData.sort((a, b) => b.totalAyat - a.totalAyat);

    console.log('Top Santri Data:', sortedData); // Debug log

    return NextResponse.json({ data: sortedData });

  } catch (error) {
    console.error('GET /api/guru/grafik/top-santri error:', error);
    return NextResponse.json({ error: 'Failed to fetch top santri data' }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const santriName = searchParams.get('santriName')
    const surat = searchParams.get('surat')
    const status = searchParams.get('status')

    // TODO: Get guru ID from session/auth
    // For now, get the first guru found (demo purposes)
    const guru = await prisma.user.findFirst({
      where: {
        role: {
          name: 'guru'
        }
      }
    })

    if (!guru) {
      return NextResponse.json({
        success: false,
        message: 'Guru tidak ditemukan'
      }, { status: 404 })
    }

    // Get santri from guru's halaqah using direct relation
    const halaqahList = await prisma.halaqah.findMany({
      where: {
        guruId: guru.id
      },
      include: {
        santri: {
          include: {
            santri: {
              select: {
                id: true,
                namaLengkap: true,
                username: true
              }
            }
          }
        }
      }
    })

    // Extract santri IDs from guru's halaqah
    const santriIds: number[] = []
    halaqahList.forEach(halaqah => {
      halaqah.santri.forEach(hs => {
        santriIds.push(hs.santri.id)
      })
    })

    if (santriIds.length === 0) {
      return NextResponse.json({
        success: true,
        data: [],
        message: 'Tidak ada santri di halaqah Anda'
      })
    }

    // Build where clause for filtering
    const whereClause: any = {
      santriId: {
        in: santriIds
      }
    }

    if (santriName) {
      // We'll filter by santri name after fetching data since it's in a relation
    }

    if (surat) {
      whereClause.surat = {
        contains: surat,
        mode: 'insensitive'
      }
    }

    if (status) {
      whereClause.status = status
    }

    // Get hafalan data with santri information
    const hafalanData = await prisma.hafalan.findMany({
      where: whereClause,
      include: {
        santri: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        }
      },
      orderBy: {
        tanggal: 'desc'
      }
    })

    // Filter by santri name if provided
    let filteredData = hafalanData
    if (santriName) {
      filteredData = hafalanData.filter(h => 
        h.santri?.namaLengkap?.toLowerCase().includes(santriName.toLowerCase()) ||
        h.santri?.username?.toLowerCase().includes(santriName.toLowerCase())
      )
    }

    return NextResponse.json({
      success: true,
      data: filteredData,
      message: `Ditemukan ${filteredData.length} data hafalan`
    })

  } catch (error) {
    console.error('Error fetching hafalan:', error)
    return NextResponse.json({
      success: false,
      message: 'Gagal mengambil data hafalan'
    }, { status: 500 })
  } finally {
    await prisma.$disconnect()
  }
}

export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { santriId, surat, ayatMulai, ayatSelesai, status, tanggal, keterangan } = body

    // Validation
    if (!santriId || !surat || !ayatMulai || !ayatSelesai || !status) {
      return NextResponse.json({
        success: false,
        error: 'Data tidak lengkap'
      }, { status: 400 })
    }

    // Create hafalan record
    const hafalan = await prisma.hafalan.create({
      data: {
        santriId: parseInt(santriId),
        surat,
        ayatMulai: parseInt(ayatMulai),
        ayatSelesai: parseInt(ayatSelesai),
        status,
        tanggal: new Date(tanggal),
        keterangan
      },
      include: {
        santri: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        }
      }
    })

    return NextResponse.json({
      success: true,
      data: hafalan,
      message: 'Hafalan berhasil ditambahkan'
    })

  } catch (error) {
    console.error('Error creating hafalan:', error)
    return NextResponse.json({
      success: false,
      error: 'Gagal menambahkan hafalan'
    }, { status: 500 })
  } finally {
    await prisma.$disconnect()
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { cookies } from 'next/headers';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

// GET - Ambil daftar halaqah yang diampu guru (own halaqah only)
export async function GET(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Get user info
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user || user.role.name !== 'guru') {
      return NextResponse.json({ error: 'Access denied' }, { status: 403 });
    }

    // Get guru's own halaqah only
    const halaqahs = await prisma.halaqah.findMany({
      where: { guruId: userId },
      include: {
        guru: {
          select: {
            id: true,
            namaLengkap: true
          }
        },
        santri: {
          include: {
            santri: {
              select: {
                id: true,
                namaLengkap: true,
                username: true
              }
            }
          }
        }
      },
      orderBy: {
        namaHalaqah: 'asc'
      }
    });

    // Format response
    const formattedHalaqahs = halaqahs.map(h => ({
      id: h.id,
      namaHalaqah: h.namaHalaqah,
      guru: h.guru,
      jumlahSantri: h.santri.length,
      santri: h.santri.map(s => s.santri)
    }));

    return NextResponse.json({
      success: true,
      data: formattedHalaqahs
    });

  } catch (error) {
    console.error('Error fetching guru halaqah:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';
import { ApiResponse, withAuth } from '@/lib/api-helpers';

// GET jadwal untuk guru
export async function GET(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    // Ensure user is guru
    if (user.role.name !== 'guru') {
      return ApiResponse.forbidden('Access denied');
    }

    const { searchParams } = new URL(request.url);
    const halaqahId = searchParams.get('halaqahId');

    const whereClause: any = {
      halaqah: {
        guruId: user.id
      }
    };

    // Filter berdasarkan halaqahId jika disediakan
    if (halaqahId) {
      whereClause.halaqahId = parseInt(halaqahId);
    }

    const jadwal = await prisma.jadwal.findMany({
      where: whereClause,
      include: {
        halaqah: {
          include: {
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      },
      orderBy: [
        { hari: 'asc' },
        { jamMulai: 'asc' }
      ]
    });

    const formatted = jadwal.map(j => ({
      id: j.id,
      hari: j.hari,
      jamMulai: j.jamMulai,
      jamSelesai: j.jamSelesai,
      halaqah: {
        id: j.halaqah.id,
        namaHalaqah: j.halaqah.namaHalaqah,
        jumlahSantri: j.halaqah.santri.length,
        santri: j.halaqah.santri.map(hs => hs.santri)
      }
    }));

    console.log(`Guru ${user.namaLengkap} has ${formatted.length} jadwal`);
    return NextResponse.json(formatted);

  } catch (error) {
    console.error('GET /api/guru/jadwal error:', error);
    return NextResponse.json({ error: 'Failed to fetch jadwal' }, { status: 500 });
  }
}

// UPDATE jadwal (limited access for guru - hanya bisa update jam)
export async function PUT(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    // Ensure user is guru
    if (user.role.name !== 'guru') {
      return ApiResponse.forbidden('Access denied');
    }

    const body = await request.json();
    const { jadwalId, jamMulai, jamSelesai } = body;

    if (!jadwalId || !jamMulai || !jamSelesai) {
      return NextResponse.json({ 
        error: 'Jadwal ID, jam mulai, dan jam selesai harus diisi' 
      }, { status: 400 });
    }

    // Verify that this jadwal belongs to the current guru
    const jadwal = await prisma.jadwal.findFirst({
      where: {
        id: parseInt(jadwalId),
        halaqah: {
          guruId: user.id
        }
      }
    });

    if (!jadwal) {
      return NextResponse.json({ error: 'Jadwal not found or access denied' }, { status: 404 });
    }

    // Validasi waktu
    const mulai = new Date(`2000-01-01T${jamMulai}`);
    const selesai = new Date(`2000-01-01T${jamSelesai}`);

    if (mulai >= selesai) {
      return NextResponse.json({ 
        error: 'Jam mulai harus lebih awal dari jam selesai' 
      }, { status: 400 });
    }

    // Update jadwal
    const updatedJadwal = await prisma.jadwal.update({
      where: { id: parseInt(jadwalId) },
      data: {
        jamMulai: new Date(`2000-01-01T${jamMulai}`),
        jamSelesai: new Date(`2000-01-01T${jamSelesai}`)
      },
      include: {
        halaqah: {
          include: {
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      }
    });

    const formatted = {
      id: updatedJadwal.id,
      hari: updatedJadwal.hari,
      jamMulai: updatedJadwal.jamMulai,
      jamSelesai: updatedJadwal.jamSelesai,
      halaqah: {
        id: updatedJadwal.halaqah.id,
        namaHalaqah: updatedJadwal.halaqah.namaHalaqah,
        jumlahSantri: updatedJadwal.halaqah.santri.length,
        santri: updatedJadwal.halaqah.santri.map(hs => hs.santri)
      }
    };

    console.log('Jadwal updated by guru:', formatted.id);
    return NextResponse.json(formatted);

  } catch (error: any) {
    console.error('PUT /api/guru/jadwal error:', error);
    return NextResponse.json({
      error: 'Failed to update jadwal',
      details: error.message || 'Unknown error occurred'
    }, { status: 500 });
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const periode = searchParams.get('periode') // 'bulan-ini', 'semester-ini', 'tahun-ini'
    const jenisUjian = searchParams.get('jenisUjian') // 'tasmi', 'tahfidz', 'mhq'
    const halaqah = searchParams.get('halaqah')
    const format = searchParams.get('format') // 'summary', 'detail', 'export'

    // Calculate date range based on periode
    const now = new Date()
    let startDate: Date
    const endDate = now

    switch (periode) {
      case 'bulan-ini':
        startDate = new Date(now.getFullYear(), now.getMonth(), 1)
        break
      case 'semester-ini':
        // Assume semester starts in July or January
        const currentMonth = now.getMonth()
        const semesterStart = currentMonth >= 6 ? 6 : 0 // July or January
        startDate = new Date(now.getFullYear(), semesterStart, 1)
        break
      case 'tahun-ini':
        startDate = new Date(now.getFullYear(), 0, 1)
        break
      default:
        // Default to current month
        startDate = new Date(now.getFullYear(), now.getMonth(), 1)
    }

    // Build query filters
    const whereClause: any = {
      tanggalUjian: {
        gte: startDate,
        lte: endDate
      }
    }

    if (jenisUjian) {
      whereClause.templateUjian = {
        jenisUjian: jenisUjian
      }
    }

    // Note: halaqah filter disabled for now due to schema limitations
    // if (halaqah) {
    //   whereClause.santri = {
    //     halaqah: {
    //       namaHalaqah: halaqah
    //     }
    //   }
    // }

    // Get ujian data
    const ujianData = await prisma.ujianSantri.findMany({
      where: whereClause,
      include: {
        santri: {
          include: { role: true,
            halaqah: {
              include: {
                guru: true
              }
            }
          }
        },
        templateUjian: {
          include: {
            komponenPenilaian: true
          }
        },
        tahunAjaran: true,
        nilaiUjian: {
          include: {
            komponenPenilaian: true
          }
        }
      },
      orderBy: {
        tanggalUjian: 'desc'
      }
    })

    // Process data based on format
    if (format === 'summary') {
      return generateSummaryReport(ujianData, periode, jenisUjian, halaqah)
    } else if (format === 'detail') {
      return generateDetailReport(ujianData, periode, jenisUjian, halaqah)
    } else if (format === 'export') {
      return generateExportData(ujianData, periode, jenisUjian, halaqah)
    }

    // Default: return processed data
    const processedData = ujianData.map(ujian => ({
      id: ujian.id,
      santriId: ujian.santriId,
      santriNama: ujian.santri.namaLengkap,
      halaqah: ujian.santri.halaqah?.namaHalaqah || 'Tidak ada halaqah',
      jenisUjian: ujian.templateUjian.jenisUjian,
      nilaiAkhir: ujian.nilaiAkhir || 0,
      tanggalUjian: ujian.tanggalUjian.toISOString(),
      statusUjian: ujian.statusUjian,
      juzRange: ujian.juzDari && ujian.juzSampai ? {
        dari: ujian.juzDari,
        sampai: ujian.juzSampai
      } : null,
      catatanGuru: ujian.catatanGuru,
      komponenNilai: ujian.nilaiUjian.map(nilai => ({
        komponen: nilai.komponenPenilaian?.namaKomponen || 'Unknown',
        nilai: nilai.nilaiRaw,
        bobot: nilai.komponenPenilaian?.bobotNilai || 0,
        catatan: nilai.catatan
      }))
    }))

    return NextResponse.json({
      success: true,
      data: processedData,
      metadata: {
        periode,
        jenisUjian,
        halaqah,
        totalUjian: processedData.length,
        dateRange: {
          start: startDate.toISOString(),
          end: endDate.toISOString()
        }
      },
      message: 'Laporan ujian berhasil diambil'
    })

  } catch (error) {
    console.error('Error generating laporan ujian:', error)
    return NextResponse.json(
      { 
        success: false,
        message: 'Gagal mengambil laporan ujian',
        error: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    )
  } finally {
    await prisma.$disconnect()
  }
}

// Generate summary report
async function generateSummaryReport(ujianData: any[], periode: string | null, jenisUjian: string | null, halaqah: string | null) {
  const totalUjian = ujianData.length
  const nilaiRataRata = ujianData.length > 0 
    ? ujianData.reduce((sum, ujian) => sum + (ujian.nilaiAkhir || 0), 0) / ujianData.length 
    : 0

  // Group by jenis ujian
  const byJenisUjian = ujianData.reduce((acc, ujian) => {
    const jenis = ujian.templateUjian.jenisUjian
    if (!acc[jenis]) {
      acc[jenis] = { count: 0, totalNilai: 0, rataRata: 0 }
    }
    acc[jenis].count++
    acc[jenis].totalNilai += ujian.nilaiAkhir || 0
    acc[jenis].rataRata = acc[jenis].totalNilai / acc[jenis].count
    return acc
  }, {} as Record<string, any>)

  // Group by halaqah
  const byHalaqah = ujianData.reduce((acc, ujian) => {
    const halaqahName = ujian.santri.halaqah?.namaHalaqah || 'Tidak ada halaqah'
    if (!acc[halaqahName]) {
      acc[halaqahName] = { count: 0, totalNilai: 0, rataRata: 0, santriCount: new Set() }
    }
    acc[halaqahName].count++
    acc[halaqahName].totalNilai += ujian.nilaiAkhir || 0
    acc[halaqahName].santriCount.add(ujian.santriId)
    acc[halaqahName].rataRata = acc[halaqahName].totalNilai / acc[halaqahName].count
    return acc
  }, {} as Record<string, any>)

  // Convert santriCount Set to number
  Object.keys(byHalaqah).forEach(key => {
    byHalaqah[key].santriCount = byHalaqah[key].santriCount.size
  })

  // Performance categories
  const performanceCategories = {
    excellent: ujianData.filter(u => (u.nilaiAkhir || 0) >= 90).length,
    good: ujianData.filter(u => (u.nilaiAkhir || 0) >= 80 && (u.nilaiAkhir || 0) < 90).length,
    average: ujianData.filter(u => (u.nilaiAkhir || 0) >= 70 && (u.nilaiAkhir || 0) < 80).length,
    needsImprovement: ujianData.filter(u => (u.nilaiAkhir || 0) < 70).length
  }

  return NextResponse.json({
    success: true,
    data: {
      summary: {
        totalUjian,
        nilaiRataRata: Math.round(nilaiRataRata * 100) / 100,
        periode: periode || 'bulan-ini',
        jenisUjian: jenisUjian || 'semua',
        halaqah: halaqah || 'semua'
      },
      byJenisUjian,
      byHalaqah,
      performanceCategories,
      trends: {
        // TODO: Add trend analysis
        weeklyAverage: [],
        monthlyProgress: []
      }
    },
    message: 'Summary laporan ujian berhasil diambil'
  })
}

// Generate detail report
async function generateDetailReport(ujianData: any[], periode: string | null, jenisUjian: string | null, halaqah: string | null) {
  const detailData = ujianData.map(ujian => ({
    id: ujian.id,
    tanggalUjian: ujian.tanggalUjian.toISOString(),
    santri: {
      id: ujian.santriId,
      nama: ujian.santri.namaLengkap,
      username: ujian.santri.username,
      halaqah: ujian.santri.halaqah?.namaHalaqah || 'Tidak ada halaqah'
    },
    ujian: {
      jenis: ujian.templateUjian.jenisUjian,
      template: ujian.templateUjian.namaTemplate,
      juzRange: ujian.juzDari && ujian.juzSampai ? {
        dari: ujian.juzDari,
        sampai: ujian.juzSampai
      } : null,
      nilaiAkhir: ujian.nilaiAkhir || 0,
      status: ujian.statusUjian
    },
    komponenNilai: ujian.nilaiUjian.map((nilai: any) => ({
      komponen: nilai.komponenPenilaian?.namaKomponen || 'Unknown',
