  }))

  return NextResponse.json({
    success: true,
    data: detailData,
    metadata: {
      totalRecords: detailData.length,
      periode: periode || 'bulan-ini',
      jenisUjian: jenisUjian || 'semua',
      halaqah: halaqah || 'semua'
    },
    message: 'Detail laporan ujian berhasil diambil'
  })
}

