import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/database/prisma'
import { withAuth } from '@/lib/api-helpers'

export async function GET(request: NextRequest) {
  try {
    // Get authenticated user
    const { user, error } = await withAuth(request)
    if (error || !user) {
      return NextResponse.json({
        success: false,
        message: 'Unauthorized - Silakan login terlebih dahulu'
      }, { status: 401 })
    }

    // Verify user is a guru
    if (user.role.name !== 'guru') {
      return NextResponse.json({
        success: false,
        message: 'Access denied - Hanya guru yang dapat mengakses endpoint ini'
      }, { status: 403 })
    }

    // Get halaqah yang diajar oleh guru ini
    const halaqahList = await prisma.halaqah.findMany({
      where: {
        guruId: user.id
      },
      include: {
        guru: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        }
      }
    })

    if (halaqahList.length === 0) {
      return NextResponse.json({
        success: false,
        message: 'Anda belum mengajar di halaqah manapun'
      }, { status: 404 })
    }

    // Get IDs dari halaqah yang diajar
    const halaqahIds = halaqahList.map(h => h.id)

    // Get santri yang terdaftar di halaqah-halaqah tersebut
    const halaqahSantriList = await prisma.halaqahSantri.findMany({
      where: {
        halaqahId: {
          in: halaqahIds
        }
      },
      include: {
        santri: {
          include: {
            role: true
          }
        },
        halaqah: {
          include: {
            guru: {
              select: {
                id: true,
                namaLengkap: true,
                username: true
              }
            }
          }
        }
      },
      orderBy: {
        santri: {
          namaLengkap: 'asc'
        }
      }
    })

    // Transform data
    const transformedSantri = halaqahSantriList.map((hs) => ({
      id: hs.santri.id,
      namaLengkap: hs.santri.namaLengkap,
      username: hs.santri.username,
      email: hs.santri.email,
      tahunAkademik: hs.tahunAkademik,
      semester: hs.semester,
      halaqah: {
        id: hs.halaqah.id,
        namaHalaqah: hs.halaqah.namaHalaqah,
        guru: hs.halaqah.guru ? {
          id: hs.halaqah.guru.id,
          namaLengkap: hs.halaqah.guru.namaLengkap,
          username: hs.halaqah.guru.username
        } : null
      }
    }))

    // Group by halaqah
    const byHalaqah = transformedSantri.reduce((acc, santri) => {
      const halaqahName = santri.halaqah?.namaHalaqah || 'Tidak ada halaqah'
      if (!acc[halaqahName]) {
        acc[halaqahName] = {
          halaqah: santri.halaqah,
          santri: []
        }
      }
      acc[halaqahName].santri.push(santri)
      return acc
    }, {} as Record<string, any>)

    return NextResponse.json({
      success: true,
      data: {
        santriList: transformedSantri,
        byHalaqah,
        halaqahList: halaqahList.map(h => ({
          id: h.id,
          namaHalaqah: h.namaHalaqah,
          guru: h.guru
        })),
        summary: {
          totalSantri: transformedSantri.length,
          totalHalaqah: Object.keys(byHalaqah).length,
          santriPerHalaqah: Object.values(byHalaqah).map((h: any) => ({
            halaqah: h.halaqah?.namaHalaqah || 'Tidak ada halaqah',
            guru: h.halaqah?.guru?.namaLengkap || 'Tidak ada guru',
            jumlahSantri: h.santri.length
          }))
        }
      },
      message: `Data santri dari ${halaqahList.length} halaqah berhasil diambil`
    })

  } catch (error) {
    console.error('Error fetching santri data:', error)
    return NextResponse.json(
      { 
        success: false,
        message: 'Gagal mengambil data santri',
        error: error instanceof Error ? error.message : 'Unknown error'
      },
      { status: 500 }
    )
  }
}

import { NextRequest, NextResponse } from 'next/server'
import { PrismaClient } from '@prisma/client'

const prisma = new PrismaClient()

// GET - Ambil data target hafalan
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const santriId = searchParams.get('santriId')

    // TODO: Get guru ID from session/auth
    const guru = await prisma.user.findFirst({
      where: {
        role: {
          name: 'guru'
        }
      }
    })

    if (!guru) {
      return NextResponse.json({
        success: false,
        message: 'Guru tidak ditemukan'
      }, { status: 404 })
    }

    // Get target hafalan data
    const whereClause: any = {}
    if (santriId) {
      whereClause.santriId = parseInt(santriId)
    } else {
      // Get all santri from guru's halaqah
      const halaqahList = await prisma.halaqah.findMany({
        where: { guruId: guru.id },
        include: {
          santri: {
            select: { santriId: true }
          }
        }
      })
      
      const santriIds = halaqahList.flatMap(h => h.santri.map(s => s.santriId))
      whereClause.santriId = { in: santriIds }
    }

    const targetData = await prisma.targetHafalan.findMany({
      where: whereClause,
      include: {
        santri: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        }
      },
      orderBy: {
        deadline: 'asc'
      }
    })

    // Calculate current progress for each target
    const targetsWithProgress = await Promise.all(
      targetData.map(async (target) => {
        // Get hafalan data for this specific target
        const hafalanData = await prisma.hafalan.findMany({
          where: {
            santriId: target.santriId,
            surat: target.surat,
            status: 'ziyadah', // Only count ziyadah for progress
            tanggal: {
              lte: target.deadline
            }
          },
          orderBy: {
            ayatSelesai: 'desc'
          }
        })

        // Calculate current progress based on highest ayat reached
        let currentAyat = 0
        if (hafalanData.length > 0) {
          const latestHafalan = hafalanData[0]
          currentAyat = Math.min(latestHafalan.ayatSelesai, target.ayatTarget)
        }

        return {
          id: target.id,
          santriId: target.santriId,
          santriNama: target.santri.namaLengkap,
          surat: target.surat,
          ayatTarget: target.ayatTarget,
          currentAyat: currentAyat,
          deadline: target.deadline.toISOString(),
          status: target.status,
          progressPercentage: Math.round((currentAyat / target.ayatTarget) * 100)
        }
      })
    )

    return NextResponse.json({
      success: true,
      data: targetsWithProgress,
      message: 'Data target hafalan berhasil diambil'
    })

  } catch (error) {
    console.error('Error fetching target hafalan:', error)
    return NextResponse.json({
      success: false,
      message: 'Gagal mengambil data target hafalan'
    }, { status: 500 })
  } finally {
    await prisma.$disconnect()
  }
}

// POST - Buat target hafalan baru
export async function POST(request: NextRequest) {
  try {
    const body = await request.json()
    const { santriId, surat, ayatTarget, deadline } = body

    // Validasi input
    if (!santriId || !surat || !ayatTarget || !deadline) {
      return NextResponse.json({
        success: false,
        message: 'Data tidak lengkap'
      }, { status: 400 })
    }

    // TODO: Get guru ID from session/auth
    const guru = await prisma.user.findFirst({
      where: {
        role: {
          name: 'guru'
        }
      }
    })

    if (!guru) {
      return NextResponse.json({
        success: false,
        message: 'Guru tidak ditemukan'
      }, { status: 404 })
    }

    // Validasi santri ada dalam halaqah guru
    const santriInHalaqah = await prisma.halaqahSantri.findFirst({
      where: {
        santriId: parseInt(santriId),
        halaqah: {
          guruId: guru.id
        }
      }
    })

    if (!santriInHalaqah) {
      return NextResponse.json({
        success: false,
        message: 'Santri tidak ada dalam halaqah Anda'
      }, { status: 403 })
    }

    // Check if target already exists for this santri and surah
    const existingTarget = await prisma.targetHafalan.findFirst({
      where: {
        santriId: parseInt(santriId),
        surat: surat,
        status: { in: ['belum', 'proses'] }
      }
    })

    if (existingTarget) {
      return NextResponse.json({
        success: false,
        message: 'Target untuk surah ini sudah ada dan belum selesai'
      }, { status: 400 })
    }

    // Create target hafalan
    const newTarget = await prisma.targetHafalan.create({
      data: {
        santriId: parseInt(santriId),
        surat: surat,
        ayatTarget: parseInt(ayatTarget),
        deadline: new Date(deadline),
        status: 'belum'
      },
      include: {
        santri: {
          select: {
            namaLengkap: true,
            username: true
          }
        }
      }
    })

    return NextResponse.json({
      success: true,
      data: {
        id: newTarget.id,
        santriId: newTarget.santriId,
        santriNama: newTarget.santri.namaLengkap,
        surat: newTarget.surat,
        ayatTarget: newTarget.ayatTarget,
        deadline: newTarget.deadline.toISOString(),
        status: newTarget.status
      },
      message: 'Target hafalan berhasil dibuat'
    })

