                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      }
    });

    // Log activity
    await prisma.auditLog.create({
      data: {
        action: 'TOGGLE_JADWAL_STATUS',
        keterangan: `${user.namaLengkap} ${updatedJadwal.isActive ? 'mengaktifkan' : 'menonaktifkan'} jadwal ${updatedJadwal.halaqah.namaHalaqah} - ${updatedJadwal.hari}`,
        userId: user.id
      }
    });

