}

import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';
import { ApiResponse, withAuth } from '@/lib/api-helpers';

// GET all jadwal
export async function GET(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    const { searchParams } = new URL(request.url);
    const halaqahId = searchParams.get('halaqahId');
    const isTemplate = searchParams.get('isTemplate');
    const isActive = searchParams.get('isActive');

    const whereClause: any = {};

    // Filter berdasarkan role user
    if (user.role.name === 'guru') {
      // Guru bisa melihat jadwal halaqah yang dia ampu + yang diberi permission
      const guruPermissions = await prisma.guruPermission.findMany({
        where: {
          guruId: user.id,
          isActive: true
        },
        select: {
          halaqahId: true
        }
      });

      const permittedHalaqahIds = guruPermissions.map(p => p.halaqahId);
      
      whereClause.halaqah = {
        OR: [
          { guruId: user.id }, // Halaqah sendiri
          { id: { in: permittedHalaqahIds } } // Halaqah yang diberi permission
        ]
      };
    } else if (user.role.name === 'santri') {
      // Santri hanya bisa melihat jadwal halaqah yang dia ikuti
      whereClause.halaqah = {
        santri: {
          some: {
            santriId: user.id
          }
        }
      };
    }

    // Filter berdasarkan halaqahId jika disediakan
    if (halaqahId) {
      whereClause.halaqahId = parseInt(halaqahId);
    }

    // Filter berdasarkan isTemplate
    if (isTemplate !== null) {
      whereClause.isTemplate = isTemplate === 'true';
    }

    // Filter berdasarkan isActive
    if (isActive !== null) {
      whereClause.isActive = isActive === 'true';
    }

    const jadwal = await prisma.jadwal.findMany({
      where: whereClause,
      include: {
        halaqah: {
          include: {
            guru: {
              select: {
                id: true,
                namaLengkap: true
              }
            },
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      },
      orderBy: [
        { hari: 'asc' },
        { jamMulai: 'asc' }
      ]
    });

    const formatted = jadwal.map(j => ({
      id: j.id,
      hari: j.hari,
      jamMulai: j.jamMulai,
      jamSelesai: j.jamSelesai,
      // Safely access new fields with fallbacks
      isTemplate: (j as any).isTemplate ?? true,
      tanggalMulai: (j as any).tanggalMulai ?? null,
      tanggalSelesai: (j as any).tanggalSelesai ?? null,
      isActive: (j as any).isActive ?? true,
      createdAt: (j as any).createdAt ?? new Date(),
      updatedAt: (j as any).updatedAt ?? new Date(),
      halaqah: {
        id: j.halaqah.id,
        namaHalaqah: j.halaqah.namaHalaqah,
        guru: j.halaqah.guru,
        jumlahSantri: j.halaqah.santri.length
      }
    }));

    return NextResponse.json(formatted);
  } catch (error) {
    console.error('GET /api/jadwal error:', error);
    return NextResponse.json({ error: 'Failed to fetch jadwal' }, { status: 500 });
  }
}

// CREATE jadwal
export async function POST(request: Request) {
  try {
    const { user, error } = await withAuth(request);
    if (error || !user) {
      return ApiResponse.unauthorized(error || 'Unauthorized');
    }

    // Hanya admin dan super-admin yang bisa membuat jadwal
    if (!['admin', 'super_admin'].includes(user.role.name)) {
      return ApiResponse.forbidden('Access denied');
    }

    const body = await request.json();
    const { 
      hari, 
      jamMulai, 
      jamSelesai, 
      halaqahId, 
      isTemplate = true,
      tanggalMulai,
      tanggalSelesai,
      isActive = true
    } = body;

    console.log('Creating jadwal:', body);

    if (!hari || !jamMulai || !jamSelesai || !halaqahId) {
      return NextResponse.json({ 
        error: 'Hari, jam mulai, jam selesai, dan halaqah harus diisi' 
      }, { status: 400 });
    }

    // Validasi halaqah exists
    const halaqah = await prisma.halaqah.findUnique({
      where: { id: parseInt(halaqahId) }
    });

    if (!halaqah) {
      return NextResponse.json({ error: 'Halaqah tidak ditemukan' }, { status: 404 });
    }

    // Validasi waktu
    const mulai = new Date(`2000-01-01T${jamMulai}`);
    const selesai = new Date(`2000-01-01T${jamSelesai}`);

    if (mulai >= selesai) {
      return NextResponse.json({ 
        error: 'Jam mulai harus lebih awal dari jam selesai' 
      }, { status: 400 });
    }

    // Validasi tanggal periode jika disediakan
    if (tanggalMulai && tanggalSelesai) {
      const startDate = new Date(tanggalMulai);
      const endDate = new Date(tanggalSelesai);
      
      if (startDate >= endDate) {
        return NextResponse.json({ 
          error: 'Tanggal mulai harus lebih awal dari tanggal selesai' 
        }, { status: 400 });
      }
    }

    // Check for conflicting schedules - hanya untuk template aktif
    const conflictingJadwal = await prisma.jadwal.findFirst({
      where: {
        hari: hari,
        halaqahId: parseInt(halaqahId),
        isActive: true,
        OR: [
          // Case 1: New schedule starts during existing schedule
          {
            AND: [
              { jamMulai: { lte: mulai } },
              { jamSelesai: { gt: mulai } }
            ]
          },
          // Case 2: New schedule ends during existing schedule
          {
            AND: [
              { jamMulai: { lt: selesai } },
              { jamSelesai: { gte: selesai } }
            ]
          },
          // Case 3: New schedule completely contains existing schedule
          {
            AND: [
              { jamMulai: { gte: mulai } },
              { jamSelesai: { lte: selesai } }
            ]
          }
        ]
      },
      include: {
        halaqah: {
          select: {
            namaHalaqah: true
          }
        }
      }
    });

    if (conflictingJadwal) {
      return NextResponse.json({ 
        error: `Jadwal bentrok dengan jadwal ${conflictingJadwal.halaqah.namaHalaqah} pada hari ${hari} jam ${conflictingJadwal.jamMulai.toTimeString().slice(0,5)}-${conflictingJadwal.jamSelesai.toTimeString().slice(0,5)}` 
      }, { status: 400 });
    }

    // Prepare data untuk create dengan validasi
    const jadwalData: any = {
      hari: hari,
      jamMulai: new Date(`2000-01-01T${jamMulai}`),
      jamSelesai: new Date(`2000-01-01T${jamSelesai}`),
      halaqahId: parseInt(halaqahId)
    };

    // Tambahkan field baru dengan default values jika tidak ada
    try {
      jadwalData.isTemplate = Boolean(isTemplate);
      jadwalData.isActive = Boolean(isActive);
      
      // Tambahkan tanggal periode jika disediakan
      if (tanggalMulai) {
        jadwalData.tanggalMulai = new Date(tanggalMulai);
      }
      if (tanggalSelesai) {
        jadwalData.tanggalSelesai = new Date(tanggalSelesai);
      }
    } catch (fieldError) {
      console.log('Warning: New fields not available, using basic jadwal creation');
      // Fallback ke basic jadwal creation jika field baru belum tersedia
    }

    // Create jadwal
    const jadwal = await prisma.jadwal.create({
      data: jadwalData,
      include: {
        halaqah: {
          include: {
            guru: {
              select: {
                id: true,
                namaLengkap: true
              }
            },
            santri: {
              include: {
                santri: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      }
    });

    const formatted = {
      id: jadwal.id,
      hari: jadwal.hari,
      jamMulai: jadwal.jamMulai,
      jamSelesai: jadwal.jamSelesai,
      // Safely access new fields with fallbacks
      isTemplate: jadwal.isTemplate ?? true,
      tanggalMulai: jadwal.tanggalMulai ?? null,
      tanggalSelesai: jadwal.tanggalSelesai ?? null,
      isActive: jadwal.isActive ?? true,
      halaqah: {
        id: jadwal.halaqah.id,
        namaHalaqah: jadwal.halaqah.namaHalaqah,
        guru: jadwal.halaqah.guru,
        jumlahSantri: jadwal.halaqah.santri.length
      }
    };

    console.log('Jadwal created successfully:', formatted.id);
    return NextResponse.json(formatted);

  } catch (error: any) {
    console.error('POST /api/jadwal error:', error);
    return NextResponse.json({
      error: 'Failed to create jadwal',
      details: error.message || 'Unknown error occurred'
    }, { status: 500 });
  }
}

// ­ƒôè API Konversi: Hafalan Surat ÔåÆ Progress Juz
// Endpoint: GET /api/konversi/progress-juz

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import jwt from 'jsonwebtoken';
import { calculateJuzProgress, calculateSuratProgress } from '@/utils/hafalan-converter';

const prisma = new PrismaClient();

export async function GET(request: NextRequest) {
  try {
    // Ambil token dari header
    const token = request.headers.get('authorization')?.replace('Bearer ', '');
    
    if (!token) {
      return NextResponse.json(
        { error: 'Token tidak ditemukan' },
        { status: 401 }
      );
    }

    // Verifikasi token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.userId;

    // Ambil parameter query
    const { searchParams } = new URL(request.url);
    const santriId = searchParams.get('santriId');
    
    // Jika ada santriId, pastikan user adalah guru yang mengajar santri tersebut
    let targetSantriId = userId;
    
    if (santriId) {
      // Cek apakah user adalah guru
      const user = await prisma.user.findUnique({
        where: { id: userId },
        include: { role: true }
      });
      
      if (user?.role.name === 'guru') {
        // Pastikan santri ada di halaqah guru ini
        const halaqahSantri = await prisma.halaqahSantri.findFirst({
          where: {
            santriId: parseInt(santriId),
            halaqah: {
              guruId: userId
            }
          }
        });
        
        if (!halaqahSantri) {
          return NextResponse.json(
            { error: 'Santri tidak ditemukan dalam halaqah Anda' },
            { status: 403 }
          );
        }
        
        targetSantriId = parseInt(santriId);
      } else if (user?.role.name === 'santri' && parseInt(santriId) !== userId) {
        return NextResponse.json(
          { error: 'Santri hanya bisa melihat data pribadi' },
          { status: 403 }
        );
      }
    }

    // Ambil data hafalan santri (hanya ziyadah yang dihitung sebagai progress)
    const hafalanData = await prisma.hafalan.findMany({
      where: {
        santriId: targetSantriId,
        status: 'ziyadah' // Hanya ziyadah yang dihitung progress
      },
      select: {
        surat: true,
        ayatMulai: true,
        ayatSelesai: true,
        status: true,
        tanggal: true
      },
      orderBy: {
        tanggal: 'desc'
      }
    });

    // Konversi ke format yang dibutuhkan converter
    const hafalanForConverter = hafalanData.map(h => ({
      surat: h.surat,
      ayatMulai: h.ayatMulai,
      ayatSelesai: h.ayatSelesai,
      status: h.status as 'ziyadah' | 'murojaah'
    }));

    // Hitung progress per juz
    const progressJuz = calculateJuzProgress(hafalanForConverter);
    
    // Hitung progress per surat
    const progressSurat = calculateSuratProgress(hafalanForConverter);

    // Statistik ringkasan
    const totalJuzSelesai = progressJuz.filter(j => j.status === 'selesai').length;
    const totalJuzProses = progressJuz.filter(j => j.status === 'proses').length;
    const totalAyatHafal = progressJuz.reduce((sum, j) => sum + j.ayatHafal, 0);
    const totalAyatAlQuran = progressJuz.reduce((sum, j) => sum + j.totalAyat, 0);
    const progressKeseluruhan = Math.round((totalAyatHafal / totalAyatAlQuran) * 100);

    const result = {
      success: true,
      data: {
        santriId: targetSantriId,
        progressJuz,
        progressSurat,
        statistik: {
          totalJuzSelesai,
          totalJuzProses,
          totalJuzBelum: 30 - totalJuzSelesai - totalJuzProses,
          totalAyatHafal,
          totalAyatAlQuran,
          progressKeseluruhan,
          totalSuratDihafal: progressSurat.length
        },
        lastUpdated: new Date().toISOString()
      }
    };

    return NextResponse.json(result);

  } catch (error) {
    console.error('ÔØî Error in progress-juz API:', error);
    
    if (error instanceof jwt.JsonWebTokenError) {
      return NextResponse.json(
        { error: 'Token tidak valid' },
        { status: 401 }
      );
    }

    return NextResponse.json(
      { error: 'Terjadi kesalahan server' },
      { status: 500 }
    );
  } finally {
    await prisma.$disconnect();
  }
}

// ­ƒÄ» API Konversi: Target Juz ÔåÆ Rencana Surat
// Endpoint: GET /api/konversi/target-surat

import { NextRequest, NextResponse } from 'next/server';
import { convertJuzToSuratTarget } from '@/utils/hafalan-converter';

export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url);
    const juzParam = searchParams.get('juz');
    
    if (!juzParam) {
      return NextResponse.json(
        { error: 'Parameter juz diperlukan. Contoh: ?juz=1,2,3' },
        { status: 400 }
      );
    }

    // Parse juz numbers
    const targetJuz = juzParam.split(',').map(j => {
      const juzNumber = parseInt(j.trim());
      if (isNaN(juzNumber) || juzNumber < 1 || juzNumber > 30) {
        throw new Error(`Juz ${j} tidak valid. Harus antara 1-30`);
      }
      return juzNumber;
    });

    // Konversi juz ke target surat
    const suratTarget = convertJuzToSuratTarget(targetJuz);

    // Hitung statistik
    const totalSurat = suratTarget.length;
    const totalAyatTarget = suratTarget.reduce((sum, s) => sum + s.ayatHafal, 0);
    const suratLengkap = suratTarget.filter(s => s.progress === 100).length;
    const suratSebagian = suratTarget.filter(s => s.progress > 0 && s.progress < 100).length;

    const result = {
      success: true,
      data: {
        targetJuz: targetJuz.sort(),
        suratTarget,
        statistik: {
          totalJuz: targetJuz.length,
          totalSurat,
          totalAyatTarget,
          suratLengkap,
          suratSebagian,
          estimasiWaktu: `${Math.ceil(totalAyatTarget / 10)} hari` // Asumsi 10 ayat per hari
        },
        rencanaHafalan: generateRencanaHafalan(suratTarget),
        lastGenerated: new Date().toISOString()
      }
    };

    return NextResponse.json(result);

  } catch (error) {
    console.error('ÔØî Error in target-surat API:', error);
    
    return NextResponse.json(
      { error: error instanceof Error ? error.message : 'Terjadi kesalahan server' },
      { status: 400 }
    );
  }
}

/**
 * Generate rencana hafalan berdasarkan target surat
 */
function generateRencanaHafalan(suratTarget: any[]) {
  return suratTarget.map((surat, index) => {
    let rencana = '';
    
    if (surat.progress === 100) {
      rencana = `Hafal lengkap surat ${surat.surat} (${surat.totalAyat} ayat)`;
    } else {
      rencana = `Hafal surat ${surat.surat} ayat 1-${surat.ayatHafal} dari ${surat.totalAyat} ayat`;
    }
    
    return {
      urutan: index + 1,
      surat: surat.surat,
      target: `Ayat 1-${surat.ayatHafal}`,
      totalAyat: surat.ayatHafal,
      juzTerkait: surat.juzTerkait,
      rencana,
      prioritas: surat.juzTerkait.length === 1 ? 'tinggi' : 'sedang' // Surat yang hanya ada di 1 juz prioritas tinggi
    };
  }).sort((a, b) => {
    // Urutkan berdasarkan prioritas dan juz terkecil
    if (a.prioritas !== b.prioritas) {
      return a.prioritas === 'tinggi' ? -1 : 1;
    }
    return Math.min(...a.juzTerkait) - Math.min(...b.juzTerkait);
  });
}

import { NextRequest, NextResponse } from "next/server";
import jwt from "jsonwebtoken";
import prisma from '@/lib/database/prisma';
import { loginSchema } from '@/lib/validations';

const JWT_SECRET = process.env.JWT_SECRET || "mysecretkey";

export async function POST(request: NextRequest) {
  try {
    const body = await request.json();
    const { passCode } = loginSchema.parse(body);

    // Find user by passCode
    const user = await prisma.user.findFirst({
      where: { passCode: passCode },
      include: { role: {
          select: { name: true }
        }
      }
    });

    if (!user) {
      console.log('Login failed: Passcode not found:', passCode);
      return NextResponse.json({ 
        error: "Passcode tidak ditemukan", 
        message: "Passcode yang Anda masukkan tidak terdaftar dalam sistem. Silakan periksa kembali atau hubungi admin.",
        code: "PASSCODE_NOT_FOUND"
      }, { status: 401 });
    }

    console.log('Login successful for user:', user.namaLengkap, 'Role:', user.role.name);

    // Create JWT token
    const token = jwt.sign(
      {
        id: user.id,
        namaLengkap: user.namaLengkap,
        username: user.username,
        role: user.role.name,
        foto: user.foto
      },
      JWT_SECRET,
      { expiresIn: '24h' }
    );

    // Set HTTP-only cookie
    const response = NextResponse.json({
      user: {
        id: user.id,
        namaLengkap: user.namaLengkap,
        username: user.username,
        role: user.role.name,
        foto: user.foto
      },
      message: "Login successful"
    });

    response.cookies.set('auth_token', token, {
      httpOnly: true,
      secure: process.env.NODE_ENV === 'production',
      sameSite: 'strict',
      maxAge: 24 * 60 * 60 // 24 hours
    });

    // Log login activity
    await prisma.auditLog.create({
      data: {
        action: 'LOGIN',
        keterangan: `User ${user.namaLengkap} logged in`,
        userId: user.id
      }
    });

    return response;

  } catch (error) {
    console.error("Login error:", error);
    if (error instanceof Error && error.name === 'ZodError') {
      return NextResponse.json(
        { error: "Validation failed", details: (error as any).errors },
        { status: 400 }
      );
    }
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

