            });
          });

          // Format content
          allAyat.forEach((ayat) => {
            if (currentSuratNumber !== ayat.suratId) {
              if (lines.length > 0) lines.push('');
              lines.push(`´┤┐ ${ayat.nama} ´┤¥`);
