export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const page = searchParams.get('page');
    const juz = searchParams.get('juz');
    const action = searchParams.get('action');

    // Get specific mushaf page with real Quran content
    if (page) {
      const pageNum = parseInt(page);
      if (pageNum < 1 || pageNum > 604) {
        return NextResponse.json(
          { 
            success: false,
            error: 'Invalid page number. Must be between 1-604' 
          },
          { status: 400 }
        );
      }
      
      const pageContent = await generateMushafPageContent(pageNum);
      return NextResponse.json({
        success: true,
        data: pageContent
      });
    }
    
    // Get juz page range
    if (juz) {
      const juzNum = parseInt(juz);
      if (juzNum < 1 || juzNum > 30) {
        return NextResponse.json(
          { 
            success: false,
            error: 'Invalid juz number. Must be between 1-30' 
          },
          { status: 400 }
        );
      }
      
      const juzMapping = JUZ_TO_PAGE_MAPPING[juzNum];
      return NextResponse.json({
        success: true,
        data: {
          juz: juzNum,
          pageRange: juzMapping,
          totalPages: juzMapping.end - juzMapping.start + 1,
          pages: Array.from(
            { length: juzMapping.end - juzMapping.start + 1 }, 
            (_, i) => juzMapping.start + i
          )
        }
      });
    }
    
    // Get juz mapping overview
    if (action === 'mapping') {
      return NextResponse.json({
        success: true,
        data: {
          juzMapping: JUZ_TO_PAGE_MAPPING,
          totalPages: 604,
          totalJuz: 30,

          summary: Object.entries(JUZ_TO_PAGE_MAPPING).map(([juzNum, info]) => ({
            juz: parseInt(juzNum),
            pageRange: `${info.start}-${info.end}`,
            totalPages: info.end - info.start + 1,
            surah: info.surah
          }))
        }
      });
    }

    // Default: return mushaf info
    return NextResponse.json({
      success: true,
      data: {
        message: 'Mushaf Digital API - Rasm Utsmani',
        endpoints: {
          getPage: '/api/mushaf?page={pageNumber}',
          getJuz: '/api/mushaf?juz={juzNumber}',
          getMapping: '/api/mushaf?action=mapping'
        },
        totalPages: 604,
        totalJuz: 30,
        note: 'Semua halaman menggunakan API alquran.cloud dengan data per-halaman yang akurat'
      }
    });

  } catch (error) {
    console.error('Error fetching mushaf data:', error);
    return NextResponse.json(
      { 
        success: false,
        error: 'Failed to fetch mushaf data' 
      },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { cookies } from 'next/headers';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

export async function GET(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Count unread notifications for the user
    const count = await prisma.notifikasi.count({
      where: {
        userId: userId,
        // You can add additional conditions here if you have a 'read' field
        // isRead: false
      }
    });

    // Also count unread pengumuman for the user
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user) {
      return NextResponse.json({ error: 'User not found' }, { status: 404 });
    }

    // Skip pengumuman count for super_admin
    let unreadPengumuman = 0;
    if (user.role.name.toLowerCase() !== 'super_admin') {
      // Get pengumuman that haven't been read by this user
      // Map role name to enum value
      const roleMapping: { [key: string]: string } = {
        'super-admin': 'super_admin',
        'orang_tua': 'ortu'
      };
      
      const targetRole = roleMapping[user.role.name.toLowerCase()] || user.role.name.toLowerCase();

      unreadPengumuman = await prisma.pengumuman.count({
        where: {
          OR: [
            { targetAudience: 'semua' },
            { targetAudience: targetRole as any }
          ],
          NOT: {
            dibacaOleh: {
              some: {
                userId: userId
              }
            }
          }
        }
      });
    }

    const totalCount = count + unreadPengumuman;

    return NextResponse.json({ 
      count: totalCount,
      notifications: count,
      pengumuman: unreadPengumuman
    });

  } catch (error) {
    console.error('Error fetching notification count:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

