      },
      { status: 500 }
    );
  }
}

import prisma from '@/lib/database/prisma';
import { NextResponse } from 'next/server';

export async function GET(request: Request) {
  try {
    const { searchParams } = new URL(request.url);
    const halaqahId = searchParams.get('halaqahId');
    const semester = searchParams.get('semester');
    const tahunAjaran = searchParams.get('tahunAjaran');

    if (!halaqahId || !semester || !tahunAjaran) {
      return NextResponse.json({ error: 'halaqahId, semester, tahunAjaran are required' }, { status: 400 });
    }

    // Get santri in halaqah
    const halaqahSantri = await prisma.halaqahSantri.findMany({
      where: {
        halaqahId: Number(halaqahId),
        tahunAkademik: tahunAjaran,
        semester: semester as any
      },
      include: {
        santri: {
          select: {
            id: true,
            namaLengkap: true,
            username: true
          }
        }
      }
    });

    const raportData = await Promise.all(
      halaqahSantri.map(async (hs) => {
        const santriId = hs.santriId;

        // Total ayat hafal
        const hafalan = await prisma.hafalan.findMany({
          where: { santriId }
        });
        const totalAyatHafal = hafalan.reduce((sum, h) => sum + h.ayatSelesai - h.ayatMulai + 1, 0);

        // Target tercapai
        const targets = await prisma.targetHafalan.findMany({
          where: { santriId }
        });
        const totalTarget = targets.reduce((sum, t) => sum + t.ayatTarget, 0);
        const targetTercapai = totalTarget > 0 ? Math.round((totalAyatHafal / totalTarget) * 100) : 0;

        // Rata-rata nilai ujian
        const ujian = await prisma.ujian.findMany({
          where: {
            santriId,
            halaqahId: Number(halaqahId)
          }
        });
        const rataRataNilaiUjian = ujian.length > 0
          ? ujian.reduce((sum, u) => sum + u.nilai, 0) / ujian.length
          : 0;

        // Status akhir based on criteria
        let statusAkhir = 'Merah';
        if (targetTercapai >= 80 && rataRataNilaiUjian >= 80) {
          statusAkhir = 'Hijau';
        } else if (targetTercapai >= 60 || rataRataNilaiUjian >= 60) {
          statusAkhir = 'Kuning';
        }

        return {
          santri: hs.santri,
          totalAyatHafal,
          targetTercapai,
          rataRataNilaiUjian: Math.round(rataRataNilaiUjian * 100) / 100,
          statusAkhir
        };
      })
    );

    return NextResponse.json(raportData);
  } catch (error) {
    console.error('GET /api/raport error:', error);
    return NextResponse.json(
      { error: 'Failed to fetch raport' },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from "next/server";
import jwt from 'jsonwebtoken';
import prisma from '@/lib/database/prisma';

const JWT_SECRET = process.env.JWT_SECRET || "mysecretkey";

export async function GET(request: NextRequest) {
  try {
    // Get user from JWT token
    const token = request.cookies.get("auth_token")?.value;

    if (!token) {
      return NextResponse.json({ error: "No token provided" }, { status: 401 });
    }

    const decoded = jwt.verify(token, JWT_SECRET) as { id: number; role: string };

    // Verify user role is super-admin (only super-admin can manage roles)
    const user = await prisma.user.findUnique({
      where: { id: decoded.id },
      select: { id: true, role: { select: { name: true } } }
    });

    if (!user || user.role.name !== 'super_admin') {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    // Get all roles and generate dynamic permissions
    const roles = await prisma.role.findMany({
      select: {
        id: true,
        name: true,
        _count: {
          select: { users: true }
        }
      }
    });

    // Generate dynamic permissions for each role
    const dynamicPermissions: Record<string, any> = {};

    roles.forEach((role, index) => {
      const roleName = role.name.toLowerCase();
      const level = roleName === 'super_admin' ? 6 : 
                   roleName === 'admin' ? 5 : 
                   roleName === 'guru' ? 4 : 
                   roleName === 'santri' ? 3 : 
                   roleName === 'ortu' ? 2 : 
                   roleName === 'yayasan' ? 1 : 
                   Math.max(1, 6 - index); // Dynamic level for new roles

      dynamicPermissions[roleName] = {
        level: level,
        allowedRoutes: [
          roleName,
          `${roleName}/profil`,
          // Super admin gets access to all routes
          ...(roleName === 'super_admin' ? ['admin', 'guru', 'santri', 'ortu', 'yayasan', 'users', 'settings'] : []),
          // Admin gets access to most routes except super-admin
          ...(roleName === 'admin' ? ['guru', 'santri', 'ortu', 'yayasan'] : [])
        ],
        dashboard: `/${roleName}/dashboard`,
        userCount: role._count.users
      };
    });

    return NextResponse.json({
      permissions: dynamicPermissions,
      roles: roles,
      message: "Dynamic role permissions generated successfully"
    });

  } catch (error) {
    console.error("Error fetching role permissions:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

export async function POST(request: NextRequest) {
  try {
    // Get user from JWT token
    const token = request.cookies.get("auth_token")?.value;

    if (!token) {
      return NextResponse.json({ error: "No token provided" }, { status: 401 });
    }

    const decoded = jwt.verify(token, JWT_SECRET) as { id: number; role: string };

    // Verify user role is super-admin
    const user = await prisma.user.findUnique({
      where: { id: decoded.id },
      select: { id: true, role: { select: { name: true } } }
    });

    if (!user || user.role.name !== 'super_admin') {
      return NextResponse.json({ error: "Unauthorized" }, { status: 401 });
    }

    const { roleName, level } = await request.json();

    if (!roleName) {
      return NextResponse.json({ error: "Role name is required" }, { status: 400 });
    }

    // Create new role in database
    const newRole = await prisma.role.create({
      data: {
        name: roleName.toLowerCase().replace(/\s+/g, '_')
      }
    });

    // Generate permission for new role
    const newPermission = {
      level: level || 1,
      allowedRoutes: [newRole.name, `${newRole.name}/profil`],
      dashboard: `/${newRole.name}/dashboard`,
      userCount: 0
    };

    return NextResponse.json({
      role: newRole,
      permission: newPermission,
      message: "New role created successfully"
    });

  } catch (error) {
    console.error("Error creating role:", error);
    return NextResponse.json(
      { error: "Internal server error" },
      { status: 500 }
    );
  }
}

import { NextRequest, NextResponse } from 'next/server';
import { PrismaClient } from '@prisma/client';
import { cookies } from 'next/headers';
import jwt from 'jsonwebtoken';

const prisma = new PrismaClient();

// GET - Ambil data absensi santri yang diinput oleh guru
export async function GET(request: NextRequest) {
  try {
    // Get token from cookies
    const cookieStore = await cookies();
    const token = cookieStore.get('auth_token')?.value;

    if (!token) {
      return NextResponse.json({ error: 'Unauthorized' }, { status: 401 });
    }

    // Verify token
    const decoded = jwt.verify(token, process.env.JWT_SECRET!) as any;
    const userId = decoded.id;

    // Get user info
    const user = await prisma.user.findUnique({
      where: { id: userId },
      include: { role: true }
    });

    if (!user || user.role.name !== 'santri') {
      return NextResponse.json({ error: 'Access denied' }, { status: 403 });
    }

    const { searchParams } = new URL(request.url);
    const startDate = searchParams.get('startDate');
    const endDate = searchParams.get('endDate');
    const limit = searchParams.get('limit');

    // Build where clause
    const whereClause: any = {
      santriId: userId
    };

    // Add date filter if provided
    if (startDate && endDate) {
      whereClause.tanggal = {
        gte: new Date(startDate + 'T00:00:00.000Z'),
        lte: new Date(endDate + 'T23:59:59.999Z')
      };
    } else if (startDate) {
      whereClause.tanggal = {
        gte: new Date(startDate + 'T00:00:00.000Z')
      };
    } else if (endDate) {
      whereClause.tanggal = {
        lte: new Date(endDate + 'T23:59:59.999Z')
      };
    }

    // Get absensi data
    const absensiData = await prisma.absensi.findMany({
      where: whereClause,
      include: {
        jadwal: {
          include: {
            halaqah: {
              include: {
                guru: {
                  select: {
                    id: true,
                    namaLengkap: true
                  }
                }
              }
            }
          }
        }
      },
      orderBy: {
        tanggal: 'desc'
      },
      take: limit ? parseInt(limit) : undefined
    });

    // Calculate statistics
    const totalAbsensi = absensiData.length;
    const totalHadir = absensiData.filter(a => a.status === 'masuk').length;
    const totalIzin = absensiData.filter(a => a.status === 'izin').length;
    const totalAlpha = absensiData.filter(a => a.status === 'alpha').length;
    const attendanceRate = totalAbsensi > 0 ? Math.round((totalHadir / totalAbsensi) * 100) : 0;

    // Calculate current streak (consecutive days present)
    let currentStreak = 0;
    const sortedAbsensi = absensiData.sort((a, b) => 
      new Date(b.tanggal).getTime() - new Date(a.tanggal).getTime()
    );

    for (const absensi of sortedAbsensi) {
      if (absensi.status === 'masuk') {
        currentStreak++;
      } else {
        break;
      }
    }

    // Calculate best streak
    let bestStreak = 0;
    let tempStreak = 0;
    
    for (const absensi of sortedAbsensi.reverse()) {
      if (absensi.status === 'masuk') {
        tempStreak++;
        bestStreak = Math.max(bestStreak, tempStreak);
      } else {
        tempStreak = 0;
      }
    }

    // Format response data
    const formattedAbsensi = absensiData.map(absensi => ({
      id: absensi.id,
      tanggal: absensi.tanggal.toISOString().split('T')[0],
      status: absensi.status === 'masuk' ? 'hadir' : absensi.status, // Convert 'masuk' to 'hadir' for frontend
      halaqah: absensi.jadwal.halaqah.namaHalaqah,
      guru: absensi.jadwal.halaqah.guru?.namaLengkap || 'Unknown',
      hari: absensi.jadwal.hari,
      jamMulai: absensi.jadwal.jamMulai.toTimeString().slice(0, 5),
      jamSelesai: absensi.jadwal.jamSelesai.toTimeString().slice(0, 5)
    }));

    const stats = {
      totalHadir,
      totalIzin,
      totalAlpha,
      attendanceRate,
      currentStreak,
      bestStreak,
      totalAbsensi
    };

    return NextResponse.json({
      success: true,
      data: {
        absensi: formattedAbsensi,
        stats: stats
      }
    });

  } catch (error) {
    console.error('Error fetching santri absensi:', error);
    return NextResponse.json({ error: 'Internal server error' }, { status: 500 });
  } finally {
    await prisma.$disconnect();
  }
}

