      'belum': STATUS_TARGET.BELUM,
      'proses': STATUS_TARGET.PROSES,
      'selesai': STATUS_TARGET.SELESAI
    };
    const mappedStatus = statusMap[status] || STATUS_TARGET.BELUM;

